/// A named savepoint within a transaction.
pub const Savepoint = struct {
    name: []const u8,
    cid: u16,
};

/// Active transaction context for the current session.
pub const TransactionContext = struct {
    xid: u32,
    isolation: IsolationLevel,
    /// For REPEATABLE READ / SERIALIZABLE: snapshot taken at BEGIN.
    /// For READ COMMITTED: null (fresh snapshot per statement).
    snapshot: ?Snapshot = null,
    /// Stack of named savepoints (most recent last).
    savepoints: std.ArrayListUnmanaged(Savepoint) = .{},
    /// Allocator for savepoint stack.
    allocator: ?Allocator = null,

    pub fn deinit(self: *TransactionContext) void {
        if (self.snapshot) |*snap| snap.deinit();
        if (self.allocator) |alloc| {
            for (self.savepoints.items) |sp| alloc.free(sp.name);
            self.savepoints.deinit(alloc);
        }
    }
};

/// Result of executing a SQL statement.
pub const QueryResult = struct {
    /// For SELECT: row iterator (caller must call close()).
    rows: ?RowIterator = null,
    /// For DML: number of rows affected.
    rows_affected: u64 = 0,
    /// Human-readable message.
    message: []const u8 = "",
    /// The AST arena that owns all plan/expr memory. Must be kept alive
    /// while iterating rows (expressions reference arena memory).
    /// Caller must deinit after closing the row iterator.
    _arena: ?*AstArena = null,
    /// Heap-allocated operator chain. Caller must free these.
    _ops: ?*OperatorChain = null,

    pub fn close(self: *QueryResult, allocator: Allocator) void {
        if (self.rows) |r| r.close();
        if (self._ops) |ops| ops.deinit(allocator);
        if (self._arena) |arena| {
            arena.deinit();
            allocator.destroy(arena);
        }
    }
};

/// Prepared statement — parse once, execute many times.
/// Caches tokenizer/parser/analyzer output to skip expensive pipeline steps
/// on repeated executions with different parameter values.
pub const PreparedStatement = struct {
    db: *Database,
    allocator: Allocator,
    /// Template arena: owns the original cached plan (read-only after prepare).
    /// Never modified during execution. Only freed when PreparedStatement closes.
    template_arena: *AstArena,
    /// Cached optimized logical plan.
    plan: LogicalPlan,
    /// Parameter count (number of ? placeholders).
    param_count: usize,
    /// Bound parameter values (indexed by position).
    bound_params: []?Value,
    /// Track which parameters have been bound (for validation).
    bound_flags: []bool,

    /// Bind a parameter at the given index (0-based).
    pub fn bind(self: *PreparedStatement, index: usize, value: Value) !void {
        if (index >= self.param_count) {
            return error.InvalidParameterIndex;
        }
        // Free previous value if any
        if (self.bound_params[index]) |prev| {
            prev.free(self.allocator);
        }
        // Duplicate the value to ensure PreparedStatement owns it
        self.bound_params[index] = try value.dupe(self.allocator);
        self.bound_flags[index] = true;
    }

    /// Execute the prepared statement with currently bound parameters.
    pub fn execute(self: *PreparedStatement) !QueryResult {
        // Validate all parameters are bound
        for (self.bound_flags, 0..) |bound, i| {
            if (!bound) {
                return error.UnboundParameter;
            }
            _ = i; // Suppress unused
        }

        // Create a fresh execution arena for this execution.
        // This arena is used for parameter substitution (creating new AST nodes)
        // and is passed to the executor, which will free it (even on error).
        const execution_arena = try self.allocator.create(AstArena);
        execution_arena.* = AstArena.init(self.allocator);

        // Execute with both arenas:
        // - template_arena: read-only, contains cached plan
        // - execution_arena: writable, used for parameter substitution and temporary data
        // NOTE: Ownership of execution_arena is transferred to executePlanWithParams.
        // It will be freed by the executor (in executeInsert/Update/Delete/Select/etc) even on error.
        return self.db.executePlanWithParams(self.template_arena, execution_arena, self.plan, self.bound_params);
    }

    /// Close the prepared statement and free all resources.
    pub fn close(self: *PreparedStatement) void {
        // Free bound parameters
        for (self.bound_params) |maybe_value| {
            if (maybe_value) |v| {
                v.free(self.allocator);
            }
        }
        self.allocator.free(self.bound_params);
        self.allocator.free(self.bound_flags);
        // Free the template arena (execution arenas are freed by executor)
        self.template_arena.deinit();
        self.allocator.destroy(self.template_arena);
    }
};

/// Holds heap-allocated operator structs to keep them alive during iteration.
const OperatorChain = struct {
    scan: ?*ScanOp = null,
    index_scan: ?*IndexScanOp = null,
    filter: ?*FilterOp = null,
    project: ?*ProjectOp = null,
    limit: ?*LimitOp = null,
    sort: ?*SortOp = null,
    aggregate: ?*AggregateOp = null,
    join: ?*NestedLoopJoinOp = null,
    hash_join: ?*HashJoinOp = null,
    merge_join: ?*MergeJoinOp = null,
    values: ?*ValuesOp = null,
    empty: ?*EmptyOp = null,
    materialized: ?*MaterializedOp = null,
    distinct: ?*DistinctOp = null,
    set_op: ?*SetOpOp = null,
    window: ?*WindowOp = null,
    /// Operator chains for set operation sub-queries (need cleanup).
    set_op_chains: std.ArrayListUnmanaged(*OperatorChain) = .{},
    /// Materialized CTE results: name → MaterializedOp*.
    cte_materialized: ?std.StringHashMapUnmanaged(*MaterializedOp) = null,
    /// Operator chains for CTE sub-queries (need cleanup).
    cte_ops: std.ArrayListUnmanaged(*OperatorChain) = .{},
    // For joins, we may need a second scan
    scan2: ?*ScanOp = null,
    /// Per-statement RC snapshot that needs cleanup (owned by this chain).
    rc_snapshot: ?Snapshot = null,
    /// Activity tracker for pg_stat_activity (reference, not owned).
    activity_tracker: ?*const executor_mod.ActivityTracker = null,
    /// StatActivityScanOp for pg_stat_activity.
    stat_activity_scan: ?*executor_mod.StatActivityScanOp = null,
    /// LocksScanOp for pg_locks.
    locks_scan: ?*executor_mod.LocksScanOp = null,
    /// LATERAL join operator.
    lateral_join: ?*LateralJoinOp = null,
    /// Outer row for correlated subquery evaluation (non-owning reference).
    outer_row: ?*const executor_mod.Row = null,
    /// Row-level locking clauses from SELECT FOR UPDATE/SHARE (non-owning reference).
    locking_clauses: []const ast_mod.LockingClause = &.{},

    fn freeScanColNames(allocator: Allocator, s: *ScanOp) void {
        for (s.col_names) |name| allocator.free(@constCast(name));
        allocator.free(s.col_names);
        if (s.col_defaults) |defaults| {
            for (defaults) |val| val.free(allocator);
            allocator.free(defaults);
        }
    }

    fn deinit(self: *OperatorChain, allocator: Allocator) void {
        // Free per-statement RC snapshot if allocated
        if (self.rc_snapshot) |*snap| snap.deinit();
        // Operators are closed via RowIterator.close() already.
        // We just free the heap-allocated structs.
        if (self.scan) |s| {
            freeScanColNames(allocator, s);
            allocator.destroy(s);
        }
        if (self.scan2) |s| {
            freeScanColNames(allocator, s);
            allocator.destroy(s);
        }
        if (self.index_scan) |is| {
            for (is.col_names) |name| allocator.free(@constCast(name));
            allocator.free(is.col_names);
            if (is.col_defaults) |defaults| {
                for (defaults) |val| val.free(allocator);
                allocator.free(defaults);
            }
            allocator.free(is.lookup_key);
            allocator.destroy(is);
        }
        if (self.filter) |f| allocator.destroy(f);
        if (self.project) |p| allocator.destroy(p);
        if (self.limit) |l| allocator.destroy(l);
        if (self.sort) |s| allocator.destroy(s);
        if (self.aggregate) |a| allocator.destroy(a);
        if (self.join) |j| allocator.destroy(j);
        if (self.hash_join) |hj| allocator.destroy(hj);
        if (self.merge_join) |mj| allocator.destroy(mj);
        if (self.values) |v| allocator.destroy(v);
        if (self.empty) |e| allocator.destroy(e);
        if (self.materialized) |m| allocator.destroy(m);
        if (self.distinct) |d| allocator.destroy(d);
        if (self.set_op) |s| allocator.destroy(s);
        if (self.window) |w| allocator.destroy(w);
        if (self.stat_activity_scan) |s| allocator.destroy(s);
        if (self.locks_scan) |l| allocator.destroy(l);
        if (self.lateral_join) |lj| allocator.destroy(lj);
        // Clean up set operation sub-query chains.
        for (self.set_op_chains.items) |chain| {
            chain.cte_materialized = null;
            chain.deinit(allocator);
        }
        self.set_op_chains.deinit(allocator);
        // Clean up CTE sub-query chains first (clear their cte_materialized
        // references to avoid double-free — the parent owns the map).
        for (self.cte_ops.items) |cte_chain| {
            cte_chain.cte_materialized = null;
            cte_chain.deinit(allocator);
        }
        self.cte_ops.deinit(allocator);
        // Clean up CTE materialized ops (parent owns the map)
        if (self.cte_materialized) |*cte_map| {
            var it = cte_map.valueIterator();
            while (it.next()) |mat_ptr| {
                mat_ptr.*.close();
                allocator.destroy(mat_ptr.*);
            }
            cte_map.deinit(allocator);
        }
        allocator.destroy(self);
    }
};

/// Returns heap-allocated column names for a built-in table-valued function.
/// Used by LEFT JOIN LATERAL when the right side produces zero rows — we still need
/// the column schema to emit properly NULL-filled right columns.
/// Caller owns the returned slice and must free each element and the slice itself.
/// Return the column name at `idx` from the table function's explicit column_names list,
/// falling back to `default` when no override was provided.
fn tfsColName(tfs: PlanNode.TableFunctionScan, idx: usize, default: []const u8) []const u8 {
    return if (idx < tfs.column_names.len) tfs.column_names[idx] else default;
}

fn tvfDefaultColumnNames(allocator: Allocator, func_name: []const u8) Allocator.Error![]const []const u8 {
    const static_names: []const []const u8 = blk: {
        if (std.mem.eql(u8, func_name, "json_each") or
            std.mem.eql(u8, func_name, "jsonb_each") or
            std.mem.eql(u8, func_name, "json_each_text") or
            std.mem.eql(u8, func_name, "jsonb_each_text"))
            break :blk &[_][]const u8{ "key", "value" };
        if (std.mem.eql(u8, func_name, "json_array_elements") or
            std.mem.eql(u8, func_name, "jsonb_array_elements") or
            std.mem.eql(u8, func_name, "json_array_elements_text") or
            std.mem.eql(u8, func_name, "jsonb_array_elements_text"))
            break :blk &[_][]const u8{"value"};
        if (std.mem.eql(u8, func_name, "unnest"))
            break :blk &[_][]const u8{"unnest"};
        if (std.mem.eql(u8, func_name, "generate_series"))
            break :blk &[_][]const u8{"generate_series"};
        break :blk &[_][]const u8{};
    };

    const result = try allocator.alloc([]const u8, static_names.len);
    for (result, static_names) |*dest, src| {
        dest.* = try allocator.dupe(u8, src);
    }
    return result;
}

/// LATERAL join operator — for each left row, evaluates right SRF with that row as context.
const LateralJoinOp = struct {
    allocator: Allocator,
    db: *Database,
    left: executor_mod.RowIterator,
    tfs: PlanNode.TableFunctionScan,
    join_type: ast_mod.JoinType,
    on_condition: ?*const ast_mod.Expr,

    // State
    current_left_row: ?executor_mod.Row = null,
    right_iter: ?executor_mod.RowIterator = null,
    right_col_count: usize = 0,
    right_col_names: ?[]const []const u8 = null,
    right_ops: OperatorChain = .{},
    exhausted: bool = false,

    pub fn init(
        allocator: Allocator,
        db: *Database,
        left: executor_mod.RowIterator,
        tfs: PlanNode.TableFunctionScan,
        join_type: ast_mod.JoinType,
        on_condition: ?*const ast_mod.Expr,
    ) LateralJoinOp {
        return .{
            .allocator = allocator,
            .db = db,
            .left = left,
            .tfs = tfs,
            .join_type = join_type,
            .on_condition = on_condition,
        };
    }

    pub fn iterator(self: *LateralJoinOp) executor_mod.RowIterator {
        return .{
            .ptr = self,
            .vtable = &.{
                .next = @ptrCast(&LateralJoinOp.next),
                .close = @ptrCast(&LateralJoinOp.close),
            },
        };
    }

    fn next(ctx: *anyopaque) executor_mod.ExecError!?executor_mod.Row {
        const self: *LateralJoinOp = @ptrCast(@alignCast(ctx));

        while (!self.exhausted) {
            // If we have a right iterator, try to get the next row from it
            if (self.right_iter) |*right| {
                if (try right.next()) |right_row| {
                    var rr = right_row;
                    defer rr.deinit();
                    if (self.current_left_row) |left_row| {
                        return try executor_mod.combineRows(self.allocator, &left_row, &rr);
                    }
                    return executor_mod.ExecError.ExecutionError;
                }
                // Right iterator exhausted
                right.close();
                self.right_iter = null;
                // Free the MaterializedOp struct (data was freed by right.close() above)
                if (self.right_ops.materialized) |m| self.allocator.destroy(m);
                self.right_ops.materialized = null;

                // For LEFT JOIN LATERAL, if right produced no rows, emit left with NULLs
                if (self.join_type == .left) {
                    if (self.current_left_row) |left_row| {
                        // If we never peeked a row (right produced zero rows immediately),
                        // derive column names from the TVF's static schema.
                        if (self.right_col_names == null) {
                            self.right_col_names = try tvfDefaultColumnNames(
                                self.allocator,
                                self.tfs.function_name,
                            );
                        }
                        const right_count = if (self.right_col_names) |rn| rn.len else 0;
                        const null_cols = try self.allocator.alloc([]const u8, right_count);
                        errdefer self.allocator.free(null_cols);
                        // Column name strings are owned by right_col_names (freed in close()).
                        // Row.deinit() only frees the slice, not individual strings — no dupe needed.
                        if (self.right_col_names) |rn| {
                            for (null_cols, rn) |*dest, src| dest.* = src;
                        }

                        const null_vals = try self.allocator.alloc(executor_mod.Value, right_count);
                        errdefer self.allocator.free(null_vals);
                        for (null_vals) |*val| {
                            val.* = .null_value;
                        }

                        var null_right = executor_mod.Row{
                            .columns = null_cols,
                            .values = null_vals,
                            .allocator = self.allocator,
                        };
                        defer null_right.deinit();
                        return try executor_mod.combineRows(self.allocator, &left_row, &null_right);
                    }
                }
            }

            // Need next left row
            if (self.current_left_row) |*old| {
                old.deinit();
                self.current_left_row = null;
            }

            const left_row = try self.left.next() orelse {
                self.exhausted = true;
                return null;
            };
            self.current_left_row = left_row;

            // Evaluate right SRF with left_row as context
            // (right_ops should already be cleaned up by previous right.close() call)
            self.right_ops = .{};
            self.right_iter = self.db.buildTableFunctionScanWithContext(
                self.tfs,
                left_row,
                &self.right_ops,
            ) catch return executor_mod.ExecError.ExecutionError;

            // Peek at first right row to determine column count and names
            if (try self.right_iter.?.next()) |peek_row| {
                var pr = peek_row;
                defer pr.deinit();
                self.right_col_count = pr.columns.len;
                // Capture column names for LEFT JOIN NULL row (if not already saved)
                if (self.right_col_names == null and pr.columns.len > 0) {
                    const names = try self.allocator.alloc([]const u8, pr.columns.len);
                    errdefer self.allocator.free(names);
                    for (names, pr.columns) |*dest, src| {
                        dest.* = try self.allocator.dupe(u8, src);
                    }
                    self.right_col_names = names;
                }
                if (self.current_left_row) |left_row2| {
                    return try executor_mod.combineRows(self.allocator, &left_row2, &pr);
                }
                return executor_mod.ExecError.ExecutionError;
            }

            // Right iterator returned no rows on first call
            // For LEFT JOIN, we'll emit left + NULLs (handled next loop)
            // For INNER, we skip this left row
            if (self.join_type != .left) {
                if (self.right_iter) |*r| r.close();
                self.right_iter = null;
                // Free the MaterializedOp struct from right_ops (materialized data already freed by close)
                if (self.right_ops.materialized) |m| self.allocator.destroy(m);
                self.right_ops.materialized = null;
            }
            // Continue loop to handle LEFT JOIN or get next left row
        }

        return null;
    }

    pub fn close(ctx: *anyopaque) void {
        const self: *LateralJoinOp = @ptrCast(@alignCast(ctx));
        if (self.right_iter) |*r| r.close();
        // Free the MaterializedOp struct from right_ops (data already freed by close)
        if (self.right_ops.materialized) |m| self.allocator.destroy(m);
        if (self.right_col_names) |names| {
            for (names) |n| self.allocator.free(@constCast(n));
            self.allocator.free(names);
        }
        if (self.current_left_row) |*lr| lr.deinit();
        self.left.close();
    }
};

/// The main database handle. Connects all engine layers.
pub const Database = struct {
    allocator: Allocator,
    pager: *Pager,
    pool: *BufferPool,
    catalog: Catalog,
    /// Arena for schema lookups — TableInfo allocated here is freed between
    /// exec calls. Avoids the analyzer needing to manage TableInfo lifetimes.
    schema_arena: std.heap.ArenaAllocator,
    /// Optional WAL for transaction durability.
    wal: ?*Wal = null,
    /// Transaction manager for MVCC (shared across connections to same file).
    tm: *TransactionManager,
    /// Database file path (owned, for TM registry release on close).
    db_path: []const u8,
    /// Lock manager for row-level and table-level locking.
    lock_manager: LockManager,
    /// Free space map for tracking available space per page.
    fsm: FreeSpaceMap,
    /// Auto-vacuum daemon for background dead tuple reclamation.
    auto_vacuum: vacuum_mod.AutoVacuumDaemon,
    /// Standby coordinator for hot standby read-only access on replicas.
    standby_coordinator: StandbyCoordinator,
    /// Runtime configuration manager for session parameters.
    config: ConfigManager,
    /// Vtable for subquery evaluation (self-referential, initialized lazily on first exec).
    subquery_evaluator_vtable: executor_mod.SubqueryEvaluator = undefined,
    /// Currently active transaction (null = auto-commit mode).
    current_txn: ?TransactionContext = null,

    /// Open or create a database file.
    pub fn open(allocator: Allocator, path: []const u8, opts: OpenOptions) !Database {
        // Initialize shared TM registry if not already done.
        // IMPORTANT: Use page_allocator for the registry instead of the passed-in allocator
        // to avoid conflicts with per-test testing.allocators. The registry persists
        // across multiple Database.open/close cycles (required for MVCC transaction ID
        // monotonicity), but testing.allocator expects all allocations to be freed
        // when a test ends. Using page_allocator avoids this mismatch.
        registry_mutex.lock();
        if (!registry_initialized) {
            global_tm_registry = SharedTmRegistry.init(std.heap.page_allocator);
            registry_initialized = true;
        }
        registry_mutex.unlock();

        const pager = try allocator.create(Pager);
        errdefer allocator.destroy(pager);
        pager.* = try Pager.init(allocator, path, .{ .page_size = opts.page_size });
        errdefer pager.deinit();

        const is_new = pager.page_count <= 1;

        const pool = try allocator.create(BufferPool);
        errdefer allocator.destroy(pool);
        pool.* = try BufferPool.init(allocator, pager, opts.cache_size);
        errdefer pool.deinit();

        // Initialize WAL if requested
        var wal_ptr: ?*Wal = null;
        if (opts.wal_mode) {
            const w = try allocator.create(Wal);
            errdefer allocator.destroy(w);
            w.* = try Wal.init(allocator, path, pager.page_size);
            pool.setWal(w);
            wal_ptr = w;
        }

        var cat = try Catalog.init(allocator, pool, is_new);
        _ = &cat;

        // Acquire shared TM for this database file path
        const tm = try global_tm_registry.acquire(path);
        errdefer global_tm_registry.release(path);

        // Own a copy of the path for later release
        const path_copy = try allocator.dupe(u8, path);
        errdefer allocator.free(path_copy);

        // Initialize ConfigManager with default parameters
        var config = ConfigManager.init(allocator);
        errdefer config.deinit();

        // Register default parameters (PostgreSQL-compatible)
        try config.registerParameter(.{
            .name = "work_mem",
            .param_type = .size,
            .default_value = "4194304", // 4MB in bytes
            .min_value = 65536, // 64KB minimum
            .max_value = 2147483647, // 2GB maximum
            .description = "Sets the maximum memory to be used for query workspaces",
        });
        try config.registerParameter(.{
            .name = "max_connections",
            .param_type = .integer,
            .default_value = "100",
            .min_value = 1,
            .max_value = 10000,
            .description = "Sets the maximum number of concurrent connections",
        });
        try config.registerParameter(.{
            .name = "statement_timeout",
            .param_type = .integer,
            .default_value = "0", // 0 = no timeout
            .min_value = 0,
            .max_value = 2147483647,
            .description = "Sets the maximum allowed duration of any statement (in milliseconds)",
        });
        try config.registerParameter(.{
            .name = "search_path",
            .param_type = .text,
            .default_value = "public",
            .description = "Sets the schema search order for names that are not schema-qualified",
        });
        try config.registerParameter(.{
            .name = "application_name",
            .param_type = .text,
            .default_value = "",
            .description = "Sets the application name to be reported in statistics and logs",
        });

        // Load configuration from silica.conf if present
        // Search standard locations: ./silica.conf, ~/.config/silica/silica.conf, /etc/silica/silica.conf
        if (findConfigFile(allocator) catch null) |config_path| {
            defer allocator.free(config_path);

            var loader = ConfigLoader.init(allocator, config_path);
            defer loader.deinit();

            // Load and apply config file (ignore errors - use defaults if file is invalid)
            loader.load() catch |err| {
                // Log warning but continue with defaults
                std.debug.print("Warning: Failed to load config from {s}: {}\n", .{ config_path, err });
            };

            // Apply config to manager (this overrides defaults with file values)
            loader.applyTo(&config) catch |err| {
                // Log warning but continue
                std.debug.print("Warning: Failed to apply config from {s}: {}\n", .{ config_path, err });
            };
        }

        return .{
            .allocator = allocator,
            .pager = pager,
            .pool = pool,
            .catalog = cat,
            .schema_arena = std.heap.ArenaAllocator.init(allocator),
            .wal = wal_ptr,
            .tm = tm,
            .db_path = path_copy,
            .lock_manager = LockManager.init(allocator),
            .fsm = FreeSpaceMap.init(allocator, pager.page_size),
            .auto_vacuum = vacuum_mod.AutoVacuumDaemon.init(allocator, opts.auto_vacuum),
            .standby_coordinator = try StandbyCoordinator.init(allocator, opts.standby_mode),
            .config = config,
        };
    }

    /// Close the database, flushing all dirty pages.
    pub fn close(self: *Database) void {
        // Abort any active transaction and release its locks
        if (self.current_txn) |*txn| {
            self.lock_manager.releaseAllLocks(txn.xid);
            self.tm.abort(txn.xid) catch {};
            txn.deinit();
            self.current_txn = null;
        }

        self.auto_vacuum.deinit();
        self.standby_coordinator.deinit();
        self.lock_manager.deinit();
        self.fsm.deinit();
        // Release shared TM (decrements refcount, frees path if last connection)
        global_tm_registry.release(self.db_path);
        // Note: db_path is freed by registry when refcount reaches 0
        // For connections with refcount > 0, the registry still owns the path
        self.allocator.free(self.db_path);
        self.config.deinit();
        self.schema_arena.deinit();

        // Checkpoint WAL before closing — writes committed pages to main DB
        if (self.wal) |w| {
            w.checkpoint(self.pager) catch {};
            w.deinit();
            self.allocator.destroy(w);
            // Clear WAL pointer so BufferPool.deinit doesn't try to use it
            self.pool.wal = null;
        }

        self.pool.deinit();
        self.pager.deinit();
        self.allocator.destroy(self.pool);
        self.allocator.destroy(self.pager);
    }

    // ── Prepared Statements ────────────────────────────────────────────

    /// Prepare a SQL statement for repeated execution.
    /// Performs tokenization, parsing, semantic analysis, and optimization once.
    /// Returns a PreparedStatement that can be executed multiple times with
    /// different bound parameter values, avoiding expensive parse/analyze steps.
    pub fn prepare(self: *Database, allocator: Allocator, sql: []const u8) !PreparedStatement {
        // Create arena for AST (will be owned by PreparedStatement)
        const arena = try allocator.create(AstArena);
        arena.* = AstArena.init(allocator);

        // 1. Parse → AST (tokenization happens inside Parser.init)
        var parser = Parser.init(allocator, sql, arena) catch |err| {
            arena.deinit();
            allocator.destroy(arena);
            return if (err == error.OutOfMemory) error.OutOfMemory else error.InvalidSql;
        };
        defer parser.deinit();

        const maybe_stmt = parser.parseStatement() catch |err| {
            arena.deinit();
            allocator.destroy(arena);
            return if (err == error.OutOfMemory) error.OutOfMemory else error.InvalidSql;
        };
        const stmt = maybe_stmt orelse {
            arena.deinit();
            allocator.destroy(arena);
            return error.InvalidSql;
        };

        // Count parameters (? placeholders) in the AST
        const param_count = countParameters(&stmt);

        // 3. Semantic analysis (uses temporary schema arena)
        _ = &self.schema_arena;
        const schema_provider = self.schemaProvider();
        var analyzer = Analyzer.init(allocator, schema_provider);
        defer analyzer.deinit();
        analyzer.analyze(stmt);
        if (analyzer.hasErrors()) {
            arena.deinit();
            allocator.destroy(arena);
            return error.InvalidSql;
        }

        // 4. Plan → Logical plan
        var planner = Planner.init(arena, schema_provider);
        const logical_plan = planner.plan(stmt) catch |err| {
            arena.deinit();
            allocator.destroy(arena);
            return if (err == error.OutOfMemory) error.OutOfMemory else error.InvalidSql;
        };

        // 5. Optimize
        var optimizer = Optimizer.initWithCatalog(arena, &self.catalog);
        const optimized_plan = optimizer.optimize(logical_plan) catch |err| {
            arena.deinit();
            allocator.destroy(arena);
            return if (err == error.OutOfMemory) error.OutOfMemory else error.InvalidSql;
        };

        // Allocate parameter storage
        const bound_params = try allocator.alloc(?Value, param_count);
        errdefer allocator.free(bound_params);
        @memset(bound_params, null);

        const bound_flags = try allocator.alloc(bool, param_count);
        errdefer allocator.free(bound_flags);
        @memset(bound_flags, false);

        return PreparedStatement{
            .db = self,
            .allocator = allocator,
            .template_arena = arena,
            .plan = optimized_plan,
            .param_count = param_count,
            .bound_params = bound_params,
            .bound_flags = bound_flags,
        };
    }

    /// Helper to merge two optional max indices.
    fn mergeMaxIndex(a: ?u32, b: ?u32) ?u32 {
        if (a == null) return b;
        if (b == null) return a;
        return @max(a.?, b.?);
    }

    /// Count parameter placeholders (?, $N) in an AST using max index approach.
    fn countParameters(stmt: *const ast_mod.Stmt) usize {
        const max_idx = switch (stmt.*) {
            .select => |s| maxParamInSelect(&s),
            .insert => |i| maxParamInInsert(&i),
            .update => |u| maxParamInUpdate(&u),
            .delete => |d| maxParamInDelete(&d),
            else => null,
        } orelse return 0;
        return @as(usize, max_idx) + 1;
    }

    fn maxParamInSelect(select: *const ast_mod.SelectStmt) ?u32 {
        var max: ?u32 = null;
        // Max in WHERE clause
        if (select.where) |where| {
            max = mergeMaxIndex(max, maxParamInExpr(where));
        }
        // Max in projections
        for (select.columns) |col| {
            switch (col) {
                .expr => |e| max = mergeMaxIndex(max, maxParamInExpr(e.value)),
                else => {},
            }
        }
        // Max in ORDER BY
        for (select.order_by) |order| {
            max = mergeMaxIndex(max, maxParamInExpr(order.expr));
        }
        // Max in HAVING
        if (select.having) |having| {
            max = mergeMaxIndex(max, maxParamInExpr(having));
        }
        // Max in JOINs
        for (select.joins) |join| {
            if (join.on_condition) |on| {
                max = mergeMaxIndex(max, maxParamInExpr(on));
            }
        }
        return max;
    }

    fn maxParamInInsert(insert: *const ast_mod.InsertStmt) ?u32 {
        var max: ?u32 = null;
        for (insert.values) |row| {
            for (row) |val| {
                max = mergeMaxIndex(max, maxParamInExpr(val));
            }
        }
        return max;
    }

    fn maxParamInUpdate(update: *const ast_mod.UpdateStmt) ?u32 {
        var max: ?u32 = null;
        for (update.assignments) |assign| {
            max = mergeMaxIndex(max, maxParamInExpr(assign.value));
        }
        if (update.where) |where| {
            max = mergeMaxIndex(max, maxParamInExpr(where));
        }
        return max;
    }

    fn maxParamInDelete(delete: *const ast_mod.DeleteStmt) ?u32 {
        var max: ?u32 = null;
        if (delete.where) |where| {
            max = mergeMaxIndex(max, maxParamInExpr(where));
        }
        return max;
    }

    fn maxParamInExpr(expr: *const ast_mod.Expr) ?u32 {
        return switch (expr.*) {
            .bind_parameter => |idx| idx,
            .binary_op => |b| mergeMaxIndex(maxParamInExpr(b.left), maxParamInExpr(b.right)),
            .unary_op => |u| maxParamInExpr(u.operand),
            .function_call => |f| blk: {
                var max: ?u32 = null;
                for (f.args) |arg| max = mergeMaxIndex(max, maxParamInExpr(arg));
                break :blk max;
            },
            .case_expr => |c| blk: {
                var max: ?u32 = null;
                if (c.operand) |v| max = mergeMaxIndex(max, maxParamInExpr(v));
                for (c.when_clauses) |when| {
                    max = mergeMaxIndex(max, maxParamInExpr(when.condition));
                    max = mergeMaxIndex(max, maxParamInExpr(when.result));
                }
                if (c.else_expr) |e| max = mergeMaxIndex(max, maxParamInExpr(e));
                break :blk max;
            },
            .in_list => |i| blk: {
                var max: ?u32 = maxParamInExpr(i.expr);
                for (i.list) |v| max = mergeMaxIndex(max, maxParamInExpr(v));
                break :blk max;
            },
            .between => |b| mergeMaxIndex(
                mergeMaxIndex(maxParamInExpr(b.expr), maxParamInExpr(b.low)),
                maxParamInExpr(b.high),
            ),
            .cast => |c| maxParamInExpr(c.expr),
            .is_null => |i| maxParamInExpr(i.expr),
            .like => |l| mergeMaxIndex(maxParamInExpr(l.expr), maxParamInExpr(l.pattern)),
            .paren => |p| maxParamInExpr(p),
            .array_subscript => |a| mergeMaxIndex(maxParamInExpr(a.array), maxParamInExpr(a.index)),
            .any => |a| mergeMaxIndex(maxParamInExpr(a.expr), maxParamInExpr(a.array)),
            .all => |a| mergeMaxIndex(maxParamInExpr(a.expr), maxParamInExpr(a.array)),
            .array_constructor => |arr| blk: {
                var max: ?u32 = null;
                for (arr) |elem| max = mergeMaxIndex(max, maxParamInExpr(elem));
                break :blk max;
            },
            .window_function => |w| blk: {
                var max: ?u32 = null;
                for (w.args) |arg| max = mergeMaxIndex(max, maxParamInExpr(arg));
                // Max in PARTITION BY
                for (w.partition_by) |part_expr| max = mergeMaxIndex(max, maxParamInExpr(part_expr));
                // Max in ORDER BY
                for (w.order_by) |order| max = mergeMaxIndex(max, maxParamInExpr(order.expr));
                break :blk max;
            },
            .exists => null, // Subquery params handled separately
            .subquery => null, // Subquery params handled separately
            else => null,
        };
    }

    /// Backwards compatibility wrapper for countParamsInExpr (now uses max-index).
    fn countParamsInExpr(expr: *const ast_mod.Expr) usize {
        const max = maxParamInExpr(expr) orelse return 0;
        return @as(usize, max) + 1;
    }

    /// Execute a plan with bound parameters (used by PreparedStatement).
    fn executePlanWithParams(
        self: *Database,
        template_arena: *AstArena,
        execution_arena: *AstArena,
        plan: LogicalPlan,
        params: []const ?Value,
    ) EngineError!QueryResult {
        // Substitute bound parameters in the plan tree.
        // Read from template_arena (cached plan), allocate new nodes in execution_arena.
        const new_root = substituteParamsInNode(template_arena, execution_arena, plan.root, params) catch |err| {
            // If substitution fails, free the execution_arena (executor hasn't taken ownership yet)
            execution_arena.deinit();
            self.allocator.destroy(execution_arena);
            return if (err == error.OutOfMemory) EngineError.OutOfMemory else EngineError.ExecutionError;
        };
        const substituted_plan = LogicalPlan{
            .root = new_root,
            .plan_type = plan.plan_type,
            .ctes = plan.ctes,
        };
        // Pass execution_arena to executor — it will be freed in executor's defer block
        return self.executePlan(execution_arena, substituted_plan);
    }

    /// Recursively substitute bind parameters in a PlanNode tree.
    /// Reads from template nodes (via `node`), allocates new nodes in `execution_arena`.
    fn substituteParamsInNode(
        template_arena: *AstArena,
        execution_arena: *AstArena,
        node: *const PlanNode,
        params: []const ?Value,
    ) !*const PlanNode {
        const new_node = try execution_arena.allocator().create(PlanNode);
        new_node.* = switch (node.*) {
            .scan, .empty, .table_function_scan => node.*, // No expressions to substitute
            .values_table_scan => |vts| blk: {
                // Substitute bind parameters in VALUES table expressions
                var new_rows = try execution_arena.allocator().alloc([]const *const ast_mod.Expr, vts.rows.len);
                for (vts.rows, 0..) |row, i| {
                    var new_row = try execution_arena.allocator().alloc(*const ast_mod.Expr, row.len);
                    for (row, 0..) |expr, j| {
                        new_row[j] = try substituteExpr(template_arena, execution_arena, expr, params);
                    }
                    new_rows[i] = new_row;
                }
                break :blk .{ .values_table_scan = .{
                    .rows = new_rows,
                    .alias = vts.alias,
                    .column_names = vts.column_names,
                } };
            },
            .values => |v| blk: {
                // Substitute bind parameters in VALUES expressions
                var new_rows = try execution_arena.allocator().alloc([]const *const ast_mod.Expr, v.rows.len);
                for (v.rows, 0..) |row, i| {
                    var new_row = try execution_arena.allocator().alloc(*const ast_mod.Expr, row.len);
                    for (row, 0..) |expr, j| {
                        new_row[j] = try substituteExpr(template_arena, execution_arena, expr, params);
                    }
                    new_rows[i] = new_row;
                }
                break :blk .{ .values = .{
                    .table = v.table,
                    .columns = v.columns,
                    .rows = new_rows,
                } };
            },
            .filter => |f| .{ .filter = .{
                .input = try substituteParamsInNode(template_arena, execution_arena, f.input, params),
                .predicate = try substituteExpr(template_arena, execution_arena, f.predicate, params),
            } },
            .project => |p| blk: {
                var new_cols = try execution_arena.allocator().alloc(PlanNode.ProjectColumn, p.columns.len);
                for (p.columns, 0..) |col, i| {
                    new_cols[i] = .{
                        .expr = try substituteExpr(template_arena, execution_arena, col.expr, params),
                        .alias = col.alias,
                    };
                }
                break :blk .{ .project = .{
                    .input = try substituteParamsInNode(template_arena, execution_arena, p.input, params),
                    .columns = new_cols,
                } };
            },
            .join => |j| .{ .join = .{
                .left = try substituteParamsInNode(template_arena, execution_arena, j.left, params),
                .right = try substituteParamsInNode(template_arena, execution_arena, j.right, params),
                .join_type = j.join_type,
                .on_condition = if (j.on_condition) |cond| try substituteExpr(template_arena, execution_arena, cond, params) else null,
                .algorithm = j.algorithm,
            } },
            .sort => |s| .{ .sort = .{
                .input = try substituteParamsInNode(template_arena, execution_arena, s.input, params),
                .order_by = s.order_by, // OrderByItem contains expressions but they're rarely bind parameters
            } },
            .aggregate => |a| .{ .aggregate = .{
                .input = try substituteParamsInNode(template_arena, execution_arena, a.input, params),
                .group_by = a.group_by, // Could have bind parameters, but rare
                .aggregates = a.aggregates, // Aggregate args could have bind parameters, but rare
                .grouping_sets = a.grouping_sets,
            } },
            .limit => |l| .{ .limit = .{
                .input = try substituteParamsInNode(template_arena, execution_arena, l.input, params),
                .limit_expr = if (l.limit_expr) |expr| try substituteExpr(template_arena, execution_arena, expr, params) else null,
                .offset_expr = if (l.offset_expr) |expr| try substituteExpr(template_arena, execution_arena, expr, params) else null,
                .with_ties = l.with_ties,
                .order_by = l.order_by,
            } },
            .distinct => |d| .{ .distinct = .{
                .input = try substituteParamsInNode(template_arena, execution_arena, d.input, params),
                .on_exprs = d.on_exprs,
            } },
            .set_op => |s| .{ .set_op = .{
                .op = s.op,
                .left = try substituteParamsInNode(template_arena, execution_arena, s.left, params),
                .right = try substituteParamsInNode(template_arena, execution_arena, s.right, params),
            } },
            .window => |w| .{ .window = .{
                .input = try substituteParamsInNode(template_arena, execution_arena, w.input, params),
                .funcs = w.funcs, // Window function exprs could have bind parameters, but rare
                .aliases = w.aliases,
            } },
        };
        return new_node;
    }

    /// Recursively substitute bind parameters in an expression.
    /// Reads from template expressions (via `expr`), allocates new expressions in `execution_arena`.
    fn substituteExpr(
        template_arena: *AstArena,
        execution_arena: *AstArena,
        expr: *const ast_mod.Expr,
        params: []const ?Value,
    ) !*const ast_mod.Expr {
        return switch (expr.*) {
            .bind_parameter => |idx| blk: {
                // Replace bind parameter with the corresponding value literal
                if (idx >= params.len) return error.InvalidParameterIndex;
                const value = params[idx] orelse return error.UnboundParameter;
                const alloc = execution_arena.allocator();
                const literal: ast_mod.Expr = e: {
                    switch (value) {
                        .integer => |i| break :e .{ .integer_literal = i },
                        .real => |r| break :e .{ .float_literal = r },
                        .text => |t| break :e .{ .string_literal = t },
                        .blob => |b| break :e .{ .blob_literal = b },
                        .null_value => break :e .null_literal,
                        .boolean => |b| break :e .{ .boolean_literal = b },
                        // Advanced types: produce CAST('formatted_value' AS type) so that
                        // Value.compare() receives matching types (date vs date, not date vs text).
                        .date => |d| {
                            const s = try executor_mod.formatDate(alloc, d);
                            const inner = try execution_arena.create(ast_mod.Expr, .{ .string_literal = s });
                            break :e .{ .cast = .{ .expr = inner, .target_type = .type_date } };
                        },
                        .time => |t| {
                            const s = try executor_mod.formatTime(alloc, t);
                            const inner = try execution_arena.create(ast_mod.Expr, .{ .string_literal = s });
                            break :e .{ .cast = .{ .expr = inner, .target_type = .type_time } };
                        },
                        .timestamp => |ts| {
                            const s = try executor_mod.formatTimestamp(alloc, ts);
                            const inner = try execution_arena.create(ast_mod.Expr, .{ .string_literal = s });
                            break :e .{ .cast = .{ .expr = inner, .target_type = .type_timestamp } };
                        },
                        .interval => |iv| {
                            const s = try executor_mod.formatInterval(alloc, iv);
                            const inner = try execution_arena.create(ast_mod.Expr, .{ .string_literal = s });
                            break :e .{ .cast = .{ .expr = inner, .target_type = .type_interval } };
                        },
                        .numeric => |n| {
                            const s = try executor_mod.formatNumeric(alloc, n);
                            const inner = try execution_arena.create(ast_mod.Expr, .{ .string_literal = s });
                            break :e .{ .cast = .{ .expr = inner, .target_type = .type_numeric } };
                        },
                        .uuid => |u| {
                            const s = try executor_mod.formatUuid(alloc, u);
                            const inner = try execution_arena.create(ast_mod.Expr, .{ .string_literal = s });
                            break :e .{ .cast = .{ .expr = inner, .target_type = .type_uuid } };
                        },
                        .array => |arr| break :e .{ .string_literal = try executor_mod.formatArray(alloc, arr) },
                        .tsvector => |v| break :e .{ .string_literal = v },
                        .tsquery => |v| break :e .{ .string_literal = v },
                    }
                };
                break :blk execution_arena.create(ast_mod.Expr, literal) catch return error.OutOfMemory;
            },
            .binary_op => |b| execution_arena.create(ast_mod.Expr, .{ .binary_op = .{
                .op = b.op,
                .left = try substituteExpr(template_arena, execution_arena, b.left, params),
                .right = try substituteExpr(template_arena, execution_arena, b.right, params),
            } }) catch return error.OutOfMemory,
            .unary_op => |u| execution_arena.create(ast_mod.Expr, .{ .unary_op = .{
                .op = u.op,
                .operand = try substituteExpr(template_arena, execution_arena, u.operand, params),
            } }) catch return error.OutOfMemory,
            .function_call => |f| blk: {
                var new_args = try execution_arena.allocator().alloc(*const ast_mod.Expr, f.args.len);
                for (f.args, 0..) |arg, i| {
                    new_args[i] = try substituteExpr(template_arena, execution_arena, arg, params);
                }
                break :blk execution_arena.create(ast_mod.Expr, .{ .function_call = .{
                    .name = f.name,
                    .args = new_args,
                    .distinct = f.distinct,
                } }) catch return error.OutOfMemory;
            },
            .case_expr => |c| blk: {
                var new_whens = try execution_arena.allocator().alloc(ast_mod.WhenClause, c.when_clauses.len);
                for (c.when_clauses, 0..) |when, i| {
                    new_whens[i] = .{
                        .condition = try substituteExpr(template_arena, execution_arena, when.condition, params),
                        .result = try substituteExpr(template_arena, execution_arena, when.result, params),
                    };
                }
                break :blk execution_arena.create(ast_mod.Expr, .{ .case_expr = .{
                    .operand = if (c.operand) |op| try substituteExpr(template_arena, execution_arena, op, params) else null,
                    .when_clauses = new_whens,
                    .else_expr = if (c.else_expr) |els| try substituteExpr(template_arena, execution_arena, els, params) else null,
                } }) catch return error.OutOfMemory;
            },
            .in_list => |i| blk: {
                var new_list = try execution_arena.allocator().alloc(*const ast_mod.Expr, i.list.len);
                for (i.list, 0..) |val, idx| {
                    new_list[idx] = try substituteExpr(template_arena, execution_arena, val, params);
                }
                break :blk execution_arena.create(ast_mod.Expr, .{ .in_list = .{
                    .expr = try substituteExpr(template_arena, execution_arena, i.expr, params),
                    .list = new_list,
                    .negated = i.negated,
                } }) catch return error.OutOfMemory;
            },
            .between => |b| execution_arena.create(ast_mod.Expr, .{ .between = .{
                .expr = try substituteExpr(template_arena, execution_arena, b.expr, params),
                .low = try substituteExpr(template_arena, execution_arena, b.low, params),
                .high = try substituteExpr(template_arena, execution_arena, b.high, params),
                .negated = b.negated,
            } }) catch return error.OutOfMemory,
            .like => |l| execution_arena.create(ast_mod.Expr, .{ .like = .{
                .expr = try substituteExpr(template_arena, execution_arena, l.expr, params),
                .pattern = try substituteExpr(template_arena, execution_arena, l.pattern, params),
                .negated = l.negated,
            } }) catch return error.OutOfMemory,
            .array_subscript => |s| execution_arena.create(ast_mod.Expr, .{ .array_subscript = .{
                .array = try substituteExpr(template_arena, execution_arena, s.array, params),
                .index = try substituteExpr(template_arena, execution_arena, s.index, params),
            } }) catch return error.OutOfMemory,
            // Literals and column refs don't need substitution
            else => expr,
        };
    }

    // ── Transaction Management ────────────────────────────────────────

    /// Begin an explicit transaction with the given isolation level.
    pub fn beginTransaction(self: *Database, isolation: IsolationLevel) EngineError!void {
        if (self.current_txn != null) return EngineError.TransactionError; // Already in a transaction

        const xid = self.tm.begin(isolation) catch return EngineError.TransactionError;
        self.current_txn = .{
            .xid = xid,
            .isolation = isolation,
            .allocator = self.allocator,
        };

        // For REPEATABLE READ / SERIALIZABLE, take snapshot at BEGIN time
        if (isolation != .read_committed) {
            const snap = self.tm.getSnapshot(xid) catch return EngineError.TransactionError;
            self.current_txn.?.snapshot = snap;
        }
    }

    /// Commit the current transaction.
    pub fn commitTransaction(self: *Database) EngineError!void {
        const txn = self.current_txn orelse return EngineError.NoActiveTransaction;

        // Release all locks held by this transaction
        self.lock_manager.releaseAllLocks(txn.xid);
        // For RR/SERIALIZABLE: tm.commit() frees the snapshot in TransactionManager,
        // so clear our copy first to prevent double-free in ctx.deinit().
        if (txn.isolation != .read_committed) {
            self.current_txn.?.snapshot = null;
        }
        // TransactionManager.commit() handles SSI check and finishTransaction internally
        self.tm.commit(txn.xid) catch |err| {
            if (err == error.SerializationFailure) {
                // Serialization failure — abort instead of commit
                self.current_txn.?.snapshot = null;
                // abort() should not fail here since txn is known active
                self.tm.abort(txn.xid) catch return EngineError.TransactionError;
                self.current_txn.?.deinit();
                self.current_txn = null;
                return EngineError.SerializationFailure;
            }
            return EngineError.TransactionError;
        };
        self.commitWal() catch {};
        // Clean up savepoints and other transaction resources
        self.current_txn.?.deinit();
        self.current_txn = null;

        // Record commit for auto-vacuum and trigger if thresholds exceeded
        self.auto_vacuum.recordCommit();
        self.runAutoVacuumIfNeeded();
    }

    /// Rollback the current transaction.
    pub fn rollbackTransaction(self: *Database) EngineError!void {
        const txn = self.current_txn orelse return EngineError.NoActiveTransaction;
        // Release all locks held by this transaction
        self.lock_manager.releaseAllLocks(txn.xid);
        // For RR/SERIALIZABLE: tm.abort() frees the snapshot in TransactionManager,
        // so clear our copy first to prevent double-free in ctx.deinit().
        if (txn.isolation != .read_committed) {
            self.current_txn.?.snapshot = null;
        }
        self.tm.abort(txn.xid) catch return EngineError.TransactionError;
        if (self.wal) |w| {
            w.rollback() catch {};
        }
        // Clean up savepoints and other transaction resources
        self.current_txn.?.deinit();
        self.current_txn = null;
    }

    // ── Savepoint Management ──────────────────────────────────────────

    /// Create a named savepoint within the current transaction.
    pub fn createSavepoint(self: *Database, name: []const u8) EngineError!void {
        var txn = &(self.current_txn orelse return EngineError.NoActiveTransaction);
        const alloc = txn.allocator orelse return EngineError.TransactionError;

        // Get current CID to save the transaction's command position
        const cid = self.tm.getCurrentCid(txn.xid) catch return EngineError.TransactionError;

        // Duplicate the name for ownership
        const owned_name = alloc.dupe(u8, name) catch return EngineError.OutOfMemory;

        // If savepoint with same name exists, replace it
        for (txn.savepoints.items, 0..) |*sp, idx| {
            if (std.mem.eql(u8, sp.name, name)) {
                alloc.free(sp.name);
                txn.savepoints.items[idx] = .{ .name = owned_name, .cid = cid };
                return;
            }
        }

        txn.savepoints.append(alloc, .{ .name = owned_name, .cid = cid }) catch return EngineError.OutOfMemory;
    }

    /// Release a savepoint (discard it, merging into parent transaction).
    pub fn releaseSavepoint(self: *Database, name: []const u8) EngineError!void {
        var txn = &(self.current_txn orelse return EngineError.NoActiveTransaction);
        const alloc = txn.allocator orelse return EngineError.TransactionError;

        // Find the savepoint
        for (txn.savepoints.items, 0..) |sp, idx| {
            if (std.mem.eql(u8, sp.name, name)) {
                alloc.free(sp.name);
                _ = txn.savepoints.orderedRemove(idx);
                return;
            }
        }
        return EngineError.SavepointNotFound;
    }

    /// Rollback to a named savepoint, undoing commands issued after it.
    pub fn rollbackToSavepoint(self: *Database, name: []const u8) EngineError!void {
        var txn = &(self.current_txn orelse return EngineError.NoActiveTransaction);
        const alloc = txn.allocator orelse return EngineError.TransactionError;

        // Find the savepoint
        var found_idx: ?usize = null;
        for (txn.savepoints.items, 0..) |sp, idx| {
            if (std.mem.eql(u8, sp.name, name)) {
                found_idx = idx;
                break;
            }
        }
        const idx = found_idx orelse return EngineError.SavepointNotFound;
        const saved_cid = txn.savepoints.items[idx].cid;

        // Remove all savepoints created after this one (nested savepoints above are discarded)
        while (txn.savepoints.items.len > idx + 1) {
            if (txn.savepoints.pop()) |removed| {
                alloc.free(removed.name);
            }
        }

        // Reset the CID to the savepoint's value, effectively making
        // commands issued after the savepoint invisible within this transaction's
        // visibility rules (cid-based filtering in isTupleVisible).
        self.tm.resetCid(txn.xid, saved_cid) catch return EngineError.TransactionError;
    }

    /// Get MVCC context for the current statement.
    /// If `ops` is provided, RC snapshots are stored in `ops.rc_snapshot` for cleanup.
    /// If `ops` is null (UPDATE/DELETE), the caller must free the snapshot.
    fn getMvccContext(self: *Database) EngineError!?MvccContext {
        return self.getMvccContextWithOps(null);
    }

    /// Get MVCC context, optionally storing RC snapshot in OperatorChain.
    fn getMvccContextWithOps(self: *Database, ops: ?*OperatorChain) EngineError!?MvccContext {
        if (self.current_txn) |txn| {
            const cid = self.tm.getCurrentCid(txn.xid) catch return EngineError.TransactionError;

            // For READ COMMITTED: fresh snapshot per statement
            if (txn.isolation == .read_committed) {
                const snap = self.tm.getSnapshot(txn.xid) catch return EngineError.TransactionError;
                // If we have an OperatorChain, store the snapshot there for cleanup
                if (ops) |o| {
                    o.rc_snapshot = snap;
                }
                return MvccContext{
                    .snapshot = snap,
                    .current_xid = txn.xid,
                    .current_cid = cid,
                    .tm = self.tm,
                };
            }
            // REPEATABLE READ / SERIALIZABLE: use stored snapshot (not owned by us)
            if (txn.snapshot) |snap| {
                return MvccContext{
                    .snapshot = snap,
                    .current_xid = txn.xid,
                    .current_cid = cid,
                    .tm = self.tm,
                };
            }
        }
        // Auto-commit mode: use empty snapshot with TM for visibility filtering.
        // This ensures aborted transactions are filtered out even without an explicit transaction.
        return MvccContext{
            .snapshot = mvcc_mod.Snapshot.EMPTY,
            .current_xid = mvcc_mod.INVALID_XID,
            .current_cid = 0,
            .tm = self.tm,
        };
    }

    /// Register a table read for SSI tracking (SERIALIZABLE transactions only).
    fn ssiRegisterRead(self: *Database, table_page_id: u32) EngineError!void {
        if (self.current_txn) |txn| {
            if (txn.isolation == .serializable) {
                self.tm.registerRead(txn.xid, table_page_id) catch return EngineError.OutOfMemory;
            }
        }
    }

    /// Register a table write for SSI tracking (SERIALIZABLE transactions only).
    fn ssiRegisterWrite(self: *Database, table_page_id: u32) EngineError!void {
        if (self.current_txn) |txn| {
            if (txn.isolation == .serializable) {
                self.tm.registerWrite(txn.xid, table_page_id) catch return EngineError.OutOfMemory;
            }
        }
    }

    /// Advance the command ID for the current transaction.
    /// Returns the CID to use for this statement's writes.
    fn advanceStatementCid(self: *Database) EngineError!u16 {
        if (self.current_txn) |txn| {
            return self.tm.advanceCid(txn.xid) catch return EngineError.TransactionError;
        }
        return 0; // Auto-commit: CID doesn't matter
    }

    /// Execute a SQL statement and return results.
    pub fn exec(self: *Database, sql: []const u8) EngineError!QueryResult {
        // Delegate to execSQL which handles both DDL and DML correctly
        return self.execSQL(sql);
    }

    /// Execute CREATE TABLE AS SELECT (CTAS)
    fn executeCTAS(self: *Database, arena: *AstArena, ctas: *const ast_mod.CreateTableStmt) EngineError!QueryResult {
        defer {
            arena.deinit();
            self.allocator.destroy(arena);
        }

        const select_stmt = ctas.as_select orelse return EngineError.ExecutionError;

        // Check if table already exists
        if (!ctas.if_not_exists) {
            if (self.catalog.getTable(ctas.name)) |table| {
                table.deinit(self.allocator);
                return EngineError.TableAlreadyExists;
            } else |_| {
                // Expected: table does not exist
            }
        } else {
            if (self.catalog.getTable(ctas.name)) |table| {
                table.deinit(self.allocator);
                // Table exists and IF NOT EXISTS was specified, so this is a no-op
                return .{ .message = "CREATE TABLE" };
            } else |_| {
                // Expected: table does not exist
            }
        }

        // Analyze the SELECT statement
        const provider = self.schemaProvider();
        var an = Analyzer.init(self.allocator, provider);
        defer an.deinit();
        an.analyze(.{ .select = select_stmt.* });
        if (an.hasErrors()) return EngineError.AnalysisError;

        // Plan the SELECT query
        var plnr = Planner.init(arena, provider);
        const plan = plnr.plan(.{ .select = select_stmt.* }) catch return EngineError.PlanError;

        var opt = Optimizer.init(arena);
        const optimized = opt.optimize(plan) catch return EngineError.PlanError;

        // Execute the SELECT query to get result rows
        const ops = self.allocator.create(OperatorChain) catch return EngineError.OutOfMemory;
        ops.* = .{};
        defer ops.deinit(self.allocator);

        const iter = self.buildIterator(optimized.root, ops) catch return EngineError.ExecutionError;

        // Collect all rows from the SELECT and capture column names
        var result_rows = std.ArrayListUnmanaged([]Value){};
        defer {
            for (result_rows.items) |row_vals| {
                for (row_vals) |v| v.free(self.allocator);
                self.allocator.free(row_vals);
            }
            result_rows.deinit(self.allocator);
        }

        var captured_names: ?[][]const u8 = null;
        defer if (captured_names) |names| {
            for (names) |n| self.allocator.free(n);
            self.allocator.free(names);
        };

        while ((iter.next() catch |err| {
            return switch (err) {
                error.ColumnNotFound => EngineError.ExecutionError,
                error.ExecutionError => EngineError.ExecutionError,
                error.OutOfMemory => EngineError.OutOfMemory,
                error.StorageError => EngineError.StorageError,
                error.TableNotFound => EngineError.TableNotFound,
                error.DivisionByZero => EngineError.ExecutionError,
                error.TypeError => EngineError.ExecutionError,
                error.UnsupportedExpression => EngineError.ExecutionError,
                error.InvalidRowData => EngineError.ExecutionError,
                error.LockConflict => EngineError.LockConflict,
                error.InvalidPattern => EngineError.ExecutionError,
            };
        })) |row| {
            var mutable_row = row;

            // Capture column names from the first row (dupe the strings)
            if (captured_names == null and mutable_row.columns.len > 0) {
                const names = self.allocator.alloc([]const u8, mutable_row.columns.len) catch return EngineError.OutOfMemory;
                var duped: usize = 0;
                errdefer {
                    for (names[0..duped]) |n| self.allocator.free(n);
                    self.allocator.free(names);
                }
                for (mutable_row.columns) |cn| {
                    names[duped] = self.allocator.dupe(u8, cn) catch return EngineError.OutOfMemory;
                    duped += 1;
                }
                captured_names = names;
            }

            const vals = self.allocator.alloc(Value, mutable_row.values.len) catch return EngineError.OutOfMemory;
            for (mutable_row.values, 0..) |v, i| {
                vals[i] = v.dupe(self.allocator) catch return EngineError.OutOfMemory;
            }
            mutable_row.deinit();
            result_rows.append(self.allocator, vals) catch return EngineError.OutOfMemory;
        }

        iter.close();

        // Build column schema for the new table.
        // Prefer captured_names (from actual execution) for correctness with SELECT *.
        // Fall back to AST-based names when result was empty (named columns only).
        var columns = std.ArrayListUnmanaged(ast_mod.ColumnDef){};
        defer {
            for (columns.items) |col| self.allocator.free(col.name);
            columns.deinit(self.allocator);
        }

        if (captured_names) |names| {
            // Use names from executed result (correct for SELECT *, aliases, etc.)
            for (names, 0..) |name, col_idx| {
                var inferred_type = ast_mod.DataType.type_text;
                if (result_rows.items.len > 0 and col_idx < result_rows.items[0].len) {
                    inferred_type = switch (result_rows.items[0][col_idx]) {
                        .null_value => ast_mod.DataType.type_text,
                        .integer => ast_mod.DataType.type_integer,
                        .real => ast_mod.DataType.type_real,
                        .text => ast_mod.DataType.type_text,
                        .blob => ast_mod.DataType.type_blob,
                        .boolean => ast_mod.DataType.type_boolean,
                        .array => ast_mod.DataType.type_array,
                        .date => ast_mod.DataType.type_date,
                        .time => ast_mod.DataType.type_time,
                        .timestamp => ast_mod.DataType.type_timestamp,
                        .uuid => ast_mod.DataType.type_uuid,
                        .interval => ast_mod.DataType.type_interval,
                        .numeric => ast_mod.DataType.type_numeric,
                        .tsvector => ast_mod.DataType.type_tsvector,
                        .tsquery => ast_mod.DataType.type_tsquery,
                    };
                }
                columns.append(self.allocator, .{
                    .name = self.allocator.dupe(u8, name) catch return EngineError.OutOfMemory,
                    .data_type = inferred_type,
                    .constraints = &.{},
                    .generated_expr_sql = null,
                }) catch return EngineError.OutOfMemory;
            }
        } else {
            // Empty result set: fall back to AST-based column names (named columns only).
            // SELECT * with empty result is not supported for schema inference.
            for (select_stmt.columns, 0..) |result_col, col_idx| {
                const col_name: []const u8 = switch (result_col) {
                    .expr => |e| if (e.alias) |alias|
                        self.allocator.dupe(u8, alias) catch return EngineError.OutOfMemory
                    else switch (e.value.*) {
                        .column_ref => |cr| self.allocator.dupe(u8, cr.name) catch return EngineError.OutOfMemory,
                        else => self.allocator.dupe(u8, "?column?") catch return EngineError.OutOfMemory,
                    },
                    .all_columns, .table_all_columns => self.allocator.dupe(u8, "?column?") catch return EngineError.OutOfMemory,
                };
                errdefer self.allocator.free(col_name);
                _ = col_idx;
                columns.append(self.allocator, .{
                    .name = col_name,
                    .data_type = ast_mod.DataType.type_text,
                    .constraints = &.{},
                    .generated_expr_sql = null,
                }) catch return EngineError.OutOfMemory;
            }
        }

        // Create the table with inferred schema
        const new_ctas = ast_mod.CreateTableStmt{
            .if_not_exists = ctas.if_not_exists,
            .name = ctas.name,
            .columns = columns.toOwnedSlice(self.allocator) catch return EngineError.OutOfMemory,
            .table_constraints = &.{},
            .without_rowid = false,
            .strict = false,
            .as_select = null,
        };

        self.catalog.createTableFromAst(&new_ctas) catch |err| {
            for (new_ctas.columns) |col| {
                self.allocator.free(col.name);
            }
            self.allocator.free(new_ctas.columns);
            return switch (err) {
                error.TableAlreadyExists => EngineError.TableAlreadyExists,
                error.OutOfMemory => EngineError.OutOfMemory,
                else => EngineError.StorageError,
            };
        };

        // Free the inferred columns (catalog made copies)
        for (new_ctas.columns) |col| {
            self.allocator.free(col.name);
        }
        self.allocator.free(new_ctas.columns);

        // Insert all collected rows into the new table
        if (result_rows.items.len > 0) {
            var table_info = self.catalog.getTable(ctas.name) catch return EngineError.TableNotFound;
            defer table_info.deinit(self.allocator);

            var tx_created = false;
            if (self.current_txn == null) {
                try self.beginTransaction(.read_committed);
                tx_created = true;
            }
            defer {
                if (tx_created) {
                    self.commitTransaction() catch {};
                }
            }

            try self.ssiRegisterWrite(table_info.data_root_page_id);

            var tree = BTree.init(self.pool, table_info.data_root_page_id);
            var next_key: u64 = self.findNextRowKey(&tree) catch return EngineError.StorageError;

            for (result_rows.items) |row_vals| {
                // Serialize the row
                const row_data = serializeRow(self.allocator, row_vals) catch return EngineError.OutOfMemory;
                defer self.allocator.free(row_data);

                // Generate key: 8-byte big-endian u64
                var key_buf: [8]u8 = undefined;
                std.mem.writeInt(u64, &key_buf, next_key, .big);
                const key = self.allocator.dupe(u8, &key_buf) catch return EngineError.OutOfMemory;
                defer self.allocator.free(key);

                // Insert into the tree
                tree.insert(key, row_data) catch return EngineError.StorageError;
                next_key += 1;
            }

            // Update root page ID in case of B+Tree split
            if (tree.root_page_id != table_info.data_root_page_id) {
                self.updateTableRootPage(ctas.name, tree.root_page_id) catch return EngineError.StorageError;
            }
        }

        self.commitWal() catch {};
        return .{ .message = "CREATE TABLE" };
    }

    fn executePlan(self: *Database, arena: *AstArena, plan: LogicalPlan) EngineError!QueryResult {
        // Determine if this is a DML statement that needs implicit transaction in auto-commit mode
        const is_dml = switch (plan.plan_type) {
            .insert, .update, .delete => true,
            else => false,
        };

        // Auto-commit DML: Create implicit transaction with READ COMMITTED isolation
        // This ensures all writes go through TransactionManager with proper MVCC headers
        const implicit_txn = self.current_txn == null and is_dml;
        if (implicit_txn) {
            try self.beginTransaction(.read_committed);
        }
        errdefer {
            // If execution fails and we created implicit txn, roll it back
            if (implicit_txn) {
                self.rollbackTransaction() catch {};
            }
        }

        // Advance CID in explicit transactions (one CID per statement)
        if (self.current_txn != null) {
            _ = self.advanceStatementCid() catch {};
        }

        const result = switch (plan.plan_type) {
            .select_query => self.executeSelect(arena, plan),
            .insert => self.executeInsert(arena, plan),
            .update => self.executeUpdate(arena, plan),
            .delete => self.executeDelete(arena, plan),
            .create_table => self.executeCreateTable(arena, plan),
            .drop_table => self.executeDropTable(arena, plan),
            else => {
                arena.deinit();
                self.allocator.destroy(arena);
                return .{ .message = "OK" };
            },
        };

        // Auto-commit implicit transaction: commit it now
        if (implicit_txn) {
            if (result) |_| {
                try self.commitTransaction();
            } else |err| {
                self.rollbackTransaction() catch {};
                return err;
            }
        } else if (self.current_txn == null) {
            // Non-DML auto-commit (DDL): commit WAL immediately
            if (result) |r| {
                if (r.rows == null) {
                    self.commitWal() catch {};
                }
            } else |_| {}
        }

        return result;
    }

    /// Flush dirty buffer pool pages and commit the WAL transaction.
    fn commitWal(self: *Database) !void {
        if (self.wal) |w| {
            try self.pool.flushAll();
            try w.commit(self.pager.page_count);
        }
    }

    // ── SELECT execution ──────────────────────────────────────────────

    fn executeSelect(self: *Database, arena: *AstArena, plan: LogicalPlan) EngineError!QueryResult {
        const ops = self.allocator.create(OperatorChain) catch return EngineError.OutOfMemory;
        ops.* = .{};
        ops.locking_clauses = plan.locking_clauses;
        errdefer ops.deinit(self.allocator);

        // Materialize CTEs before executing main query
        if (plan.ctes.len > 0) {
            try self.materializeCtes(plan.ctes, ops);
        }

        // Apply RLS filtering if enabled
        var mutable_plan = plan;
        const primary_table = getPrimaryTableFromPlan(plan.root);
        if (primary_table) |table_name| {
            const rls_enabled = self.catalog.isRLSEnabled(table_name) catch false;
            if (rls_enabled) {
                const policies = self.catalog.listPoliciesForTable(self.allocator, table_name) catch null;
                if (policies) |policy_names| {
                    defer {
                        for (policy_names) |name| self.allocator.free(name);
                        self.allocator.free(policy_names);
                    }
                    // Build OR condition from all USING expressions for PERMISSIVE policies
                    var rls_conditions: std.ArrayListUnmanaged(*const ast_mod.Expr) = .{};
                    defer rls_conditions.deinit(self.allocator);

                    for (policy_names) |policy_name| {
                        const policy_info = self.catalog.getPolicy(table_name, policy_name) catch continue;
                        defer policy_info.deinit();

                        if (policy_info.command != .select) continue;
                        if (policy_info.policy_type != .permissive) continue;
                        if (policy_info.using_expr) |using_expr_str| {
                            // Dupe the SQL into the query arena so column name slices
                            // in the parsed AST remain valid after policy_info is freed.
                            const owned_sql = arena.arena.allocator().dupe(u8, using_expr_str) catch continue;

                            var infra_alloc = std.heap.ArenaAllocator.init(self.allocator);
                            defer infra_alloc.deinit();

                            var p = Parser.init(infra_alloc.allocator(), owned_sql, arena) catch continue;
                            defer p.deinit();

                            if (p.parseExpr(0) catch null) |expr| {
                                rls_conditions.append(self.allocator, expr) catch continue;
                            }
                        }
                    }

                    // If there are RLS conditions, add them to the plan
                    if (rls_conditions.items.len > 0) {
                        // Build an OR expression from all conditions
                        var rls_filter: ?*const ast_mod.Expr = rls_conditions.items[0];
                        for (rls_conditions.items[1..]) |cond| {
                            const or_expr = arena.arena.allocator().create(ast_mod.Expr) catch continue;
                            or_expr.* = .{
                                .binary_op = .{
                                    .left = rls_filter.?,
                                    .right = cond,
                                    .op = .@"or",
                                },
                            };
                            rls_filter = or_expr;
                        }

                        // Wrap plan in a Filter node if needed
                        if (rls_filter) |filter_expr| {
                            const filter_node = arena.arena.allocator().create(PlanNode) catch return EngineError.OutOfMemory;
                            filter_node.* = .{
                                .filter = .{
                                    .input = plan.root,
                                    .predicate = filter_expr,
                                },
                            };
                            mutable_plan.root = filter_node;
                        }
                    }
                }
            }
        }

        const iter = self.buildIterator(mutable_plan.root, ops) catch return EngineError.ExecutionError;
        return .{
            .rows = iter,
            ._arena = arena,
            ._ops = ops,
        };
    }

    /// Extract the primary table name from a plan node (if it's a simple scan).
    fn getPrimaryTableFromPlan(node: *const PlanNode) ?[]const u8 {
        return switch (node.*) {
            .scan => |s| s.table,
            .filter => |f| getPrimaryTableFromPlan(f.input),
            .project => |p| getPrimaryTableFromPlan(p.input),
            else => null,
        };
    }

    /// Build an OR of all USING expressions from PERMISSIVE policies matching `command` for the table.
    /// Returns null if RLS is disabled or no matching USING expressions exist.
    fn buildRlsUsingExpr(
        self: *Database,
        arena: *AstArena,
        table_name: []const u8,
        command: ast_mod.PolicyCommand,
    ) EngineError!?*const ast_mod.Expr {
        const rls_enabled = self.catalog.isRLSEnabled(table_name) catch false;
        if (!rls_enabled) return null;

        const policy_names = self.catalog.listPoliciesForTable(self.allocator, table_name) catch return null;
        defer {
            for (policy_names) |name| self.allocator.free(name);
            self.allocator.free(policy_names);
        }

        var conditions: std.ArrayListUnmanaged(*const ast_mod.Expr) = .{};
        defer conditions.deinit(self.allocator);

        for (policy_names) |policy_name| {
            const policy_info = self.catalog.getPolicy(table_name, policy_name) catch continue;
            defer policy_info.deinit();

            if (policy_info.policy_type != .permissive) continue;
            const matches = policy_info.command == command or policy_info.command == .all;
            if (!matches) continue;

            if (policy_info.using_expr) |using_expr_str| {
                // Dupe the SQL into the query arena so column name slices
                // in the parsed AST remain valid after policy_info is freed.
                const owned_sql = arena.arena.allocator().dupe(u8, using_expr_str) catch continue;

                var infra_alloc = std.heap.ArenaAllocator.init(self.allocator);
                defer infra_alloc.deinit();

                var p = Parser.init(infra_alloc.allocator(), owned_sql, arena) catch continue;
                defer p.deinit();

                if (p.parseExpr(0) catch null) |expr| {
                    conditions.append(self.allocator, expr) catch continue;
                }
            }
        }

        if (conditions.items.len == 0) return null;

        var result: *const ast_mod.Expr = conditions.items[0];
        for (conditions.items[1..]) |cond| {
            const or_expr = arena.create(ast_mod.Expr, .{
                .binary_op = .{ .left = result, .right = cond, .op = .@"or" },
            }) catch return EngineError.OutOfMemory;
            result = or_expr;
        }
        return result;
    }

    /// Evaluate all PERMISSIVE policies' WITH CHECK expressions for INSERT/UPDATE on a candidate row.
    /// Returns EngineError.RlsPolicyViolation if any WITH CHECK expression evaluates to false.
    fn checkRlsWithCheck(
        self: *Database,
        arena: *AstArena,
        table_name: []const u8,
        col_names: []const []const u8,
        vals: []Value,
        command: ast_mod.PolicyCommand,
    ) EngineError!void {
        const rls_enabled = self.catalog.isRLSEnabled(table_name) catch false;
        if (!rls_enabled) return;

        const policy_names = self.catalog.listPoliciesForTable(self.allocator, table_name) catch return;
        defer {
            for (policy_names) |name| self.allocator.free(name);
            self.allocator.free(policy_names);
        }

        for (policy_names) |policy_name| {
            const policy_info = self.catalog.getPolicy(table_name, policy_name) catch continue;
            defer policy_info.deinit();

            if (policy_info.policy_type != .permissive) continue;
            const matches = policy_info.command == command or policy_info.command == .all;
            if (!matches) continue;

            if (policy_info.with_check_expr) |with_check_sql| {
                const owned_sql = arena.arena.allocator().dupe(u8, with_check_sql) catch continue;

                var infra_alloc = std.heap.ArenaAllocator.init(self.allocator);
                defer infra_alloc.deinit();

                var p = Parser.init(infra_alloc.allocator(), owned_sql, arena) catch continue;
                defer p.deinit();

                if (p.parseExpr(0) catch null) |expr| {
                    const row = Row{
                        .columns = col_names,
                        .values = vals,
                        .allocator = self.allocator,
                    };
                    const result = evalExpr(self.allocator, expr, &row, &self.catalog) catch continue;
                    defer result.free(self.allocator);
                    if (!result.isTruthy()) {
                        return EngineError.RlsPolicyViolation;
                    }
                }
            }
        }
    }

    /// Recursively translate a PlanNode tree into an executor RowIterator chain.
    fn buildIterator(self: *Database, node: *const PlanNode, ops: *OperatorChain) EngineError!RowIterator {
        return switch (node.*) {
            .scan => |s| self.buildScan(s, ops),
            .table_function_scan => |tfs| self.buildTableFunctionScan(tfs, ops),
            .values_table_scan => |vts| self.buildValuesTableScan(vts, ops),
            .filter => |f| self.buildFilter(f, ops),
            .project => |p| self.buildProject(p, ops),
            .limit => |l| self.buildLimit(l, ops),
            .sort => |s| self.buildSort(s, ops),
            .aggregate => |a| self.buildAggregate(a, ops),
            .join => |j| self.buildJoin(j, ops),
            .set_op => |s| self.buildSetOp(s, ops),
            .distinct => |d| self.buildDistinct(d, ops),
            .window => |w| self.buildWindow(w, ops),
            .values => |v| self.buildValues(v, ops),
            .empty => |e| self.buildEmpty(e, ops),
        };
    }

    fn buildScan(self: *Database, scan: PlanNode.Scan, ops: *OperatorChain) EngineError!RowIterator {
        // Check if this scan references a materialized CTE
        if (ops.cte_materialized) |cte_map| {
            if (cte_map.get(scan.table)) |cte_mat| {
                return self.buildCteScan(scan, ops, cte_mat);
            }
        }

        // Check for system tables
        if (std.mem.eql(u8, scan.table, "pg_stat_activity")) {
            return self.buildStatActivityScan(scan, ops);
        }
        if (std.mem.eql(u8, scan.table, "pg_locks")) {
            return self.buildLocksScan(scan, ops);
        }

        // Check if the name refers to a table
        if (self.catalog.getTable(scan.table)) |_table_info| {
            var table_info = _table_info;
            return self.buildTableScan(scan, ops, &table_info);
        } else |_| {
            // Table not found — check if it's a view
            const view_info = self.catalog.getView(scan.table) catch return EngineError.TableNotFound;
            defer view_info.deinit();
            return self.buildViewScan(scan, ops, view_info);
        }
    }

    fn buildTableFunctionScanWithContext(
        self: *Database,
        tfs: PlanNode.TableFunctionScan,
        context_row: executor_mod.Row,
        ops: *OperatorChain,
    ) EngineError!executor_mod.RowIterator {
        // Handle unnest() function with context
        if (std.mem.eql(u8, tfs.function_name, "unnest")) {
            if (tfs.args.len != 1) {
                return EngineError.ExecutionError;
            }

            // Evaluate the array argument using the context row
            const array_value = executor_mod.evalExpr(self.allocator, tfs.args[0], &context_row, null) catch
                return EngineError.ExecutionError;

            if (array_value != .array) {
                array_value.free(self.allocator);
                return EngineError.ExecutionError;
            }

            const unnest_ctx_n_cols: usize = if (tfs.with_ordinality) 2 else 1;
            const col_names = try self.allocator.alloc([]const u8, unnest_ctx_n_cols);
            col_names[0] = try self.allocator.dupe(u8, tfsColName(tfs, 0, "unnest"));
            if (tfs.with_ordinality) col_names[1] = try self.allocator.dupe(u8, tfsColName(tfs, 1, "ordinality"));

            var rows = std.ArrayListUnmanaged([]executor_mod.Value){};
            for (array_value.array, 1..) |elem, ord| {
                const vals = try self.allocator.alloc(executor_mod.Value, unnest_ctx_n_cols);
                vals[0] = try elem.dupe(self.allocator);
                if (tfs.with_ordinality) vals[1] = .{ .integer = @intCast(ord) };
                try rows.append(self.allocator, vals);
            }

            array_value.free(self.allocator);

            const mat_op = try self.allocator.create(MaterializedOp);
            mat_op.* = MaterializedOp.init(
                self.allocator,
                col_names,
                try rows.toOwnedSlice(self.allocator),
            );

            ops.materialized = mat_op;
            return mat_op.iterator();
        }

        // Handle generate_series() function with context
        if (std.mem.eql(u8, tfs.function_name, "generate_series")) {
            if (tfs.args.len < 2 or tfs.args.len > 3) {
                return EngineError.ExecutionError;
            }

            // Evaluate the arguments using the context row
            const start_val = executor_mod.evalExpr(self.allocator, tfs.args[0], &context_row, null) catch
                return EngineError.ExecutionError;
            defer start_val.free(self.allocator);

            const stop_val = executor_mod.evalExpr(self.allocator, tfs.args[1], &context_row, null) catch
                return EngineError.ExecutionError;
            defer stop_val.free(self.allocator);

            const step_val = if (tfs.args.len > 2)
                executor_mod.evalExpr(self.allocator, tfs.args[2], &context_row, null) catch return EngineError.ExecutionError
            else
                null;
            defer if (step_val) |sv| sv.free(self.allocator);

            const gs_ctx_n_cols: usize = if (tfs.with_ordinality) 2 else 1;
            const col_names = try self.allocator.alloc([]const u8, gs_ctx_n_cols);
            col_names[0] = try self.allocator.dupe(u8, tfsColName(tfs, 0, "generate_series"));
            if (tfs.with_ordinality) col_names[1] = try self.allocator.dupe(u8, tfsColName(tfs, 1, "ordinality"));

            var rows = std.ArrayListUnmanaged([]executor_mod.Value){};

            const is_float = start_val == .real or stop_val == .real or (step_val != null and step_val.? == .real);

            if (is_float) {
                const start = switch (start_val) {
                    .integer => |i| @as(f64, @floatFromInt(i)),
                    .real => |r| r,
                    else => return EngineError.ExecutionError,
                };

                const stop = switch (stop_val) {
                    .integer => |i| @as(f64, @floatFromInt(i)),
                    .real => |r| r,
                    else => return EngineError.ExecutionError,
                };

                const step = if (step_val) |sv|
                    switch (sv) {
                        .integer => |i| @as(f64, @floatFromInt(i)),
                        .real => |r| r,
                        else => return EngineError.ExecutionError,
                    }
                else
                    @as(f64, 1.0);

                if (step == 0.0 or (step > 0 and start > stop) or (step < 0 and start < stop)) {
                    // Empty result
                } else {
                    var v = start;
                    var ord: i64 = 1;
                    const max_rows = 10_000_000;
                    var count: usize = 0;
                    while ((step > 0 and v <= stop) or (step < 0 and v >= stop)) : (count += 1) {
                        if (count >= max_rows) break;
                        const vals = try self.allocator.alloc(executor_mod.Value, gs_ctx_n_cols);
                        vals[0] = .{ .real = v };
                        if (tfs.with_ordinality) { vals[1] = .{ .integer = ord }; ord += 1; }
                        try rows.append(self.allocator, vals);
                        v += step;
                    }
                }
            } else {
                const start = switch (start_val) {
                    .integer => |i| i,
                    else => return EngineError.ExecutionError,
                };

                const stop = switch (stop_val) {
                    .integer => |i| i,
                    else => return EngineError.ExecutionError,
                };

                const step = if (step_val) |sv|
                    switch (sv) {
                        .integer => |i| i,
                        else => return EngineError.ExecutionError,
                    }
                else
                    1;

                if (step == 0 or (step > 0 and start > stop) or (step < 0 and start < stop)) {
                    // Empty result
                } else {
                    var v = start;
                    var ord: i64 = 1;
                    const max_rows = 10_000_000;
                    var count: usize = 0;
                    while ((step > 0 and v <= stop) or (step < 0 and v >= stop)) : (count += 1) {
                        if (count >= max_rows) break;
                        const vals = try self.allocator.alloc(executor_mod.Value, gs_ctx_n_cols);
                        vals[0] = .{ .integer = v };
                        if (tfs.with_ordinality) { vals[1] = .{ .integer = ord }; ord += 1; }
                        try rows.append(self.allocator, vals);
                        if (step > 0) {
                            v +|= @as(i64, @intCast(step));
                        } else {
                            v -|= @as(i64, @intCast(-step));
                        }
                    }
                }
            }

            const mat_op = try self.allocator.create(MaterializedOp);
            mat_op.* = MaterializedOp.init(
                self.allocator,
                col_names,
                try rows.toOwnedSlice(self.allocator),
            );

            ops.materialized = mat_op;
            return mat_op.iterator();
        }

        // For other functions (json_each, json_array_elements, etc.), handle with context row
        // by using standard JSON parsing like buildTableFunctionScan does.
        // Handle json_each() and jsonb_each() — expand JSON object into (key, value) rows
        if (std.mem.eql(u8, tfs.function_name, "json_each") or
            std.mem.eql(u8, tfs.function_name, "jsonb_each") or
            std.mem.eql(u8, tfs.function_name, "json_each_text") or
            std.mem.eql(u8, tfs.function_name, "jsonb_each_text"))
        {
            const as_text = std.mem.endsWith(u8, tfs.function_name, "_text");

            if (tfs.args.len != 1) return EngineError.ExecutionError;

            // Evaluate with context row instead of empty row
            const json_val = executor_mod.evalExpr(self.allocator, tfs.args[0], &context_row, null) catch
                return EngineError.ExecutionError;
            defer json_val.free(self.allocator);

            // Build column names (2 or 3 if WITH ORDINALITY)
            const je_ctx_n_cols: usize = if (tfs.with_ordinality) 3 else 2;

            // NULL → empty result
            if (json_val == .null_value) {
                const col_names = try self.allocator.alloc([]const u8, je_ctx_n_cols);
                col_names[0] = try self.allocator.dupe(u8, tfsColName(tfs, 0, "key"));
                col_names[1] = try self.allocator.dupe(u8, tfsColName(tfs, 1, "value"));
                if (tfs.with_ordinality) col_names[2] = try self.allocator.dupe(u8, tfsColName(tfs, 2, "ordinality"));
                const mat_op = try self.allocator.create(MaterializedOp);
                mat_op.* = MaterializedOp.init(self.allocator, col_names, &.{});
                ops.materialized = mat_op;
                return mat_op.iterator();
            }

            const json_text = switch (json_val) {
                .text => |t| t,
                .blob => |b| b,
                else => return EngineError.ExecutionError,
            };

            const col_names = try self.allocator.alloc([]const u8, je_ctx_n_cols);
            col_names[0] = try self.allocator.dupe(u8, tfsColName(tfs, 0, "key"));
            col_names[1] = try self.allocator.dupe(u8, tfsColName(tfs, 1, "value"));
            if (tfs.with_ordinality) col_names[2] = try self.allocator.dupe(u8, tfsColName(tfs, 2, "ordinality"));

            var rows = std.ArrayListUnmanaged([]executor_mod.Value){};

            // Parse and iterate JSON object entries
            if (std.json.parseFromSlice(std.json.Value, self.allocator, json_text, .{})) |parsed| {
                defer parsed.deinit();

                switch (parsed.value) {
                    .object => |obj| {
                        var iter = obj.iterator();
                        var ord: i64 = 1;
                        while (iter.next()) |entry| {
                            const vals = try self.allocator.alloc(executor_mod.Value, je_ctx_n_cols);
                            vals[0] = .{ .text = try self.allocator.dupe(u8, entry.key_ptr.*) };
                            vals[1] = blk: {
                                const v = entry.value_ptr.*;
                                if (as_text) {
                                    // _text variant: return bare text, null for null
                                    switch (v) {
                                        .null => break :blk executor_mod.Value.null_value,
                                        .string => |s| break :blk executor_mod.Value{ .text = try self.allocator.dupe(u8, s) },
                                        .integer => |i| break :blk executor_mod.Value{ .text = try std.fmt.allocPrint(self.allocator, "{d}", .{i}) },
                                        .float => |f| break :blk executor_mod.Value{ .text = try std.fmt.allocPrint(self.allocator, "{d}", .{f}) },
                                        .bool => |b| break :blk executor_mod.Value{ .text = try std.fmt.allocPrint(self.allocator, "{s}", .{if (b) "true" else "false"}) },
                                        else => {
                                            var buf = std.ArrayListUnmanaged(u8){};
                                            defer buf.deinit(self.allocator);
                                            try std.fmt.format(buf.writer(self.allocator), "{f}", .{std.json.fmt(v, .{})});
                                            break :blk executor_mod.Value{ .text = try self.allocator.dupe(u8, buf.items) };
                                        },
                                    }
                                } else {
                                    // json_each: serialize value back to JSON text
                                    var buf = std.ArrayListUnmanaged(u8){};
                                    defer buf.deinit(self.allocator);
                                    try std.fmt.format(buf.writer(self.allocator), "{f}", .{std.json.fmt(v, .{})});
                                    break :blk executor_mod.Value{ .text = try self.allocator.dupe(u8, buf.items) };
                                }
                            };
                            if (tfs.with_ordinality) { vals[2] = .{ .integer = ord }; ord += 1; }
                            try rows.append(self.allocator, vals);
                        }
                    },
                    else => {}, // Not an object → empty result
                }
            } else |_| {
                // Parse error → empty result
            }

            const mat_op = try self.allocator.create(MaterializedOp);
            mat_op.* = MaterializedOp.init(
                self.allocator,
                col_names,
                try rows.toOwnedSlice(self.allocator),
            );

            ops.materialized = mat_op;
            return mat_op.iterator();
        }

        // Handle json_array_elements() function with context
        if (std.mem.eql(u8, tfs.function_name, "json_array_elements") or
            std.mem.eql(u8, tfs.function_name, "jsonb_array_elements") or
            std.mem.eql(u8, tfs.function_name, "json_array_elements_text") or
            std.mem.eql(u8, tfs.function_name, "jsonb_array_elements_text"))
        {
            const as_text = std.mem.endsWith(u8, tfs.function_name, "_text");

            if (tfs.args.len != 1) return EngineError.ExecutionError;

            // Evaluate with context row
            const json_val = executor_mod.evalExpr(self.allocator, tfs.args[0], &context_row, null) catch
                return EngineError.ExecutionError;
            defer json_val.free(self.allocator);

            // Build column names (1 or 2 if WITH ORDINALITY)
            const jae_ctx_n_cols: usize = if (tfs.with_ordinality) 2 else 1;

            // NULL → empty result
            if (json_val == .null_value) {
                const col_names = try self.allocator.alloc([]const u8, jae_ctx_n_cols);
                col_names[0] = try self.allocator.dupe(u8, tfsColName(tfs, 0, "value"));
                if (tfs.with_ordinality) col_names[1] = try self.allocator.dupe(u8, tfsColName(tfs, 1, "ordinality"));
                const mat_op = try self.allocator.create(MaterializedOp);
                mat_op.* = MaterializedOp.init(self.allocator, col_names, &.{});
                ops.materialized = mat_op;
                return mat_op.iterator();
            }

            const json_text = switch (json_val) {
                .text => |t| t,
                .blob => |b| b,
                else => return EngineError.ExecutionError,
            };

            const col_names = try self.allocator.alloc([]const u8, jae_ctx_n_cols);
            col_names[0] = try self.allocator.dupe(u8, tfsColName(tfs, 0, "value"));
            if (tfs.with_ordinality) col_names[1] = try self.allocator.dupe(u8, tfsColName(tfs, 1, "ordinality"));

            var rows = std.ArrayListUnmanaged([]executor_mod.Value){};

            // Parse and iterate JSON array elements
            if (std.json.parseFromSlice(std.json.Value, self.allocator, json_text, .{})) |parsed| {
                defer parsed.deinit();

                switch (parsed.value) {
                    .array => |arr| {
                        var ord: i64 = 1;
                        for (arr.items) |elem| {
                            const vals = try self.allocator.alloc(executor_mod.Value, jae_ctx_n_cols);
                            vals[0] = blk: {
                                if (as_text) {
                                    switch (elem) {
                                        .null => break :blk executor_mod.Value.null_value,
                                        .string => |s| break :blk executor_mod.Value{ .text = try self.allocator.dupe(u8, s) },
                                        .integer => |i| break :blk executor_mod.Value{ .text = try std.fmt.allocPrint(self.allocator, "{d}", .{i}) },
                                        .float => |f| break :blk executor_mod.Value{ .text = try std.fmt.allocPrint(self.allocator, "{d}", .{f}) },
                                        .bool => |b| break :blk executor_mod.Value{ .text = try std.fmt.allocPrint(self.allocator, "{s}", .{if (b) "true" else "false"}) },
                                        else => {
                                            var buf = std.ArrayListUnmanaged(u8){};
                                            defer buf.deinit(self.allocator);
                                            try std.fmt.format(buf.writer(self.allocator), "{f}", .{std.json.fmt(elem, .{})});
                                            break :blk executor_mod.Value{ .text = try self.allocator.dupe(u8, buf.items) };
                                        },
                                    }
                                } else {
                                    var buf = std.ArrayListUnmanaged(u8){};
                                    defer buf.deinit(self.allocator);
                                    try std.fmt.format(buf.writer(self.allocator), "{f}", .{std.json.fmt(elem, .{})});
                                    break :blk executor_mod.Value{ .text = try self.allocator.dupe(u8, buf.items) };
                                }
                            };
                            if (tfs.with_ordinality) { vals[1] = .{ .integer = ord }; ord += 1; }
                            try rows.append(self.allocator, vals);
                        }
                    },
                    else => {}, // Not an array → empty result
                }
            } else |_| {
                // Parse error → empty result
            }

            const mat_op = try self.allocator.create(MaterializedOp);
            mat_op.* = MaterializedOp.init(
                self.allocator,
                col_names,
                try rows.toOwnedSlice(self.allocator),
            );

            ops.materialized = mat_op;
            return mat_op.iterator();
        }

        return EngineError.ExecutionError;
    }

    fn buildTableFunctionScan(self: *Database, tfs: PlanNode.TableFunctionScan, ops: *OperatorChain) EngineError!RowIterator {
        // Handle unnest() function
        if (std.mem.eql(u8, tfs.function_name, "unnest")) {
            // unnest() requires exactly 1 argument (the array)
            if (tfs.args.len != 1) {
                return EngineError.ExecutionError;
            }

            // Create an empty row context for evaluating the array expression
            // (since unnest is in FROM clause, there's no input row to reference)
            var empty_row = Row{
                .columns = &.{},
                .values = &.{},
                .allocator = self.allocator,
            };

            // Evaluate the array argument
            const array_value = executor_mod.evalExpr(self.allocator, tfs.args[0], &empty_row, null) catch
                return EngineError.ExecutionError;

            // Ensure it's actually an array
            if (array_value != .array) {
                array_value.free(self.allocator);
                return EngineError.ExecutionError; // Type mismatch
            }

            // Build column names (1 or 2 if WITH ORDINALITY)
            const unnest_n_cols: usize = if (tfs.with_ordinality) 2 else 1;
            const col_names = try self.allocator.alloc([]const u8, unnest_n_cols);
            col_names[0] = try self.allocator.dupe(u8, tfsColName(tfs, 0, "unnest"));
            if (tfs.with_ordinality) {
                col_names[1] = try self.allocator.dupe(u8, tfsColName(tfs, 1, "ordinality"));
            }

            // Convert array elements into rows (with 1-based ordinality if requested)
            var rows = std.ArrayListUnmanaged([]Value){};
            for (array_value.array, 1..) |elem, ord| {
                const vals = try self.allocator.alloc(Value, unnest_n_cols);
                vals[0] = try elem.dupe(self.allocator);
                if (tfs.with_ordinality) vals[1] = .{ .integer = @intCast(ord) };
                try rows.append(self.allocator, vals);
            }

            // Clean up the array value (we've already duped the elements)
            array_value.free(self.allocator);

            // Create MaterializedOp to hold the rows
            const mat_op = try self.allocator.create(MaterializedOp);
            mat_op.* = MaterializedOp.init(
                self.allocator,
                col_names,
                try rows.toOwnedSlice(self.allocator),
            );

            ops.materialized = mat_op;
            return mat_op.iterator();
        }

        // Handle generate_series() function
        if (std.mem.eql(u8, tfs.function_name, "generate_series")) {
            // generate_series requires 2 or 3 arguments (start, stop, [step])
            if (tfs.args.len < 2 or tfs.args.len > 3) {
                return EngineError.ExecutionError;
            }

            // Create an empty row context for evaluating arguments
            var empty_row = Row{
                .columns = &.{},
                .values = &.{},
                .allocator = self.allocator,
            };

            // Evaluate the arguments
            const start_val = executor_mod.evalExpr(self.allocator, tfs.args[0], &empty_row, null) catch
                return EngineError.ExecutionError;
            defer start_val.free(self.allocator);

            const stop_val = executor_mod.evalExpr(self.allocator, tfs.args[1], &empty_row, null) catch
                return EngineError.ExecutionError;
            defer stop_val.free(self.allocator);

            const step_val = if (tfs.args.len > 2)
                executor_mod.evalExpr(self.allocator, tfs.args[2], &empty_row, null) catch return EngineError.ExecutionError
            else
                null;
            defer if (step_val) |sv| sv.free(self.allocator);

            // Build column names (1 or 2 if WITH ORDINALITY)
            const gs_n_cols: usize = if (tfs.with_ordinality) 2 else 1;
            const col_names = try self.allocator.alloc([]const u8, gs_n_cols);
            col_names[0] = try self.allocator.dupe(u8, tfsColName(tfs, 0, "generate_series"));
            if (tfs.with_ordinality) {
                col_names[1] = try self.allocator.dupe(u8, tfsColName(tfs, 1, "ordinality"));
            }

            var rows = std.ArrayListUnmanaged([]Value){};

            // Check if we're dealing with floats or integers
            const is_float = start_val == .real or stop_val == .real or (step_val != null and step_val.? == .real);

            if (is_float) {
                // Float path
                const start = switch (start_val) {
                    .integer => |i| @as(f64, @floatFromInt(i)),
                    .real => |r| r,
                    else => return EngineError.ExecutionError,
                };

                const stop = switch (stop_val) {
                    .integer => |i| @as(f64, @floatFromInt(i)),
                    .real => |r| r,
                    else => return EngineError.ExecutionError,
                };

                const step = if (step_val) |sv|
                    switch (sv) {
                        .integer => |i| @as(f64, @floatFromInt(i)),
                        .real => |r| r,
                        else => return EngineError.ExecutionError,
                    }
                else
                    @as(f64, 1.0); // Default step is always 1

                if (step == 0.0 or (step > 0 and start > stop) or (step < 0 and start < stop)) {
                    // Empty result
                } else {
                    var v = start;
                    var ord: i64 = 1;
                    const max_rows = 10_000_000;
                    var count: usize = 0;
                    while ((step > 0 and v <= stop) or (step < 0 and v >= stop)) : (count += 1) {
                        if (count >= max_rows) break;
                        const vals = try self.allocator.alloc(Value, gs_n_cols);
                        vals[0] = .{ .real = v };
                        if (tfs.with_ordinality) { vals[1] = .{ .integer = ord }; ord += 1; }
                        try rows.append(self.allocator, vals);
                        v += step;
                    }
                }
            } else {
                // Integer path
                const start = switch (start_val) {
                    .integer => |i| i,
                    else => return EngineError.ExecutionError,
                };

                const stop = switch (stop_val) {
                    .integer => |i| i,
                    else => return EngineError.ExecutionError,
                };

                const step = if (step_val) |sv|
                    switch (sv) {
                        .integer => |i| i,
                        else => return EngineError.ExecutionError,
                    }
                else
                    @as(i64, 1); // Default step is always 1

                if (step == 0 or (step > 0 and start > stop) or (step < 0 and start < stop)) {
                    // Empty result
                } else {
                    var v = start;
                    var ord: i64 = 1;
                    const max_rows = 10_000_000;
                    var count: usize = 0;
                    while ((step > 0 and v <= stop) or (step < 0 and v >= stop)) : (count += 1) {
                        if (count >= max_rows) break;
                        const vals = try self.allocator.alloc(Value, gs_n_cols);
                        vals[0] = .{ .integer = v };
                        if (tfs.with_ordinality) { vals[1] = .{ .integer = ord }; ord += 1; }
                        try rows.append(self.allocator, vals);
                        v += step;
                    }
                }
            }

            // Create MaterializedOp to hold the rows
            const mat_op = try self.allocator.create(MaterializedOp);
            mat_op.* = MaterializedOp.init(
                self.allocator,
                col_names,
                try rows.toOwnedSlice(self.allocator),
            );

            ops.materialized = mat_op;
            return mat_op.iterator();
        }

        // Handle json_each() and jsonb_each() — expand JSON object into (key, value) rows
        if (std.mem.eql(u8, tfs.function_name, "json_each") or
            std.mem.eql(u8, tfs.function_name, "jsonb_each") or
            std.mem.eql(u8, tfs.function_name, "json_each_text") or
            std.mem.eql(u8, tfs.function_name, "jsonb_each_text"))
        {
            const as_text = std.mem.endsWith(u8, tfs.function_name, "_text");

            if (tfs.args.len != 1) return EngineError.ExecutionError;

            var empty_row = Row{ .columns = &.{}, .values = &.{}, .allocator = self.allocator };
            const json_val = executor_mod.evalExpr(self.allocator, tfs.args[0], &empty_row, null) catch
                return EngineError.ExecutionError;
            defer json_val.free(self.allocator);

            // Build column names (2 or 3 if WITH ORDINALITY)
            const je_n_cols: usize = if (tfs.with_ordinality) 3 else 2;

            // NULL → empty result
            if (json_val == .null_value) {
                const col_names = try self.allocator.alloc([]const u8, je_n_cols);
                col_names[0] = try self.allocator.dupe(u8, tfsColName(tfs, 0, "key"));
                col_names[1] = try self.allocator.dupe(u8, tfsColName(tfs, 1, "value"));
                if (tfs.with_ordinality) col_names[2] = try self.allocator.dupe(u8, tfsColName(tfs, 2, "ordinality"));
                const mat_op = try self.allocator.create(MaterializedOp);
                mat_op.* = MaterializedOp.init(self.allocator, col_names, &.{});
                ops.materialized = mat_op;
                return mat_op.iterator();
            }

            const json_text = switch (json_val) {
                .text => |t| t,
                .blob => |b| b,
                else => return EngineError.ExecutionError,
            };

            const col_names = try self.allocator.alloc([]const u8, je_n_cols);
            col_names[0] = try self.allocator.dupe(u8, tfsColName(tfs, 0, "key"));
            col_names[1] = try self.allocator.dupe(u8, tfsColName(tfs, 1, "value"));
            if (tfs.with_ordinality) col_names[2] = try self.allocator.dupe(u8, tfsColName(tfs, 2, "ordinality"));

            var rows = std.ArrayListUnmanaged([]Value){};

            // Parse and iterate JSON object entries
            if (std.json.parseFromSlice(std.json.Value, self.allocator, json_text, .{})) |parsed| {
                defer parsed.deinit();

                switch (parsed.value) {
                    .object => |obj| {
                        var iter = obj.iterator();
                        var ord: i64 = 1;
                        while (iter.next()) |entry| {
                            const vals = try self.allocator.alloc(Value, je_n_cols);
                            vals[0] = .{ .text = try self.allocator.dupe(u8, entry.key_ptr.*) };
                            vals[1] = blk: {
                                const v = entry.value_ptr.*;
                                if (as_text) {
                                    // _text variant: return bare text, null for null
                                    switch (v) {
                                        .null => break :blk Value.null_value,
                                        .string => |s| break :blk Value{ .text = try self.allocator.dupe(u8, s) },
                                        .integer => |i| break :blk Value{ .text = try std.fmt.allocPrint(self.allocator, "{d}", .{i}) },
                                        .float => |f| break :blk Value{ .text = try std.fmt.allocPrint(self.allocator, "{d}", .{f}) },
                                        .bool => |b| break :blk Value{ .text = try std.fmt.allocPrint(self.allocator, "{s}", .{if (b) "true" else "false"}) },
                                        else => {
                                            var buf = std.ArrayListUnmanaged(u8){};
                                            defer buf.deinit(self.allocator);
                                            try std.fmt.format(buf.writer(self.allocator), "{f}", .{std.json.fmt(v, .{})});
                                            break :blk Value{ .text = try self.allocator.dupe(u8, buf.items) };
                                        },
                                    }
                                } else {
                                    // json_each: serialize value back to JSON text
                                    var buf = std.ArrayListUnmanaged(u8){};
                                    defer buf.deinit(self.allocator);
                                    try std.fmt.format(buf.writer(self.allocator), "{f}", .{std.json.fmt(v, .{})});
                                    break :blk Value{ .text = try self.allocator.dupe(u8, buf.items) };
                                }
                            };
                            if (tfs.with_ordinality) { vals[2] = .{ .integer = ord }; ord += 1; }
                            try rows.append(self.allocator, vals);
                        }
                    },
                    else => {}, // Not an object → empty result
                }
            } else |_| {
                // Parse error → empty result
            }

            const mat_op = try self.allocator.create(MaterializedOp);
            mat_op.* = MaterializedOp.init(
                self.allocator,
                col_names,
                try rows.toOwnedSlice(self.allocator),
            );
            ops.materialized = mat_op;
            return mat_op.iterator();
        }

        // Handle json_array_elements() and jsonb_array_elements() — expand JSON array into value rows
        if (std.mem.eql(u8, tfs.function_name, "json_array_elements") or
            std.mem.eql(u8, tfs.function_name, "jsonb_array_elements") or
            std.mem.eql(u8, tfs.function_name, "json_array_elements_text") or
            std.mem.eql(u8, tfs.function_name, "jsonb_array_elements_text"))
        {
            const as_text = std.mem.endsWith(u8, tfs.function_name, "_text");

            if (tfs.args.len != 1) return EngineError.ExecutionError;

            var empty_row = Row{ .columns = &.{}, .values = &.{}, .allocator = self.allocator };
            const json_val = executor_mod.evalExpr(self.allocator, tfs.args[0], &empty_row, null) catch
                return EngineError.ExecutionError;
            defer json_val.free(self.allocator);

            // Build column names (1 or 2 if WITH ORDINALITY)
            const jae_n_cols: usize = if (tfs.with_ordinality) 2 else 1;
            const col_names = try self.allocator.alloc([]const u8, jae_n_cols);
            col_names[0] = try self.allocator.dupe(u8, tfsColName(tfs, 0, "value"));
            if (tfs.with_ordinality) col_names[1] = try self.allocator.dupe(u8, tfsColName(tfs, 1, "ordinality"));

            var rows = std.ArrayListUnmanaged([]Value){};

            // NULL → empty result
            if (json_val != .null_value) {
                const json_text = switch (json_val) {
                    .text => |t| t,
                    .blob => |b| b,
                    else => {
                        for (col_names) |cn| self.allocator.free(cn);
                        self.allocator.free(col_names);
                        return EngineError.ExecutionError;
                    },
                };

                if (std.json.parseFromSlice(std.json.Value, self.allocator, json_text, .{})) |parsed| {
                    defer parsed.deinit();

                    switch (parsed.value) {
                        .array => |arr| {
                            var ord: i64 = 1;
                            for (arr.items) |item| {
                                const vals = try self.allocator.alloc(Value, jae_n_cols);
                                vals[0] = blk: {
                                    if (as_text) {
                                        switch (item) {
                                            .null => break :blk Value.null_value,
                                            .string => |s| break :blk Value{ .text = try self.allocator.dupe(u8, s) },
                                            .integer => |i| break :blk Value{ .text = try std.fmt.allocPrint(self.allocator, "{d}", .{i}) },
                                            .float => |f| break :blk Value{ .text = try std.fmt.allocPrint(self.allocator, "{d}", .{f}) },
                                            .bool => |b| break :blk Value{ .text = try std.fmt.allocPrint(self.allocator, "{s}", .{if (b) "true" else "false"}) },
                                            else => {
                                                var buf = std.ArrayListUnmanaged(u8){};
                                                defer buf.deinit(self.allocator);
                                                try std.fmt.format(buf.writer(self.allocator), "{f}", .{std.json.fmt(item, .{})});
                                                break :blk Value{ .text = try self.allocator.dupe(u8, buf.items) };
                                            },
                                        }
                                    } else {
                                        var buf = std.ArrayListUnmanaged(u8){};
                                        defer buf.deinit(self.allocator);
                                        try std.fmt.format(buf.writer(self.allocator), "{f}", .{std.json.fmt(item, .{})});
                                        break :blk Value{ .text = try self.allocator.dupe(u8, buf.items) };
                                    }
                                };
                                if (tfs.with_ordinality) { vals[1] = .{ .integer = ord }; ord += 1; }
                                try rows.append(self.allocator, vals);
                            }
                        },
                        else => {}, // Not an array → empty result
                    }
                } else |_| {
                    // Parse error → empty result
                }
            }

            const mat_op = try self.allocator.create(MaterializedOp);
            mat_op.* = MaterializedOp.init(
                self.allocator,
                col_names,
                try rows.toOwnedSlice(self.allocator),
            );
            ops.materialized = mat_op;
            return mat_op.iterator();
        }

        // Unknown table function
        return EngineError.ExecutionError;
    }

    fn buildValuesTableScan(self: *Database, vts: PlanNode.ValuesTableScan, ops: *OperatorChain) EngineError!RowIterator {
        const alloc = self.allocator;

        // Determine number of columns
        const n_cols = if (vts.rows.len > 0) vts.rows[0].len else 0;

        // Build column names from vts.column_names or generate defaults
        const col_names = try alloc.alloc([]const u8, n_cols);
        for (0..n_cols) |i| {
            if (i < vts.column_names.len) {
                col_names[i] = try alloc.dupe(u8, vts.column_names[i]);
            } else {
                col_names[i] = try std.fmt.allocPrint(alloc, "column{d}", .{i + 1});
            }
        }

        // Materialize all rows by evaluating their expressions
        var materialized = std.ArrayListUnmanaged([]Value){};

        // Create empty row context (VALUES table has no input rows to reference)
        var empty_row = Row{
            .columns = &.{},
            .values = &.{},
            .allocator = alloc,
        };

        for (vts.rows) |row_exprs| {
            const vals = try alloc.alloc(Value, row_exprs.len);
            for (row_exprs, 0..) |expr, i| {
                vals[i] = executor_mod.evalExpr(alloc, expr, &empty_row, null) catch {
                    // On error, free allocated values and return error
                    for (vals[0..i]) |v| v.free(alloc);
                    alloc.free(vals);
                    return EngineError.ExecutionError;
                };
            }
            try materialized.append(alloc, vals);
        }

        // Create MaterializedOp to hold the rows
        const mat_op = try alloc.create(MaterializedOp);
        mat_op.* = MaterializedOp.init(
            alloc,
            col_names,
            try materialized.toOwnedSlice(alloc),
        );

        ops.materialized = mat_op;
        return mat_op.iterator();
    }

    fn buildViewScan(self: *Database, scan: PlanNode.Scan, ops: *OperatorChain, view_info: catalog_mod.Catalog.ViewInfo) EngineError!RowIterator {
        // Phase 1: Parse and execute the view's SQL (uses temporary arenas)
        var rows = std.ArrayListUnmanaged([]Value){};
        var first_row_cols: ?[]const []const u8 = null;

        {
            // Temporary arenas for parsing/planning — freed after materialization
            var view_arena = AstArena.init(self.allocator);
            defer view_arena.deinit();

            var infra_alloc = std.heap.ArenaAllocator.init(self.allocator);
            defer infra_alloc.deinit();

            var p = Parser.init(infra_alloc.allocator(), view_info.sql, &view_arena) catch return EngineError.ParseError;
            defer p.deinit();

            const stmt = (p.parseStatement() catch return EngineError.ParseError) orelse return EngineError.ParseError;

            const view_select = switch (stmt) {
                .create_view => |cv| cv.select,
                .select => |s| s,
                else => return EngineError.ExecutionError,
            };

            const provider = self.schemaProvider();
            var plnr = Planner.init(&view_arena, provider);
            const view_plan = plnr.plan(.{ .select = view_select }) catch return EngineError.PlanError;

            var opt = Optimizer.init(&view_arena);
            const optimized = opt.optimize(view_plan) catch return EngineError.PlanError;

            const view_ops = self.allocator.create(OperatorChain) catch return EngineError.OutOfMemory;
            view_ops.* = .{};

            var view_iter = self.buildIterator(optimized.root, view_ops) catch return EngineError.ExecutionError;

            // Materialize all rows
            while (view_iter.next() catch null) |row_data| {
                var row = row_data;
                if (first_row_cols == null) {
                    // Save column names from the first row (duped to survive arena cleanup)
                    const saved = self.allocator.alloc([]const u8, row.columns.len) catch return EngineError.OutOfMemory;
                    for (row.columns, 0..) |c, i| {
                        saved[i] = self.allocator.dupe(u8, c) catch return EngineError.OutOfMemory;
                    }
                    first_row_cols = saved;
                }
                const vals = self.allocator.alloc(Value, row.values.len) catch return EngineError.OutOfMemory;
                for (row.values, 0..) |v, i| {
                    vals[i] = v.dupe(self.allocator) catch return EngineError.OutOfMemory;
                }
                row.deinit();
                rows.append(self.allocator, vals) catch return EngineError.OutOfMemory;
            }
            view_iter.close();
            view_ops.deinit(self.allocator);
        }
        // view_arena and infra_alloc are now freed via defer

        // Phase 2: Build column names
        const col_names_result = if (first_row_cols) |inner_cols| blk: {
            defer {
                for (inner_cols) |c| self.allocator.free(@constCast(c));
                self.allocator.free(inner_cols);
            }
            break :blk self.buildViewColNames(inner_cols, scan.alias, view_info.column_names) catch return EngineError.OutOfMemory;
        } else self.buildViewColNamesFromScan(scan, view_info.column_names) catch return EngineError.OutOfMemory;

        // Phase 3: Create MaterializedOp
        const mat_op = self.allocator.create(MaterializedOp) catch return EngineError.OutOfMemory;
        mat_op.* = MaterializedOp.init(
            self.allocator,
            col_names_result,
            rows.toOwnedSlice(self.allocator) catch return EngineError.OutOfMemory,
        );

        ops.materialized = mat_op;
        return mat_op.iterator();
    }

    /// Build a scan for pg_stat_activity system table
    fn buildStatActivityScan(self: *Database, scan: PlanNode.Scan, ops: *OperatorChain) EngineError!RowIterator {
        _ = scan; // scan.alias not used for now — column names are always pg_stat_activity.*

        // Create StatActivityScanOp
        const stat_op = self.allocator.create(executor_mod.StatActivityScanOp) catch return EngineError.OutOfMemory;
        stat_op.* = executor_mod.StatActivityScanOp.init(self.allocator);

        // Set the tracker from OperatorChain (will be null in embedded mode, populated in server mode)
        if (ops.activity_tracker) |tracker| {
            stat_op.setTracker(tracker);
        }

        // Store operator in chain for cleanup
        ops.stat_activity_scan = stat_op;

        return stat_op.iterator();
    }

    /// Build a scan for pg_locks system table
    fn buildLocksScan(self: *Database, scan: PlanNode.Scan, ops: *OperatorChain) EngineError!RowIterator {
        _ = scan; // scan.alias not used for now — column names are always pg_locks.*

        // Create LocksScanOp
        const locks_op = self.allocator.create(executor_mod.LocksScanOp) catch return EngineError.OutOfMemory;
        locks_op.* = executor_mod.LocksScanOp.init(self.allocator);

        // Set the lock manager (always available in Database)
        locks_op.setLockManager(&self.lock_manager);

        // Store operator in chain for cleanup
        ops.locks_scan = locks_op;

        return locks_op.iterator();
    }

    /// Build column names for a view from the inner query's row columns.
    /// Applies view column aliases and scan alias prefix.
    fn buildViewColNames(self: *Database, row_cols: []const []const u8, scan_alias: ?[]const u8, view_col_names: []const []const u8) ![]const []const u8 {
        const num_cols = row_cols.len;
        const cols = try self.allocator.alloc([]const u8, num_cols);
        errdefer self.allocator.free(cols);

        for (0..num_cols) |i| {
            // Use view column alias if available, else strip any table prefix from inner column name
            const base_name = if (i < view_col_names.len)
                view_col_names[i]
            else blk: {
                // Strip "table." prefix from inner query column names
                const inner = row_cols[i];
                if (std.mem.indexOfScalar(u8, inner, '.')) |dot| {
                    break :blk inner[dot + 1 ..];
                }
                break :blk inner;
            };

            if (scan_alias) |alias| {
                cols[i] = try std.fmt.allocPrint(self.allocator, "{s}.{s}", .{ alias, base_name });
            } else {
                cols[i] = try self.allocator.dupe(u8, base_name);
            }
        }
        return cols;
    }

    /// Build column names for an empty view result from the scan's column refs.
    fn buildViewColNamesFromScan(self: *Database, scan: PlanNode.Scan, view_col_names: []const []const u8) ![]const []const u8 {
        const num_cols = scan.columns.len;
        const cols = try self.allocator.alloc([]const u8, num_cols);
        errdefer self.allocator.free(cols);

        for (scan.columns, 0..) |col_ref, i| {
            const base_name = if (i < view_col_names.len)
                view_col_names[i]
            else
                col_ref.column;

            if (scan.alias) |alias| {
                cols[i] = try std.fmt.allocPrint(self.allocator, "{s}.{s}", .{ alias, base_name });
            } else {
                cols[i] = try self.allocator.dupe(u8, base_name);
            }
        }
        return cols;
    }

    // ── CTE execution ──────────────────────────────────────────────────

    /// Materialize all CTEs in definition order and store in ops.cte_materialized.
    fn materializeCtes(self: *Database, ctes: []const planner_mod.CtePlan, ops: *OperatorChain) EngineError!void {
        var cte_map = std.StringHashMapUnmanaged(*MaterializedOp){};

        for (ctes) |cte| {
            if (cte.recursive) {
                try self.materializeRecursiveCte(cte, &cte_map, ops);
                continue;
            }

            // Create a sub-operator chain for this CTE's query
            const cte_ops = self.allocator.create(OperatorChain) catch return EngineError.OutOfMemory;
            cte_ops.* = .{};
            // Propagate parent CTE map so later CTEs can reference earlier ones
            cte_ops.cte_materialized = cte_map;

            ops.cte_ops.append(self.allocator, cte_ops) catch return EngineError.OutOfMemory;

            var cte_iter = self.buildIterator(cte.plan, cte_ops) catch return EngineError.ExecutionError;

            // Materialize all rows from the CTE query
            var rows = std.ArrayListUnmanaged([]Value){};
            var first_row_cols: ?[]const []const u8 = null;

            while (cte_iter.next() catch return EngineError.ExecutionError) |row_data| {
                var row = row_data;
                if (first_row_cols == null) {
                    const saved = self.allocator.alloc([]const u8, row.columns.len) catch return EngineError.OutOfMemory;
                    for (row.columns, 0..) |c, i| {
                        saved[i] = self.allocator.dupe(u8, c) catch return EngineError.OutOfMemory;
                    }
                    first_row_cols = saved;
                }
                const vals = self.allocator.alloc(Value, row.values.len) catch return EngineError.OutOfMemory;
                for (row.values, 0..) |v, i| {
                    vals[i] = v.dupe(self.allocator) catch return EngineError.OutOfMemory;
                }
                row.deinit();
                rows.append(self.allocator, vals) catch return EngineError.OutOfMemory;
            }
            cte_iter.close();

            // Build column names: use explicit CTE column aliases or inner query column names
            const col_names = if (cte.column_names.len > 0) blk: {
                // Free inner column names if we're overriding with explicit aliases
                if (first_row_cols) |inner| {
                    for (inner) |c| self.allocator.free(@constCast(c));
                    self.allocator.free(inner);
                }
                const names = self.allocator.alloc([]const u8, cte.column_names.len) catch return EngineError.OutOfMemory;
                for (cte.column_names, 0..) |name, i| {
                    names[i] = self.allocator.dupe(u8, name) catch return EngineError.OutOfMemory;
                }
                break :blk names;
            } else if (first_row_cols) |inner_cols| blk: {
                // Strip table prefixes from inner column names
                const names = self.allocator.alloc([]const u8, inner_cols.len) catch return EngineError.OutOfMemory;
                for (inner_cols, 0..) |c, i| {
                    const base = if (std.mem.indexOfScalar(u8, c, '.')) |dot| c[dot + 1 ..] else c;
                    names[i] = self.allocator.dupe(u8, base) catch return EngineError.OutOfMemory;
                    self.allocator.free(@constCast(c));
                }
                self.allocator.free(inner_cols);
                break :blk names;
            } else blk: {
                // Empty result set
                const names = self.allocator.alloc([]const u8, 0) catch return EngineError.OutOfMemory;
                break :blk names;
            };

            // Create MaterializedOp
            const mat_op = self.allocator.create(MaterializedOp) catch return EngineError.OutOfMemory;
            mat_op.* = MaterializedOp.init(
                self.allocator,
                col_names,
                rows.toOwnedSlice(self.allocator) catch return EngineError.OutOfMemory,
            );

            cte_map.put(self.allocator, cte.name, mat_op) catch return EngineError.OutOfMemory;
        }

        ops.cte_materialized = cte_map;
    }

    /// Maximum recursion depth to prevent infinite loops.
    const max_recursive_cte_depth = 1000;

    /// Materialize a recursive CTE using iterative fixed-point evaluation.
    /// The CTE's plan must be a set_op (UNION ALL) node with left=anchor, right=recursive.
    fn materializeRecursiveCte(
        self: *Database,
        cte: planner_mod.CtePlan,
        cte_map: *std.StringHashMapUnmanaged(*MaterializedOp),
        ops: *OperatorChain,
    ) EngineError!void {
        // The plan root must be a set_op (UNION ALL) — anchor UNION ALL recursive
        const set_op = switch (cte.plan.*) {
            .set_op => |s| s,
            else => return EngineError.ExecutionError,
        };
        if (set_op.op != .union_all) return EngineError.ExecutionError;

        const anchor_plan = set_op.left;
        const recursive_plan = set_op.right;

        // CYCLE clause setup: evaluate TO/DEFAULT literal values
        const has_cycle = cte.cycle != null;
        var cycle_to_val: Value = .null_value;
        var cycle_default_val: Value = .null_value;
        defer {
            if (has_cycle) {
                cycle_to_val.free(self.allocator);
                cycle_default_val.free(self.allocator);
            }
        }
        if (cte.cycle) |cy| {
            const empty_row = Row{ .columns = &.{}, .values = &.{}, .allocator = self.allocator };
            cycle_to_val = evalExpr(self.allocator, cy.cycle_value, &empty_row, null) catch .{ .integer = 1 };
            cycle_default_val = evalExpr(self.allocator, cy.no_cycle_value, &empty_row, null) catch .{ .integer = 0 };
        }

        // Cycle tracking: set of cycle keys seen so far (globally across all iterations)
        var cycle_seen = std.StringHashMapUnmanaged(void){};
        defer {
            var it = cycle_seen.keyIterator();
            while (it.next()) |key| self.allocator.free(key.*);
            cycle_seen.deinit(self.allocator);
        }

        // Step 1: Execute the anchor query
        const anchor_ops = self.allocator.create(OperatorChain) catch return EngineError.OutOfMemory;
        anchor_ops.* = .{};
        anchor_ops.cte_materialized = cte_map.*;
        ops.cte_ops.append(self.allocator, anchor_ops) catch return EngineError.OutOfMemory;

        var anchor_iter = self.buildIterator(anchor_plan, anchor_ops) catch return EngineError.ExecutionError;

        // Collect anchor rows and determine column names (without cycle col)
        // all_rows: rows with cycle col appended (if CYCLE clause present)
        // working_rows: rows without cycle col (feed to recursive step)
        var all_rows = std.ArrayListUnmanaged([]Value){};
        var col_names: ?[]const []const u8 = null;

        // Cycle column indices in base cols (determined after first anchor row)
        var cycle_col_indices_opt: ?[]usize = null;
        defer if (cycle_col_indices_opt) |buf| self.allocator.free(buf);

        while (anchor_iter.next() catch return EngineError.ExecutionError) |row_data| {
            var row = row_data;
            if (col_names == null) {
                col_names = try self.captureColNames(&row, cte.column_names);
                // Find cycle column indices in base col_names
                if (cte.cycle) |cy| {
                    const indices = self.allocator.alloc(usize, cy.columns.len) catch return EngineError.OutOfMemory;
                    for (cy.columns, 0..) |cycle_col, i| {
                        indices[i] = col_names.?.len; // sentinel: not found = out of bounds
                        for (col_names.?, 0..) |cn, j| {
                            const base_cn = if (std.mem.indexOfScalar(u8, cn, '.')) |dot| cn[dot + 1 ..] else cn;
                            if (std.ascii.eqlIgnoreCase(base_cn, cycle_col)) {
                                indices[i] = j;
                                break;
                            }
                        }
                    }
                    cycle_col_indices_opt = indices;
                }
            }
            const base_vals = try self.dupeRowValues(row.values);
            row.deinit();

            if (has_cycle) {
                // Add base key to cycle_seen (anchor rows are never cycles)
                const key = try self.computeCycleKey(base_vals, cycle_col_indices_opt orelse &.{});
                if (!cycle_seen.contains(key)) {
                    cycle_seen.put(self.allocator, key, {}) catch {
                        self.allocator.free(key);
                        return EngineError.OutOfMemory;
                    };
                } else {
                    self.allocator.free(key);
                }
                // Append no_cycle_value to base vals
                const full_vals = try self.appendCycleValue(base_vals, cycle_default_val);
                all_rows.append(self.allocator, full_vals) catch return EngineError.OutOfMemory;
            } else {
                all_rows.append(self.allocator, base_vals) catch return EngineError.OutOfMemory;
            }
        }
        anchor_iter.close();

        // If anchor produced no rows, create empty CTE
        if (col_names == null) {
            col_names = try self.buildEmptyColNames(cte.column_names);
        }

        // Build extended column names (with cycle column appended) for output
        const output_col_names: []const []const u8 = if (cte.cycle) |cy| blk: {
            const extended = self.allocator.alloc([]const u8, col_names.?.len + 1) catch return EngineError.OutOfMemory;
            for (col_names.?, 0..) |n, i| extended[i] = n;
            extended[col_names.?.len] = cy.cycle_column;
            // col_names is now owned by extended; don't free it separately
            self.allocator.free(col_names.?);
            col_names = null;
            break :blk extended;
        } else col_names.?;

        // Step 2: Build initial working set from anchor rows (base cols only)
        var working_rows = std.ArrayListUnmanaged([]Value){};
        for (all_rows.items) |row_vals| {
            const base_len = if (has_cycle) row_vals.len - 1 else row_vals.len;
            const base_copy = self.allocator.alloc(Value, base_len) catch return EngineError.OutOfMemory;
            for (0..base_len) |i| base_copy[i] = row_vals[i].dupe(self.allocator) catch return EngineError.OutOfMemory;
            working_rows.append(self.allocator, base_copy) catch return EngineError.OutOfMemory;
        }

        // Working table column names are base only (without cycle col)
        const base_col_names: []const []const u8 = if (has_cycle)
            output_col_names[0 .. output_col_names.len - 1]
        else
            output_col_names;

        var iteration: usize = 0;
        while (iteration < max_recursive_cte_depth) : (iteration += 1) {
            if (working_rows.items.len == 0) break;

            // Create a MaterializedOp for the working table (current iteration's input)
            // Working table uses base col names (without cycle col)
            const working_col_names = try self.dupeColNames(base_col_names);
            const working_data = working_rows.toOwnedSlice(self.allocator) catch return EngineError.OutOfMemory;
            const working_mat = self.allocator.create(MaterializedOp) catch return EngineError.OutOfMemory;
            working_mat.* = MaterializedOp.init(self.allocator, working_col_names, working_data);

            // Put the working table into the CTE map so recursive scans find it
            if (cte_map.get(cte.name)) |old_mat| {
                old_mat.close();
                self.allocator.destroy(old_mat);
            }
            cte_map.put(self.allocator, cte.name, working_mat) catch return EngineError.OutOfMemory;

            // Execute the recursive part against the working table
            const rec_ops = self.allocator.create(OperatorChain) catch return EngineError.OutOfMemory;
            rec_ops.* = .{};
            rec_ops.cte_materialized = cte_map.*;
            ops.cte_ops.append(self.allocator, rec_ops) catch return EngineError.OutOfMemory;

            var rec_iter = self.buildIterator(recursive_plan, rec_ops) catch return EngineError.ExecutionError;

            // Collect new rows from this iteration
            working_rows = .{};
            while (rec_iter.next() catch return EngineError.ExecutionError) |row_data| {
                var row = row_data;
                const base_vals = try self.dupeRowValues(row.values);
                row.deinit();

                if (has_cycle) {
                    // Compute cycle key from base values
                    const key = try self.computeCycleKey(base_vals, cycle_col_indices_opt orelse &.{});
                    if (cycle_seen.contains(key)) {
                        // Cycle detected: emit with cycle_to_val, don't recurse further
                        self.allocator.free(key);
                        const full_vals = try self.appendCycleValue(base_vals, cycle_to_val);
                        all_rows.append(self.allocator, full_vals) catch return EngineError.OutOfMemory;
                        // base_vals ownership transferred to full_vals (first n-1 elements)
                    } else {
                        // No cycle: emit with cycle_default_val and continue recursion
                        cycle_seen.put(self.allocator, key, {}) catch {
                            self.allocator.free(key);
                            for (base_vals) |v| v.free(self.allocator);
                            self.allocator.free(base_vals);
                            return EngineError.OutOfMemory;
                        };
                        const base_len = base_vals.len; // save before appendCycleValue takes ownership
                        const full_vals = try self.appendCycleValue(base_vals, cycle_default_val);
                        all_rows.append(self.allocator, full_vals) catch return EngineError.OutOfMemory;
                        // Add base copy to working set for next iteration
                        const working_copy = self.allocator.alloc(Value, base_len) catch return EngineError.OutOfMemory;
                        for (0..base_len) |i| working_copy[i] = full_vals[i].dupe(self.allocator) catch return EngineError.OutOfMemory;
                        working_rows.append(self.allocator, working_copy) catch return EngineError.OutOfMemory;
                    }
                } else {
                    // No CYCLE clause: add to both complete result and next working set
                    all_rows.append(self.allocator, base_vals) catch return EngineError.OutOfMemory;
                    const working_copy = try self.dupeRowValuesSlice(base_vals);
                    working_rows.append(self.allocator, working_copy) catch return EngineError.OutOfMemory;
                }
            }
            rec_iter.close();
        }

        // Free any remaining working rows (from the last empty iteration or overflow)
        for (working_rows.items) |vals| {
            for (vals) |v| v.free(self.allocator);
            self.allocator.free(vals);
        }
        working_rows.deinit(self.allocator);

        // Build final MaterializedOp with all accumulated rows
        const final_col_names = try self.dupeColNames(output_col_names);
        // Free the output_col_names inner strings and outer slice.
        // In cycle case: output_col_names[0..n-1] are heap strings from captureColNames;
        // output_col_names[n] is AST-owned (cycle_column) — must NOT be freed.
        // In non-cycle case: all strings in output_col_names are heap-allocated.
        const owned_count = if (has_cycle) output_col_names.len - 1 else output_col_names.len;
        for (output_col_names[0..owned_count]) |c| self.allocator.free(@constCast(c));
        self.allocator.free(@constCast(output_col_names));

        const final_mat = self.allocator.create(MaterializedOp) catch return EngineError.OutOfMemory;
        final_mat.* = MaterializedOp.init(
            self.allocator,
            final_col_names,
            all_rows.toOwnedSlice(self.allocator) catch return EngineError.OutOfMemory,
        );

        // Replace the working table entry with the final complete result
        if (cte_map.get(cte.name)) |old_mat| {
            old_mat.close();
            self.allocator.destroy(old_mat);
        }
        cte_map.put(self.allocator, cte.name, final_mat) catch return EngineError.OutOfMemory;
    }

    /// Compute a cycle key from specific column values (used by CYCLE clause).
    fn computeCycleKey(self: *Database, vals: []const Value, col_indices: []const usize) EngineError![]const u8 {
        var buf = std.ArrayList(u8){};
        const alloc = self.allocator;
        for (col_indices, 0..) |idx, i| {
            if (i > 0) buf.append(alloc, 0) catch return EngineError.OutOfMemory; // null-byte separator
            if (idx >= vals.len) {
                buf.appendSlice(alloc, "\xff") catch return EngineError.OutOfMemory;
                continue;
            }
            switch (vals[idx]) {
                .null_value => buf.appendSlice(alloc, "\xfe") catch return EngineError.OutOfMemory,
                .integer => |n| std.fmt.format(buf.writer(alloc), "{d}", .{n}) catch return EngineError.OutOfMemory,
                .real => |r| std.fmt.format(buf.writer(alloc), "{d}", .{r}) catch return EngineError.OutOfMemory,
                .text => |t| buf.appendSlice(alloc, t) catch return EngineError.OutOfMemory,
                .blob => |b| buf.appendSlice(alloc, b) catch return EngineError.OutOfMemory,
                .boolean => |b| buf.append(alloc, if (b) 1 else 0) catch return EngineError.OutOfMemory,
                else => buf.appendSlice(alloc, "?") catch return EngineError.OutOfMemory,
            }
        }
        return buf.toOwnedSlice(alloc) catch return EngineError.OutOfMemory;
    }

    /// Append a cycle marker value to a base row's values array.
    /// Takes ownership of base_vals and returns a new slice with cycle_val appended.
    fn appendCycleValue(self: *Database, base_vals: []Value, cycle_val: Value) EngineError![]Value {
        const extended = self.allocator.alloc(Value, base_vals.len + 1) catch return EngineError.OutOfMemory;
        @memcpy(extended[0..base_vals.len], base_vals);
        self.allocator.free(base_vals);
        extended[extended.len - 1] = cycle_val.dupe(self.allocator) catch return EngineError.OutOfMemory;
        return extended;
    }

    /// Capture column names from a row, applying CTE column aliases if provided.
    fn captureColNames(self: *Database, row: *const Row, cte_col_names: []const []const u8) EngineError![]const []const u8 {
        if (cte_col_names.len > 0) {
            const names = self.allocator.alloc([]const u8, cte_col_names.len) catch return EngineError.OutOfMemory;
            for (cte_col_names, 0..) |name, i| {
                names[i] = self.allocator.dupe(u8, name) catch return EngineError.OutOfMemory;
            }
            return names;
        }
        const names = self.allocator.alloc([]const u8, row.columns.len) catch return EngineError.OutOfMemory;
        for (row.columns, 0..) |c, i| {
            const base = if (std.mem.indexOfScalar(u8, c, '.')) |dot| c[dot + 1 ..] else c;
            names[i] = self.allocator.dupe(u8, base) catch return EngineError.OutOfMemory;
        }
        return names;
    }

    /// Build empty column names from explicit CTE column aliases.
    fn buildEmptyColNames(self: *Database, cte_col_names: []const []const u8) EngineError![]const []const u8 {
        if (cte_col_names.len > 0) {
            const names = self.allocator.alloc([]const u8, cte_col_names.len) catch return EngineError.OutOfMemory;
            for (cte_col_names, 0..) |name, i| {
                names[i] = self.allocator.dupe(u8, name) catch return EngineError.OutOfMemory;
            }
            return names;
        }
        return self.allocator.alloc([]const u8, 0) catch return EngineError.OutOfMemory;
    }

    /// Duplicate row values.
    fn dupeRowValues(self: *Database, values: []const Value) EngineError![]Value {
        const vals = self.allocator.alloc(Value, values.len) catch return EngineError.OutOfMemory;
        for (values, 0..) |v, i| {
            vals[i] = v.dupe(self.allocator) catch return EngineError.OutOfMemory;
        }
        return vals;
    }

    /// Duplicate a slice of values (for working set copies).
    fn dupeRowValuesSlice(self: *Database, values: []const Value) EngineError![]Value {
        return self.dupeRowValues(values);
    }

    /// Duplicate column names.
    fn dupeColNames(self: *Database, names: []const []const u8) EngineError![]const []const u8 {
        const result = self.allocator.alloc([]const u8, names.len) catch return EngineError.OutOfMemory;
        for (names, 0..) |n, i| {
            result[i] = self.allocator.dupe(u8, n) catch return EngineError.OutOfMemory;
        }
        return result;
    }

    /// Build a scan over a materialized CTE result.
    fn buildCteScan(self: *Database, scan: PlanNode.Scan, ops: *OperatorChain, source_mat: *MaterializedOp) EngineError!RowIterator {
        // Create a new MaterializedOp that reads from the same data
        // We duplicate all the data since each MaterializedOp owns its data
        const num_cols = source_mat.col_names.len;
        const num_rows = source_mat.rows.len;

        // Duplicate column names (apply scan alias if present)
        const col_names = self.allocator.alloc([]const u8, num_cols) catch return EngineError.OutOfMemory;
        for (source_mat.col_names, 0..) |c, i| {
            if (scan.alias) |alias| {
                col_names[i] = std.fmt.allocPrint(self.allocator, "{s}.{s}", .{ alias, c }) catch return EngineError.OutOfMemory;
            } else {
                col_names[i] = self.allocator.dupe(u8, c) catch return EngineError.OutOfMemory;
            }
        }

        // Duplicate all rows
        const rows = self.allocator.alloc([]Value, num_rows) catch return EngineError.OutOfMemory;
        for (source_mat.rows, 0..) |src_vals, r| {
            const vals = self.allocator.alloc(Value, src_vals.len) catch return EngineError.OutOfMemory;
            for (src_vals, 0..) |v, c| {
                vals[c] = v.dupe(self.allocator) catch return EngineError.OutOfMemory;
            }
            rows[r] = vals;
        }

        const mat_op = self.allocator.create(MaterializedOp) catch return EngineError.OutOfMemory;
        mat_op.* = MaterializedOp.init(self.allocator, col_names, rows);
        ops.materialized = mat_op;
        return mat_op.iterator();
    }

    /// Parse a default expression string into a Value.
    /// Handles: integers, floats, quoted strings, true, false, NULL.
    fn evalDefaultExprToValue(expr: []const u8, allocator: std.mem.Allocator) executor_mod.Value {
        // Try parsing as integer
        if (std.fmt.parseInt(i64, expr, 10)) |n| {
            return .{ .integer = n };
        } else |_| {}

        // Try parsing as float
        if (std.fmt.parseFloat(f64, expr)) |f| {
            return .{ .real = f };
        } else |_| {}

        // Try parsing as quoted string: 'text'
        if (expr.len >= 2 and expr[0] == '\'' and expr[expr.len - 1] == '\'') {
            const inner = expr[1 .. expr.len - 1];
            const text = allocator.dupe(u8, inner) catch return .null_value;
            return .{ .text = text };
        }

        // Try parsing as boolean
        if (std.ascii.eqlIgnoreCase(expr, "true")) {
            return .{ .boolean = true };
        }
        if (std.ascii.eqlIgnoreCase(expr, "false")) {
            return .{ .boolean = false };
        }

        // Try parsing as NULL
        if (std.ascii.eqlIgnoreCase(expr, "null")) {
            return .null_value;
        }

        // Default to null if unrecognized
        return .null_value;
    }

    fn buildTableScan(self: *Database, scan: PlanNode.Scan, ops: *OperatorChain, table_info: *catalog_mod.TableInfo) EngineError!RowIterator {
        defer table_info.deinit(self.allocator);

        // Register SSI read for SERIALIZABLE transactions
        try self.ssiRegisterRead(table_info.data_root_page_id);

        // Build column names for the scan
        const col_names = self.allocator.alloc([]const u8, table_info.columns.len) catch return EngineError.OutOfMemory;
        for (table_info.columns, 0..) |col, i| {
            if (scan.alias) |alias| {
                col_names[i] = std.fmt.allocPrint(self.allocator, "{s}.{s}", .{ alias, col.name }) catch return EngineError.OutOfMemory;
            } else {
                col_names[i] = self.allocator.dupe(u8, col.name) catch return EngineError.OutOfMemory;
            }
        }

        // Build default values for columns (needed when old rows have fewer columns than schema)
        const col_defaults = self.allocator.alloc(executor_mod.Value, table_info.columns.len) catch return EngineError.OutOfMemory;
        for (col_defaults) |*d| d.* = .null_value;
        for (table_info.columns, 0..) |col, i| {
            if (self.catalog.getDefaultExpr(scan.table, col.name) catch null) |expr_sql| {
                defer self.allocator.free(expr_sql);
                col_defaults[i] = evalDefaultExprToValue(expr_sql, self.allocator);
            }
        }

        const scan_op = self.allocator.create(ScanOp) catch return EngineError.OutOfMemory;
        scan_op.* = ScanOp.init(self.allocator, self.pool, table_info.data_root_page_id, col_names);
        scan_op.col_defaults = col_defaults;
        // TABLESAMPLE: configure probabilistic row sampling
        if (scan.tablesample) |ts| {
            scan_op.sample_pct = ts.percent;
            if (ts.seed) |s| {
                // User-specified seed: ensure non-zero (xorshift64 breaks on 0)
                scan_op.sample_state = if (s == 0) 1 else @as(u64, @bitCast(s));
            }
        }
        // Set MVCC context for visibility filtering (RC snapshot stored in ops for cleanup)
        scan_op.mvcc_ctx = try self.getMvccContextWithOps(ops);
        // Set row-level locking for SELECT FOR UPDATE/SHARE
        if (ops.locking_clauses.len > 0) {
            if (self.current_txn) |txn| {
                for (ops.locking_clauses) |lc| {
                    // Apply if no specific tables listed, or this table is in the list
                    const applies = lc.tables.len == 0 or blk: {
                        for (lc.tables) |t| {
                            if (std.ascii.eqlIgnoreCase(t, scan.table)) break :blk true;
                        }
                        break :blk false;
                    };
                    if (applies) {
                        scan_op.lock_manager = &self.lock_manager;
                        scan_op.lock_xid = txn.xid;
                        scan_op.lock_table_page_id = table_info.data_root_page_id;
                        scan_op.lock_mode = switch (lc.strength) {
                            .update, .no_key_update => LockMode.exclusive,
                            .share, .key_share => LockMode.shared,
                        };
                        scan_op.lock_skip_locked = lc.wait_policy == .skip_locked;
                        break;
                    }
                }
            }
        }
        scan_op.initCursor(); // Must be called after heap placement

        if (ops.scan == null) {
            ops.scan = scan_op;
        } else {
            ops.scan2 = scan_op;
        }
        return scan_op.iterator();
    }

    fn buildFilter(self: *Database, filter: PlanNode.Filter, ops: *OperatorChain) EngineError!RowIterator {
        // Try index selection: if the predicate is `col = literal` and the
        // input is a table scan on a table with an index on that column,
        // use IndexScanOp for a direct B+Tree lookup instead of full scan.
        if (filter.input.* == .scan) {
            if (self.tryBuildIndexScan(filter.input.scan, filter.predicate, ops)) |iter| {
                return iter;
            }
        }

        const input = try self.buildIterator(filter.input, ops);
        const filter_op = self.allocator.create(FilterOp) catch return EngineError.OutOfMemory;
        filter_op.* = FilterOp.init(self.allocator, input, filter.predicate);
        filter_op.catalog = &self.catalog;
        filter_op.outer_row = ops.outer_row;
        ops.filter = filter_op;
        return filter_op.iterator();
    }

    /// Try to use a secondary index for a predicate on a scan.
    /// Returns a RowIterator if successful, null if index scan is not applicable.
    fn tryBuildIndexScan(self: *Database, scan: PlanNode.Scan, predicate: *const ast_mod.Expr, ops: *OperatorChain) ?RowIterator {
        // Only handle simple equality predicates: column_ref = literal
        const eq = extractEqualityPredicate(predicate) orelse return null;

        // Look up the table to find index info
        var table_info = self.catalog.getTable(scan.table) catch return null;
        defer table_info.deinit(self.allocator);

        // Register SSI read for SERIALIZABLE transactions
        // OOM here falls through to full table scan which also registers read
        self.ssiRegisterRead(table_info.data_root_page_id) catch return null;

        // Check if there's an index on the referenced column
        const col_name = eq.column_name;
        const idx_info = table_info.findIndex(col_name) orelse return null;

        // Encode the literal value as an index key
        const idx_key = switch (eq.value_type) {
            .integer => |v| integerToIndexKey(self.allocator, v) catch return null,
            .text => |v| stringToIndexKey(self.allocator, v) catch return null,
        };

        // Build column names for the scan
        const col_names = self.allocator.alloc([]const u8, table_info.columns.len) catch return null;
        for (table_info.columns, 0..) |col, i| {
            if (scan.alias) |alias| {
                col_names[i] = std.fmt.allocPrint(self.allocator, "{s}.{s}", .{ alias, col.name }) catch return null;
            } else {
                col_names[i] = self.allocator.dupe(u8, col.name) catch return null;
            }
        }

        // Build default values for columns (needed when old rows have fewer columns than schema)
        const col_defaults = self.allocator.alloc(executor_mod.Value, table_info.columns.len) catch return null;
        for (col_defaults) |*d| d.* = .null_value;
        for (table_info.columns, 0..) |col, i| {
            if (self.catalog.getDefaultExpr(scan.table, col.name) catch null) |expr_sql| {
                defer self.allocator.free(expr_sql);
                col_defaults[i] = evalDefaultExprToValue(expr_sql, self.allocator);
            }
        }

        const idx_op = self.allocator.create(IndexScanOp) catch return null;
        idx_op.* = IndexScanOp.init(
            self.allocator,
            self.pool,
            table_info.data_root_page_id,
            idx_info.root_page_id,
            idx_info.index_type,
            idx_key,
            col_names,
        );
        idx_op.col_defaults = col_defaults;
        // Set MVCC context for visibility filtering (RC snapshot stored in ops for cleanup)
        idx_op.mvcc_ctx = self.getMvccContextWithOps(ops) catch return null;
        ops.index_scan = idx_op;
        return idx_op.iterator();
    }

    fn buildProject(self: *Database, project: PlanNode.Project, ops: *OperatorChain) EngineError!RowIterator {
        const input = try self.buildIterator(project.input, ops);

        // Check if this is a SELECT * (single column_ref with name "*")
        if (project.columns.len == 1) {
            if (project.columns[0].expr.* == .column_ref) {
                const ref = project.columns[0].expr.column_ref;
                if (std.mem.eql(u8, ref.name, "*") and ref.prefix == null) {
                    // SELECT * — pass through all columns without projection
                    return input;
                }
            }
        }

        const project_op = self.allocator.create(ProjectOp) catch return EngineError.OutOfMemory;
        project_op.* = ProjectOp.init(self.allocator, input, project.columns, &self.catalog);
        ops.project = project_op;
        return project_op.iterator();
    }

    fn buildLimit(self: *Database, limit: PlanNode.Limit, ops: *OperatorChain) EngineError!RowIterator {
        const input = try self.buildIterator(limit.input, ops);

        // Evaluate limit/offset expressions (they should be integer literals)
        const empty_row = Row{ .columns = &.{}, .values = &.{}, .allocator = self.allocator };
        const limit_count: ?u64 = if (limit.limit_expr) |expr| blk: {
            const val = evalExpr(self.allocator, expr, &empty_row, null) catch break :blk null;
            defer val.free(self.allocator);
            break :blk if (val.toInteger()) |i| @intCast(i) else null;
        } else null;
        const offset_count: u64 = if (limit.offset_expr) |expr| blk: {
            const val = evalExpr(self.allocator, expr, &empty_row, null) catch break :blk 0;
            defer val.free(self.allocator);
            break :blk if (val.toInteger()) |i| @intCast(i) else 0;
        } else 0;

        const limit_op = self.allocator.create(LimitOp) catch return EngineError.OutOfMemory;
        limit_op.* = LimitOp.init(self.allocator, input, limit_count, offset_count);
        limit_op.with_ties = limit.with_ties;
        limit_op.order_by = limit.order_by;
        ops.limit = limit_op;
        return limit_op.iterator();
    }

    fn buildSort(self: *Database, sort: PlanNode.Sort, ops: *OperatorChain) EngineError!RowIterator {
        const input = try self.buildIterator(sort.input, ops);
        const sort_op = self.allocator.create(SortOp) catch return EngineError.OutOfMemory;
        sort_op.* = SortOp.init(self.allocator, input, sort.order_by);
        sort_op.catalog = &self.catalog;
        ops.sort = sort_op;
        return sort_op.iterator();
    }

    fn buildAggregate(self: *Database, agg: PlanNode.Aggregate, ops: *OperatorChain) EngineError!RowIterator {
        const input = try self.buildIterator(agg.input, ops);
        const agg_op = self.allocator.create(AggregateOp) catch return EngineError.OutOfMemory;
        agg_op.* = AggregateOp.init(self.allocator, input, agg.group_by, agg.aggregates);
        if (agg.grouping_sets) |gs| agg_op.grouping_sets = gs;
        ops.aggregate = agg_op;
        return agg_op.iterator();
    }

    fn buildJoin(self: *Database, join: PlanNode.Join, ops: *OperatorChain) EngineError!RowIterator {
        // Check if right side is a LATERAL table function scan
        if (join.right.* == .table_function_scan) {
            const tfs = join.right.table_function_scan;
            if (tfs.is_lateral) {
                // Use LateralJoinOp instead of regular join
                const left = try self.buildIterator(join.left, ops);
                const lateral_op = self.allocator.create(LateralJoinOp) catch return EngineError.OutOfMemory;
                lateral_op.* = LateralJoinOp.init(self.allocator, self, left, tfs, join.join_type, join.on_condition);
                ops.lateral_join = lateral_op;
                return lateral_op.iterator();
            }
        }

        const left = try self.buildIterator(join.left, ops);
        const right = try self.buildIterator(join.right, ops);

        // Use the algorithm selected by the optimizer
        return switch (join.algorithm) {
            .nested_loop => {
                const join_op = self.allocator.create(NestedLoopJoinOp) catch return EngineError.OutOfMemory;
                join_op.* = NestedLoopJoinOp.init(self.allocator, left, right, join.join_type, join.on_condition);
                ops.join = join_op;
                return join_op.iterator();
            },
            .hash => {
                const join_op = self.allocator.create(HashJoinOp) catch return EngineError.OutOfMemory;
                join_op.* = HashJoinOp.init(self.allocator, left, right, join.join_type, join.on_condition);
                ops.hash_join = join_op;
                return join_op.iterator();
            },
            .merge => {
                const join_op = self.allocator.create(MergeJoinOp) catch return EngineError.OutOfMemory;
                join_op.* = MergeJoinOp.init(self.allocator, left, right, join.join_type, join.on_condition);
                ops.merge_join = join_op;
                return join_op.iterator();
            },
        };
    }

    fn buildDistinct(self: *Database, d: PlanNode.Distinct, ops: *OperatorChain) EngineError!RowIterator {
        const input = try self.buildIterator(d.input, ops);
        const distinct_op = self.allocator.create(DistinctOp) catch return EngineError.OutOfMemory;
        distinct_op.* = DistinctOp.init(self.allocator, input, d.on_exprs);
        ops.distinct = distinct_op;
        return distinct_op.iterator();
    }

    fn buildWindow(self: *Database, w: PlanNode.Window, ops: *OperatorChain) EngineError!RowIterator {
        const input = try self.buildIterator(w.input, ops);
        const window_op = self.allocator.create(WindowOp) catch return EngineError.OutOfMemory;
        window_op.* = WindowOp.init(self.allocator, input, w.funcs, w.aliases);
        ops.window = window_op;
        return window_op.iterator();
    }

    fn buildSetOp(self: *Database, set_op: PlanNode.SetOp, ops: *OperatorChain) EngineError!RowIterator {
        // Each side of a set operation needs its own OperatorChain because
        // both sides produce independent operator trees (scan, project, etc.)
        // that would otherwise overwrite each other in a single chain.
        const left_ops = self.allocator.create(OperatorChain) catch return EngineError.OutOfMemory;
        left_ops.* = .{};
        left_ops.cte_materialized = ops.cte_materialized;
        ops.set_op_chains.append(self.allocator, left_ops) catch return EngineError.OutOfMemory;

        const right_ops = self.allocator.create(OperatorChain) catch return EngineError.OutOfMemory;
        right_ops.* = .{};
        right_ops.cte_materialized = ops.cte_materialized;
        ops.set_op_chains.append(self.allocator, right_ops) catch return EngineError.OutOfMemory;

        const left = try self.buildIterator(set_op.left, left_ops);
        const right = try self.buildIterator(set_op.right, right_ops);
        const set_op_op = self.allocator.create(SetOpOp) catch return EngineError.OutOfMemory;
        set_op_op.* = SetOpOp.init(self.allocator, left, right, set_op.op);
        ops.set_op = set_op_op;
        return set_op_op.iterator();
    }

    fn buildValues(self: *Database, values: PlanNode.Values, ops: *OperatorChain) EngineError!RowIterator {
        const col_names: []const []const u8 = if (values.columns) |cols| cols else &.{};
        const values_op = self.allocator.create(ValuesOp) catch return EngineError.OutOfMemory;
        values_op.* = ValuesOp.init(self.allocator, col_names, values.rows);
        ops.values = values_op;
        return values_op.iterator();
    }

    fn buildEmpty(self: *Database, empty: PlanNode.Empty, ops: *OperatorChain) EngineError!RowIterator {
        const empty_op = self.allocator.create(EmptyOp) catch return EngineError.OutOfMemory;
        empty_op.* = .{
            .allocator = self.allocator,
            .description = empty.description,
        };
        ops.empty = empty_op;
        return empty_op.iterator();
    }

    // ── INSERT execution ──────────────────────────────────────────────

    fn executeInsert(self: *Database, arena: *AstArena, plan: LogicalPlan) EngineError!QueryResult {
        defer {
            arena.deinit();
            self.allocator.destroy(arena);
        }

        // Check if write operations are allowed (standby mode check)
        self.standby_coordinator.checkWriteAllowed() catch |err| {
            return switch (err) {
                StandbyCoordinator.Error.WriteOperationNotAllowed => EngineError.TransactionError,
                else => EngineError.ExecutionError,
            };
        };

        const values_node = switch (plan.root.*) {
            .values => |v| v,
            else => return EngineError.ExecutionError,
        };

        // Try direct table lookup first; if not found, check for updatable view
        var view_arena_storage: ?AstArena = null;
        var view_infra_storage: ?std.heap.ArenaAllocator = null;
        defer if (view_arena_storage) |*va| va.deinit();
        defer if (view_infra_storage) |*vi| vi.deinit();

        var view_check_where: ?*const ast_mod.Expr = null;

        var actual_table: []const u8 = values_node.table;
        if (self.catalog.getTable(values_node.table)) |ti| {
            ti.deinit(self.allocator);
        } else |_| {
            // Table not found — check for updatable view
            view_arena_storage = AstArena.init(self.allocator);
            view_infra_storage = std.heap.ArenaAllocator.init(self.allocator);
            if (self.resolveUpdatableView(
                &view_arena_storage.?,
                &view_infra_storage.?,
                values_node.table,
            )) |uvi| {
                actual_table = uvi.base_table;
                if (uvi.check_option != 0 and uvi.where_clause != null) {
                    view_check_where = uvi.where_clause;
                }
            } else {
                return EngineError.TableNotFound;
            }
        }

        // Look up the actual base table
        var table_info = self.catalog.getTable(actual_table) catch return EngineError.TableNotFound;
        defer table_info.deinit(self.allocator);

        // Register SSI write for SERIALIZABLE transactions
        try self.ssiRegisterWrite(table_info.data_root_page_id);

        var tree = BTree.init(self.pool, table_info.data_root_page_id);
        const empty_row = Row{ .columns = &.{}, .values = &.{}, .allocator = self.allocator };

        // Build column names for check option evaluation
        var check_col_names: ?[]const []const u8 = null;
        defer if (check_col_names) |ccn| self.allocator.free(ccn);
        if (view_check_where != null) {
            const names = self.allocator.alloc([]const u8, table_info.columns.len) catch return EngineError.OutOfMemory;
            for (table_info.columns, 0..) |col, i| {
                names[i] = col.name;
            }
            check_col_names = names;
        }

        // Find the next available row key by scanning to the end
        var next_key: u64 = self.findNextRowKey(&tree) catch return EngineError.StorageError;

        var rows_inserted: u64 = 0;

        // Build column names for trigger context
        const insert_col_names = self.allocator.alloc([]const u8, table_info.columns.len) catch return EngineError.OutOfMemory;
        defer self.allocator.free(insert_col_names);
        for (table_info.columns, 0..) |col, i| {
            insert_col_names[i] = col.name;
        }

        // Collect inserted rows if RETURNING clause is present
        var inserted_rows = std.ArrayListUnmanaged([]Value){};
        defer {
            for (inserted_rows.items) |row| {
                for (row) |v| v.free(self.allocator);
                self.allocator.free(row);
            }
            inserted_rows.deinit(self.allocator);
        }

        // Fire BEFORE INSERT triggers (STATEMENT fires once, ROW fires per row to be inserted)
        self.fireTriggers(actual_table, .insert, .before, @intCast(values_node.rows.len), null, false, null);

        for (values_node.rows) |row_exprs| {
            // Evaluate value expressions
            const user_vals = self.allocator.alloc(Value, row_exprs.len) catch return EngineError.OutOfMemory;
            var user_inited: usize = 0;
            defer {
                for (user_vals[0..user_inited]) |v| v.free(self.allocator);
                self.allocator.free(user_vals);
            }

            for (row_exprs, 0..) |expr, i| {
                user_vals[i] = evalExpr(self.allocator, expr, &empty_row, null) catch return EngineError.ExecutionError;
                user_inited += 1;
            }

            // Check if any generated columns are specified in INSERT and reject
            if (values_node.columns) |spec_cols| {
                for (spec_cols) |sc| {
                    for (table_info.columns) |tc| {
                        if (tc.flags.is_generated and std.ascii.eqlIgnoreCase(sc, tc.name)) {
                            return EngineError.GeneratedColumnViolation;
                        }
                    }
                }
            }

            // Build full row with generated columns evaluated
            var vals: []Value = undefined;
            var full_row_allocated = false;
            defer {
                if (full_row_allocated) {
                    for (vals) |v| v.free(self.allocator);
                    self.allocator.free(vals);
                }
            }

            const has_generated = blk: {
                for (table_info.columns) |col| {
                    if (col.flags.is_generated) break :blk true;
                }
                break :blk false;
            };

            const has_autoincrement = blk: {
                for (table_info.columns) |col| {
                    if (col.flags.autoincrement) break :blk true;
                }
                break :blk false;
            };

            // Check if we need to fill defaults or validate NOT NULL
            const has_defaults = blk: {
                for (table_info.columns) |col| {
                    if (col.flags.has_default) break :blk true;
                }
                break :blk false;
            };

            const has_not_null = blk: {
                for (table_info.columns) |col| {
                    if (col.flags.not_null) break :blk true;
                }
                break :blk false;
            };

            // Check if we need to build a full row (has generated, autoincrement, defaults, or NOT NULL)
            const need_full_row = has_generated or has_autoincrement or has_defaults or has_not_null;

            if (need_full_row) {
                // Build full row for all table columns
                vals = self.allocator.alloc(Value, table_info.columns.len) catch return EngineError.OutOfMemory;
                full_row_allocated = true;
                for (vals) |*v| v.* = .null_value;

                // Map user-provided values into their positions
                if (values_node.columns) |spec_cols| {
                    // Column list specified — map by name
                    for (spec_cols, 0..) |sc, si| {
                        if (si >= user_vals.len) break;
                        for (table_info.columns, 0..) |tc, ti| {
                            if (std.ascii.eqlIgnoreCase(sc, tc.name)) {
                                vals[ti].free(self.allocator);
                                vals[ti] = user_vals[si].dupe(self.allocator) catch return EngineError.OutOfMemory;
                                break;
                            }
                        }
                    }
                } else {
                    // No column list — determine whether user provided values for ALL columns
                    // (including SERIAL) or only for non-SERIAL columns.
                    const non_autoinc_cols: usize = blk: {
                        var n: usize = 0;
                        for (table_info.columns) |tc| {
                            if (!tc.flags.is_generated and !tc.flags.autoincrement) n += 1;
                        }
                        break :blk n;
                    };
                    const all_cols = table_info.columns.len;
                    // If values count matches total columns, user provides explicit SERIAL values too
                    const skip_autoinc = user_vals.len < all_cols;
                    _ = non_autoinc_cols;
                    var vi: usize = 0;
                    for (table_info.columns, 0..) |tc, ti| {
                        if (tc.flags.is_generated) continue;
                        if (skip_autoinc and tc.flags.autoincrement) continue;
                        if (vi < user_vals.len) {
                            vals[ti].free(self.allocator);
                            vals[ti] = user_vals[vi].dupe(self.allocator) catch return EngineError.OutOfMemory;
                            vi += 1;
                        }
                    }
                }

                // Fill in default values for columns that weren't provided
                for (table_info.columns, 0..) |col, ti| {
                    if (vals[ti] == .null_value and col.flags.has_default) {
                        if (self.catalog.getDefaultExpr(actual_table, col.name) catch null) |expr_sql| {
                            defer self.allocator.free(expr_sql);
                            vals[ti] = evalDefaultExprToValue(expr_sql, self.allocator);
                        }
                    }
                }

                // Build column names for row context (needed for generated col evaluation)
                const col_names = self.allocator.alloc([]const u8, table_info.columns.len) catch return EngineError.OutOfMemory;
                defer self.allocator.free(col_names);
                for (table_info.columns, 0..) |col, ci| col_names[ci] = col.name;

                // Evaluate generated columns
                const gen_row = Row{ .columns = col_names, .values = vals, .allocator = self.allocator };
                for (table_info.columns, 0..) |tc, ti| {
                    if (!tc.flags.is_generated) continue;
                    if (tc.generated_expr.len == 0) continue;
                    const gen_val = try self.evalGeneratedExpr(tc.generated_expr, &gen_row);
                    vals[ti].free(self.allocator);
                    vals[ti] = gen_val;
                }

                // Fill autoincrement columns: auto-generate if not provided, advance seq if provided
                for (table_info.columns, 0..) |tc, ti| {
                    if (!tc.flags.autoincrement) continue;
                    if (vals[ti] == .null_value) {
                        // Column not provided — auto-generate next value
                        const next_val = self.catalog.getSeqNextVal(actual_table, tc.name) catch
                            return EngineError.ExecutionError;
                        vals[ti] = .{ .integer = next_val };
                    } else if (vals[ti] == .integer) {
                        // Explicit value provided — advance sequence if it exceeds current max
                        self.catalog.advanceSeqIfGreater(actual_table, tc.name, vals[ti].integer) catch
                            return EngineError.ExecutionError;
                    }
                }

                // Validate NOT NULL constraints
                for (table_info.columns, 0..) |col, ti| {
                    if (col.flags.not_null and vals[ti] == .null_value) {
                        return EngineError.ConstraintViolation;
                    }
                }
            } else {
                // No generated columns or autoincrement — use user values directly
                vals = user_vals;
            }

            // Enforce column-level CHECK constraints
            {
                const has_any_check: bool = for (table_info.columns) |col| {
                    if (col.flags.has_check) break true;
                } else false;
                if (has_any_check) {
                    const check_names = self.allocator.alloc([]const u8, table_info.columns.len) catch return EngineError.OutOfMemory;
                    defer self.allocator.free(check_names);
                    for (table_info.columns, 0..) |col, i| check_names[i] = col.name;
                    try self.evalCheckConstraints(&table_info, check_names, vals);
                }
            }

            // WITH CHECK OPTION: validate that the inserted row satisfies the view's WHERE
            if (view_check_where) |where_expr| {
                if (check_col_names) |col_names| {
                    if (!self.checkViewCondition(where_expr, col_names, vals)) {
                        return EngineError.CheckOptionViolation;
                    }
                }
            }

            // RLS WITH CHECK: validate the candidate row against INSERT policies
            {
                const rls_col_names = self.allocator.alloc([]const u8, table_info.columns.len) catch return EngineError.OutOfMemory;
                defer self.allocator.free(rls_col_names);
                for (table_info.columns, 0..) |col, ci| rls_col_names[ci] = col.name;
                try self.checkRlsWithCheck(arena, actual_table, rls_col_names, vals, .insert);
            }

            // Serialize the row (with MVCC header if in a transaction)
            const row_data = if (self.current_txn) |txn| blk: {
                const cid = self.tm.getCurrentCid(txn.xid) catch return EngineError.TransactionError;
                const header = TupleHeader.forInsert(txn.xid, cid);
                break :blk mvcc_mod.serializeVersionedRow(self.allocator, header, vals) catch return EngineError.OutOfMemory;
            } else serializeRow(self.allocator, vals) catch return EngineError.OutOfMemory;
            defer self.allocator.free(row_data);

            // Generate key: 8-byte big-endian u64 for lexicographic ordering
            var key_buf: [8]u8 = undefined;
            std.mem.writeInt(u64, &key_buf, next_key, .big);
            const key = self.allocator.dupe(u8, &key_buf) catch return EngineError.OutOfMemory;
            defer self.allocator.free(key);
            next_key += 1;

            // Acquire exclusive row lock for the new row
            if (self.current_txn) |txn| {
                const lock_target = LockTarget{
                    .table_page_id = table_info.data_root_page_id,
                    .row_key = next_key - 1,
                };
                self.lock_manager.acquireRowLock(txn.xid, lock_target, .exclusive) catch
                    return EngineError.LockConflict;
            }

            // Insert into B+Tree
            tree.insert(key, row_data) catch return EngineError.StorageError;

            // Update root page ID in case of B+Tree split
            if (tree.root_page_id != table_info.data_root_page_id) {
                self.updateTableRootPage(actual_table, tree.root_page_id) catch return EngineError.StorageError;
                table_info.data_root_page_id = tree.root_page_id;
            }

            // Maintain secondary indexes — handle conflicts if needed
            var insert_succeeded = true;
            self.insertIndexEntries(actual_table, &table_info, vals, &key_buf) catch |err| {
                if (err != error.UniqueConstraintViolation) {
                    return EngineError.StorageError;
                }

                insert_succeeded = false;

                // Unique constraint violation — handle ON CONFLICT clause
                if (values_node.on_conflict) |oc| {
                    // Remove the just-inserted row from the B+Tree
                    tree.delete(key) catch return EngineError.StorageError;

                    switch (oc.action) {
                        .nothing => {
                            // DO NOTHING: skip this row entirely
                            next_key -= 1;
                            continue;
                        },
                        .update => {
                            // Find the existing conflicting row key from the unique index.
                            const conflicting_key: []u8 = blk: {
                                for (table_info.indexes) |idx| {
                                    if (!idx.is_unique) continue;
                                    if (idx.column_index >= vals.len) continue;
                                    const idx_key = valueToIndexKey(self.allocator, vals[idx.column_index]) catch continue;
                                    defer self.allocator.free(idx_key);
                                    switch (idx.index_type) {
                                        .btree => {
                                            var idx_tree = BTree.init(self.pool, idx.root_page_id);
                                            if (idx_tree.get(self.allocator, idx_key) catch null) |existing| {
                                                break :blk existing;
                                            }
                                        },
                                        .hash => {
                                            var idx_hash = HashIndex.init(self.pool, idx.root_page_id);
                                            if (idx_hash.get(self.allocator, idx_key) catch null) |existing| {
                                                break :blk existing;
                                            }
                                        },
                                        else => {},
                                    }
                                }
                                return EngineError.StorageError;
                            };
                            defer self.allocator.free(conflicting_key);

                            // Read existing row from main table.
                            const existing_data = (tree.get(self.allocator, conflicting_key) catch
                                return EngineError.StorageError) orelse return EngineError.StorageError;
                            defer self.allocator.free(existing_data);

                            const existing_raw = if (isVersionedRowData(existing_data))
                                existing_data[mvcc_mod.MVCC_ROW_OVERHEAD..]
                            else
                                existing_data;

                            const existing_vals = deserializeRow(self.allocator, existing_raw) catch
                                return EngineError.StorageError;
                            defer {
                                for (existing_vals) |v| v.free(self.allocator);
                                self.allocator.free(existing_vals);
                            }

                            const n_cols = table_info.columns.len;

                            // Build column names for this table.
                            const upsert_col_names = self.allocator.alloc([]const u8, n_cols) catch
                                return EngineError.OutOfMemory;
                            defer self.allocator.free(upsert_col_names);
                            for (table_info.columns, 0..) |col, i| {
                                upsert_col_names[i] = col.name;
                            }

                            // Build "excluded.<col>" names for the combined evaluation row.
                            const excluded_names = self.allocator.alloc([]u8, n_cols) catch
                                return EngineError.OutOfMemory;
                            var excluded_inited: usize = 0;
                            defer {
                                for (excluded_names[0..excluded_inited]) |en| self.allocator.free(en);
                                self.allocator.free(excluded_names);
                            }
                            for (upsert_col_names, 0..) |cn, i| {
                                excluded_names[i] = std.fmt.allocPrint(self.allocator, "excluded.{s}", .{cn}) catch
                                    return EngineError.OutOfMemory;
                                excluded_inited += 1;
                            }

                            // Combined row: existing values first, then excluded values.
                            // EXCLUDED.col → new row value; col / table.col → existing row value.
                            const combined_cols = self.allocator.alloc([]const u8, n_cols * 2) catch
                                return EngineError.OutOfMemory;
                            defer self.allocator.free(combined_cols);
                            const combined_values = self.allocator.alloc(Value, n_cols * 2) catch
                                return EngineError.OutOfMemory;
                            defer self.allocator.free(combined_values);

                            for (0..n_cols) |i| {
                                combined_cols[i] = upsert_col_names[i];
                                combined_values[i] = if (i < existing_vals.len) existing_vals[i] else .null_value;
                                combined_cols[n_cols + i] = excluded_names[i];
                                combined_values[n_cols + i] = if (i < vals.len) vals[i] else .null_value;
                            }

                            var combined_row = Row{
                                .columns = combined_cols,
                                .values = combined_values,
                                .allocator = self.allocator,
                            };

                            // Start with a copy of the existing row, then apply SET assignments.
                            const updated_vals = self.allocator.alloc(Value, n_cols) catch
                                return EngineError.OutOfMemory;
                            var updated_inited: usize = 0;
                            defer {
                                for (updated_vals[0..updated_inited]) |v| v.free(self.allocator);
                                self.allocator.free(updated_vals);
                            }
                            for (existing_vals, 0..) |v, i| {
                                updated_vals[i] = v.dupe(self.allocator) catch return EngineError.OutOfMemory;
                                updated_inited += 1;
                            }

                            for (oc.assignments) |assign| {
                                const new_val = evalExpr(self.allocator, assign.value, &combined_row, null) catch continue;
                                var found_col = false;
                                for (upsert_col_names, 0..) |cn, ci| {
                                    if (std.ascii.eqlIgnoreCase(cn, assign.column)) {
                                        updated_vals[ci].free(self.allocator);
                                        updated_vals[ci] = new_val;
                                        combined_values[ci] = new_val;
                                        found_col = true;
                                        break;
                                    }
                                }
                                if (!found_col) new_val.free(self.allocator);
                            }

                            // Remove old index entries, update the row, re-insert index entries.
                            self.deleteIndexEntries(&table_info, existing_vals);
                            tree.delete(conflicting_key) catch return EngineError.StorageError;

                            const new_row_data = serializeRow(self.allocator, updated_vals) catch
                                return EngineError.OutOfMemory;
                            defer self.allocator.free(new_row_data);

                            tree.insert(conflicting_key, new_row_data) catch return EngineError.StorageError;

                            self.insertIndexEntries(actual_table, &table_info, updated_vals, conflicting_key) catch |ie| {
                                return if (ie == error.UniqueConstraintViolation)
                                    EngineError.UniqueConstraintViolation
                                else
                                    EngineError.StorageError;
                            };

                            next_key -= 1;
                            insert_succeeded = true;
                        },
                    }
                } else {
                    return EngineError.UniqueConstraintViolation;
                }
            };

            // For successful inserts (no conflict or conflict handled), add to collection and increment count
            if (insert_succeeded) {
                // Always collect row for RETURNING and trigger evaluation
                const row_copy = self.allocator.alloc(Value, vals.len) catch return EngineError.OutOfMemory;
                for (vals, 0..) |v, i| {
                    row_copy[i] = try v.dupe(self.allocator);
                }
                try inserted_rows.append(self.allocator, row_copy);

                rows_inserted += 1;
            }
        }

        // Track inserts for auto-vacuum
        if (rows_inserted > 0) {
            self.auto_vacuum.recordModification(actual_table, rows_inserted, 0, 0) catch {};
        }

        // Fire AFTER INSERT triggers (STATEMENT fires once, ROW fires per successfully inserted row)
        if (rows_inserted > 0) {
            // For ROW-level triggers with WHEN conditions that reference NEW, evaluate per-row
            const triggers_after = self.catalog.listTriggersForTable(
                self.allocator,
                actual_table,
                .insert,
                .after,
            ) catch null;
            defer if (triggers_after) |trigs| {
                for (trigs) |tri| tri.deinit();
                self.allocator.free(trigs);
            };

            if (triggers_after) |trigs| {
                var rows_that_pass: u64 = 0;
                var first_passing_idx: ?usize = null;

                // Check if any ROW-level trigger has a WHEN condition with NEW references
                for (trigs) |trigger| {
                    if (!trigger.enabled or trigger.level != .row) continue;
                    if (trigger.when_condition) |cond| {
                        if (containsIgnoreCaseSubstring(cond, "new.")) {
                            // Evaluate WHEN condition for each inserted row
                            rows_that_pass = 0;
                            first_passing_idx = null;
                            for (inserted_rows.items, 0..) |row, ri| {
                                const row_ctx: TriggerRowContext = .{
                                    .col_names = insert_col_names,
                                    .new_values = row,
                                    .old_values = null,
                                };
                                if (self.evaluateTriggerWhenCondition(cond, row_ctx)) {
                                    rows_that_pass += 1;
                                    if (first_passing_idx == null) first_passing_idx = ri;
                                }
                            }

                            // Call fireTriggers with only the count of passing rows
                            if (first_passing_idx) |fpi| {
                                if (rows_that_pass > 0) {
                                    const insert_ctx: TriggerRowContext = .{
                                        .col_names = insert_col_names,
                                        .new_values = inserted_rows.items[fpi],
                                        .old_values = null,
                                    };
                                    self.fireTriggers(actual_table, .insert, .after, rows_that_pass, insert_ctx, true, null);
                                }
                            }
                            break; // Only evaluate once
                        }
                    }
                }

                // If no ROW triggers with WHEN that filter, fire normally
                if (rows_that_pass == 0 and first_passing_idx == null) {
                    const insert_ctx: ?TriggerRowContext = if (inserted_rows.items.len > 0) .{
                        .col_names = insert_col_names,
                        .new_values = inserted_rows.items[0],
                        .old_values = null,
                    } else null;
                    self.fireTriggers(actual_table, .insert, .after, rows_inserted, insert_ctx, false, null);
                }
            } else {
                const insert_ctx: ?TriggerRowContext = if (inserted_rows.items.len > 0) .{
                    .col_names = insert_col_names,
                    .new_values = inserted_rows.items[0],
                    .old_values = null,
                } else null;
                self.fireTriggers(actual_table, .insert, .after, rows_inserted, insert_ctx, false, null);
            }
        }

        // Handle RETURNING clause
        if (values_node.returning) |returning_cols| {
            // Build column names for result set
            var result_col_names = std.ArrayListUnmanaged([]const u8){};
            var result_rows = std.ArrayListUnmanaged([]Value){};

            for (returning_cols) |ret_col| {
                switch (ret_col) {
                    .all_columns => {
                        // Add all table column names (dupe to avoid dangling pointers)
                        for (table_info.columns) |col| {
                            const name_copy = try self.allocator.dupe(u8, col.name);
                            try result_col_names.append(self.allocator, name_copy);
                        }
                        break; // all_columns should be alone
                    },
                    .expr => |e| {
                        // Use alias if provided, otherwise stringify the expression
                        // Dupe the column name to ensure it remains valid after table_info is freed
                        const col_name = e.alias orelse "?column?";
                        const name_copy = try self.allocator.dupe(u8, col_name);
                        try result_col_names.append(self.allocator, name_copy);
                    },
                    .table_all_columns => {
                        // For now, treat as all_columns (dupe to avoid dangling pointers)
                        for (table_info.columns) |col| {
                            const name_copy = try self.allocator.dupe(u8, col.name);
                            try result_col_names.append(self.allocator, name_copy);
                        }
                        break;
                    },
                }
            }

            // Build result rows by evaluating RETURNING expressions for each inserted row
            for (inserted_rows.items) |inserted_row| {
                var result_row = std.ArrayListUnmanaged(Value){};

                // Create a Row object for expression evaluation
                const col_names = try self.allocator.alloc([]const u8, table_info.columns.len);
                for (table_info.columns, 0..) |col, i| {
                    col_names[i] = col.name;
                }
                var input_row = Row{
                    .columns = col_names,
                    .values = inserted_row,
                    .allocator = self.allocator,
                };
                defer self.allocator.free(input_row.columns);

                for (returning_cols) |ret_col| {
                    switch (ret_col) {
                        .all_columns => {
                            // Return all columns
                            for (inserted_row) |val| {
                                try result_row.append(self.allocator, try val.dupe(self.allocator));
                            }
                            break;
                        },
                        .expr => |e| {
                            // Evaluate the expression
                            const val = evalExpr(self.allocator, e.value, &input_row, null) catch
                                return EngineError.ExecutionError;
                            try result_row.append(self.allocator, val);
                        },
                        .table_all_columns => {
                            // Return all columns
                            for (inserted_row) |val| {
                                try result_row.append(self.allocator, try val.dupe(self.allocator));
                            }
                            break;
                        },
                    }
                }

                try result_rows.append(self.allocator, try result_row.toOwnedSlice(self.allocator));
            }

            // Create MaterializedOp for RETURNING results
            const ops = try self.allocator.create(OperatorChain);
            ops.* = .{};
            const mat_op = try self.allocator.create(MaterializedOp);
            mat_op.* = MaterializedOp.init(
                self.allocator,
                try result_col_names.toOwnedSlice(self.allocator),
                try result_rows.toOwnedSlice(self.allocator),
            );
            ops.materialized = mat_op;

            return .{
                .rows = mat_op.iterator(),
                .rows_affected = rows_inserted,
                .message = "INSERT",
                ._ops = ops,
            };
        }

        return .{
            .rows_affected = rows_inserted,
            .message = "INSERT",
        };
    }

    /// Find the next available row key by seeking to the last entry in the B+Tree.
    /// Keys are 8-byte big-endian u64 for lexicographic ordering.
    fn findNextRowKey(self: *Database, tree: *BTree) !u64 {
        var cursor = btree_mod.Cursor.init(self.allocator, tree);
        defer cursor.deinit();

        // Seek to last key directly — O(log n) instead of scanning all rows
        try cursor.seekLast();
        if (try cursor.next()) |entry| {
            defer self.allocator.free(entry.key);
            defer self.allocator.free(entry.value);
            if (entry.key.len == 8) {
                return std.mem.readInt(u64, entry.key[0..8], .big) + 1;
            }
        }

        return 0;
    }

    /// Update a table's root page ID in the catalog after a B+Tree split.
    fn updateTableRootPage(self: *Database, table_name: []const u8, new_root: u32) !void {
        // Re-read the table info, update root, re-serialize and update
        var info = try self.catalog.getTable(table_name);
        defer info.deinit(self.allocator);

        const new_value = try catalog_mod.serializeTableFull(
            self.allocator,
            info.columns,
            info.table_constraints,
            info.indexes,
            new_root,
        );
        defer self.allocator.free(new_value);

        // Delete and re-insert in the schema B+Tree
        try self.catalog.tree.delete(table_name);
        try self.catalog.tree.insert(table_name, new_value);
    }

    /// Update an index's root page ID in the catalog after a B+Tree split.
    fn updateIndexRootPage(self: *Database, table_name: []const u8, col_name: []const u8, new_idx_root: u32) !void {
        var info = try self.catalog.getTable(table_name);
        defer info.deinit(self.allocator);

        // Build a mutable copy of indexes with updated root page
        const new_indexes = try self.allocator.alloc(catalog_mod.IndexInfo, info.indexes.len);
        defer self.allocator.free(new_indexes);
        for (info.indexes, 0..) |idx, i| {
            new_indexes[i] = idx;
            if (std.ascii.eqlIgnoreCase(idx.column_name, col_name)) {
                new_indexes[i].root_page_id = new_idx_root;
            }
        }

        const value = try catalog_mod.serializeTableFull(
            self.allocator,
            info.columns,
            info.table_constraints,
            new_indexes,
            info.data_root_page_id,
        );
        defer self.allocator.free(value);

        try self.catalog.tree.delete(table_name);
        try self.catalog.tree.insert(table_name, value);
    }

    // ── Index Maintenance ─────────────────────────────────────────────

    /// Insert index entries for all indexed columns of a newly inserted row.
    fn insertIndexEntries(self: *Database, table_name: []const u8, table_info: *const catalog_mod.TableInfo, vals: []const Value, row_key: []const u8) !void {
        for (table_info.indexes) |idx| {
            if (idx.column_index >= vals.len) continue;
            const idx_key = valueToIndexKey(self.allocator, vals[idx.column_index]) catch continue;
            defer self.allocator.free(idx_key);
            const idx_val = try self.allocator.dupe(u8, row_key);
            defer self.allocator.free(idx_val);

            // Dispatch based on index type
            switch (idx.index_type) {
                .btree => {
                    var idx_tree = BTree.init(self.pool, idx.root_page_id);

                    // Check UNIQUE constraint before inserting
                    if (idx.is_unique) {
                        const existing = idx_tree.get(self.allocator, idx_key) catch null;
                        if (existing) |val| {
                            self.allocator.free(val);
                            return error.UniqueConstraintViolation;
                        }
                    }

                    try idx_tree.insert(idx_key, idx_val);

                    if (idx_tree.root_page_id != idx.root_page_id) {
                        self.updateIndexRootPage(table_name, idx.column_name, idx_tree.root_page_id) catch {};
                    }
                },
                .hash => {
                    var idx_hash = HashIndex.init(self.pool, idx.root_page_id);

                    // Check UNIQUE constraint before inserting
                    if (idx.is_unique) {
                        if (try idx_hash.get(self.allocator, idx_key)) |existing| {
                            self.allocator.free(existing);
                            return error.UniqueConstraintViolation;
                        }
                    }

                    try idx_hash.insert(idx_key, idx_val);
                    // Hash index root page ID doesn't change (no rebalancing like B+Tree)
                },
                .gist, .gin => {
                    // GiST/GIN pages are initialized as B+Tree leaf pages at CREATE INDEX time,
                    // so we can use B+Tree semantics for DML until native GiST/GIN storage is integrated.
                    var idx_tree = BTree.init(self.pool, idx.root_page_id);
                    if (idx.is_unique) {
                        const existing = idx_tree.get(self.allocator, idx_key) catch null;
                        if (existing) |val| {
                            self.allocator.free(val);
                            return error.UniqueConstraintViolation;
                        }
                    }
                    try idx_tree.insert(idx_key, idx_val);
                    if (idx_tree.root_page_id != idx.root_page_id) {
                        self.updateIndexRootPage(table_name, idx.column_name, idx_tree.root_page_id) catch {};
                    }
                },
            }
        }
    }

    /// Remove index entries for all indexed columns of a row being deleted.
    fn deleteIndexEntries(self: *Database, table_info: *const catalog_mod.TableInfo, vals: []const Value) void {
        for (table_info.indexes) |idx| {
            if (idx.column_index >= vals.len) continue;
            const idx_key = valueToIndexKey(self.allocator, vals[idx.column_index]) catch continue;
            defer self.allocator.free(idx_key);

            // Dispatch based on index type
            switch (idx.index_type) {
                .btree => {
                    var idx_tree = BTree.init(self.pool, idx.root_page_id);
                    idx_tree.delete(idx_key) catch {};
                },
                .hash => {
                    var idx_hash = HashIndex.init(self.pool, idx.root_page_id);
                    idx_hash.delete(idx_key) catch {};
                },
                .gist, .gin => {
                    var idx_tree = BTree.init(self.pool, idx.root_page_id);
                    idx_tree.delete(idx_key) catch {};
                },
            }
        }
    }

    const TriggerRowContext = struct {
        col_names: []const []const u8,
        new_values: ?[]const Value = null,
        old_values: ?[]const Value = null,
    };

    /// Format a Value as a SQL literal string for substitution into WHEN conditions.
    fn valueToSqlLiteral(allocator: Allocator, val: Value) ![]u8 {
        return switch (val) {
            .null_value => allocator.dupe(u8, "NULL"),
            .boolean => |b| allocator.dupe(u8, if (b) "TRUE" else "FALSE"),
            .integer => |n| std.fmt.allocPrint(allocator, "{d}", .{n}),
            .real => |f| std.fmt.allocPrint(allocator, "{d}", .{f}),
            .text => |s| blk: {
                var buf = std.ArrayListUnmanaged(u8){};
                errdefer buf.deinit(allocator);
                try buf.append(allocator, '\'');
                for (s) |c| {
                    if (c == '\'') try buf.append(allocator, '\'');
                    try buf.append(allocator, c);
                }
                try buf.append(allocator, '\'');
                break :blk buf.toOwnedSlice(allocator);
            },
            .blob => |b| blk: {
                var hex = std.ArrayListUnmanaged(u8){};
                errdefer hex.deinit(allocator);
                try hex.appendSlice(allocator, "X'");
                for (b) |byte| {
                    try hex.writer(allocator).print("{x:0>2}", .{byte});
                }
                try hex.append(allocator, '\'');
                break :blk hex.toOwnedSlice(allocator);
            },
            .date => |d| std.fmt.allocPrint(allocator, "DATE '{d}'", .{d}),
            .time => |t| std.fmt.allocPrint(allocator, "TIME '{d}'", .{t}),
            .timestamp => |ts| std.fmt.allocPrint(allocator, "TIMESTAMP '{d}'", .{ts}),
            .interval => |i| std.fmt.allocPrint(allocator, "INTERVAL '{d} {d} {d}'", .{ i.months, i.days, i.micros }),
            .numeric => |n| executor_mod.formatNumeric(allocator, n),
            .uuid => |u| blk: {
                var buf = std.ArrayListUnmanaged(u8){};
                errdefer buf.deinit(allocator);
                try buf.appendSlice(allocator, "'");
                for (0..16) |i| {
                    if (i == 4 or i == 6 or i == 8 or i == 10) try buf.append(allocator, '-');
                    try buf.writer(allocator).print("{x:0>2}", .{u[i]});
                }
                try buf.append(allocator, '\'');
                break :blk buf.toOwnedSlice(allocator);
            },
            .array => allocator.dupe(u8, "ARRAY[]"), // Simplified: arrays to empty ARRAY[]
            .tsvector => |s| blk: {
                var buf = std.ArrayListUnmanaged(u8){};
                errdefer buf.deinit(allocator);
                try buf.append(allocator, '\'');
                for (s) |c| {
                    if (c == '\'') try buf.append(allocator, '\'');
                    try buf.append(allocator, c);
                }
                try buf.append(allocator, '\'');
                break :blk buf.toOwnedSlice(allocator);
            },
            .tsquery => |s| blk: {
                var buf = std.ArrayListUnmanaged(u8){};
                errdefer buf.deinit(allocator);
                try buf.append(allocator, '\'');
                for (s) |c| {
                    if (c == '\'') try buf.append(allocator, '\'');
                    try buf.append(allocator, c);
                }
                try buf.append(allocator, '\'');
                break :blk buf.toOwnedSlice(allocator);
            },
        };
    }

    /// Evaluate a WHEN condition for a specific row context (NEW/OLD values).
    /// Returns true if the condition is satisfied, false otherwise.
    /// If the condition references NEW/OLD, evaluates against the provided context.
    /// If the condition doesn't reference NEW/OLD, evaluates as a constant expression.
    fn evaluateTriggerWhenCondition(self: *Database, cond: []const u8, ctx: TriggerRowContext) bool {
        const has_row_ref = containsIgnoreCaseSubstring(cond, "new.") or
            containsIgnoreCaseSubstring(cond, "old.");

        if (has_row_ref) {
            const eval_cond = substituteRowRefs(self.allocator, cond, ctx) catch return false;
            defer self.allocator.free(eval_cond);

            const when_sql = std.fmt.allocPrint(self.allocator, "SELECT ({s})", .{eval_cond}) catch return false;
            defer self.allocator.free(when_sql);
            var cond_result = self.exec(when_sql) catch return false;
            defer cond_result.close(self.allocator);
            const is_truthy = blk: {
                if (cond_result.rows == null) break :blk false;
                const first_row = cond_result.rows.?.next() catch break :blk false;
                if (first_row == null) break :blk false;
                var row = first_row.?;
                defer row.deinit();
                if (row.values.len == 0) break :blk false;
                break :blk row.values[0].isTruthy();
            };
            return is_truthy;
        }

        // Evaluate condition as constant (no NEW/OLD references)
        const when_sql = std.fmt.allocPrint(self.allocator, "SELECT ({s})", .{cond}) catch return false;
        defer self.allocator.free(when_sql);
        var cond_result = self.exec(when_sql) catch return false;
        defer cond_result.close(self.allocator);
        const is_truthy = blk: {
            if (cond_result.rows == null) break :blk false;
            const first_row = cond_result.rows.?.next() catch break :blk false;
            if (first_row == null) break :blk false;
            var row = first_row.?;
            defer row.deinit();
            if (row.values.len == 0) break :blk false;
            break :blk row.values[0].isTruthy();
        };
        return is_truthy;
    }

    /// Substitute NEW.col and OLD.col references in a WHEN condition string with SQL literal values.
    fn substituteRowRefs(allocator: Allocator, cond: []const u8, ctx: TriggerRowContext) ![]u8 {
        var result = std.ArrayListUnmanaged(u8){};
        errdefer result.deinit(allocator);

        var i: usize = 0;
        while (i < cond.len) {
            // Check for NEW. or OLD. prefix (case-insensitive, need at least 4 chars)
            const has_new = i + 4 <= cond.len and std.ascii.eqlIgnoreCase(cond[i..][0..4], "new.");
            const has_old = i + 4 <= cond.len and std.ascii.eqlIgnoreCase(cond[i..][0..4], "old.");

            if (has_new or has_old) {
                const is_new = has_new;
                const values = if (is_new) ctx.new_values else ctx.old_values;

                // Find the identifier after NEW. or OLD.
                const name_start = i + 4;
                var name_end = name_start;
                while (name_end < cond.len and (std.ascii.isAlphanumeric(cond[name_end]) or cond[name_end] == '_')) {
                    name_end += 1;
                }

                if (name_end > name_start and values != null) {
                    const col_name = cond[name_start..name_end];
                    var col_idx: ?usize = null;
                    for (ctx.col_names, 0..) |cn, ci| {
                        if (std.ascii.eqlIgnoreCase(cn, col_name)) {
                            col_idx = ci;
                            break;
                        }
                    }
                    if (col_idx) |ci| {
                        if (ci < values.?.len) {
                            const lit = try valueToSqlLiteral(allocator, values.?[ci]);
                            defer allocator.free(lit);
                            try result.appendSlice(allocator, lit);
                            i = name_end;
                            continue;
                        }
                    }
                }
            }

            try result.append(allocator, cond[i]);
            i += 1;
        }

        return result.toOwnedSlice(allocator);
    }

    /// Fire all matching triggers for a table+event+timing combination.
    /// row_count: how many rows were affected (used for ROW-level vs STATEMENT-level firing).
    /// For STATEMENT-level triggers, fires exactly once regardless of row_count.
    /// For ROW-level triggers, fires row_count times (or 0 if row_count is 0).
    /// ctx: optional row context containing NEW/OLD values for WHEN condition evaluation.
    /// skip_when_eval: if true, skip WHEN condition evaluation (caller has pre-evaluated it).
    fn fireTriggers(
        self: *Database,
        table_name: []const u8,
        event: ast_mod.TriggerEvent,
        timing: ast_mod.TriggerTiming,
        row_count: u64,
        ctx: ?TriggerRowContext,
        skip_when_eval: bool,
        /// For UPDATE events: the columns actually being SET. null = all columns.
        updated_cols: ?[]const []const u8,
    ) void {
        const triggers = self.catalog.listTriggersForTable(
            self.allocator,
            table_name,
            event,
            timing,
        ) catch return;
        defer {
            for (triggers) |ti| ti.deinit();
            self.allocator.free(triggers);
        }

        for (triggers) |trigger| {
            if (!trigger.enabled) continue;

            // UPDATE OF column_list enforcement: only fire if an updated column matches.
            if (event == .update and trigger.update_columns.len > 0) {
                if (updated_cols) |cols| {
                    var matched = false;
                    for (trigger.update_columns) |tc| {
                        for (cols) |uc| {
                            if (std.ascii.eqlIgnoreCase(tc, uc)) {
                                matched = true;
                                break;
                            }
                        }
                        if (matched) break;
                    }
                    if (!matched) continue;
                }
                // updated_cols == null means "all columns" — fire regardless
            }

            // Evaluate WHEN condition if present (unless caller pre-evaluated it).
            if (!skip_when_eval and trigger.when_condition != null) {
                if (trigger.when_condition) |cond| {
                    const has_row_ref = containsIgnoreCaseSubstring(cond, "new.") or
                        containsIgnoreCaseSubstring(cond, "old.");

                    // Build the condition SQL to evaluate — substitute row refs if context available
                    const eval_cond: []const u8 = if (has_row_ref and ctx != null)
                        substituteRowRefs(self.allocator, cond, ctx.?) catch continue
                    else if (has_row_ref)
                        continue // No row context yet (e.g., BEFORE trigger) — always fire
                    else
                        self.allocator.dupe(u8, cond) catch continue;
                    defer self.allocator.free(eval_cond);

                    const when_sql = std.fmt.allocPrint(self.allocator, "SELECT ({s})", .{eval_cond}) catch continue;
                    defer self.allocator.free(when_sql);
                    var cond_result = self.exec(when_sql) catch continue;
                    defer cond_result.close(self.allocator);
                    const is_truthy = blk: {
                        if (cond_result.rows == null) break :blk false;
                        const first_row = cond_result.rows.?.next() catch break :blk false;
                        if (first_row == null) break :blk false;
                        var row = first_row.?;
                        defer row.deinit();
                        if (row.values.len == 0) break :blk false;
                        break :blk row.values[0].isTruthy();
                    };
                    if (!is_truthy) continue;
                }
            }

            const fire_count: u64 = switch (trigger.level) {
                .statement => 1,
                .row => if (row_count > 0) row_count else 1,
            };

            for (0..fire_count) |_| {
                var result = self.exec(trigger.body) catch continue;
                result.close(self.allocator);
            }
        }
    }

    /// Helper function: case-insensitive substring search.
    fn containsIgnoreCaseSubstring(haystack: []const u8, needle: []const u8) bool {
        if (needle.len > haystack.len) return false;
        var i: usize = 0;
        while (i + needle.len <= haystack.len) : (i += 1) {
            if (std.ascii.eqlIgnoreCase(haystack[i..][0..needle.len], needle)) return true;
        }
        return false;
    }

    // ── UPDATE execution ──────────────────────────────────────────────

    fn executeUpdate(self: *Database, arena: *AstArena, plan: LogicalPlan) EngineError!QueryResult {
        defer {
            arena.deinit();
            self.allocator.destroy(arena);
        }

        // Check if write operations are allowed (standby mode check)
        self.standby_coordinator.checkWriteAllowed() catch |err| {
            return switch (err) {
                StandbyCoordinator.Error.WriteOperationNotAllowed => EngineError.TransactionError,
                else => EngineError.ExecutionError,
            };
        };

        // Plan structure for UPDATE: Project(Filter(Scan)) or Project(Scan)
        // The Project node has columns with alias = column name to update
        // We need to: scan rows, evaluate WHERE, apply assignments, write back

        // Extract the update info from the plan tree
        var scan_table: []const u8 = "";
        var predicate: ?*const ast_mod.Expr = null;
        var assignments: []const PlanNode.ProjectColumn = &.{};

        // Walk the plan tree to extract components
        var current = plan.root;
        while (true) {
            switch (current.*) {
                .project => |p| {
                    assignments = p.columns;
                    current = p.input;
                },
                .filter => |f| {
                    predicate = f.predicate;
                    current = f.input;
                },
                .scan => |s| {
                    scan_table = s.table;
                    break;
                },
                else => return EngineError.ExecutionError,
            }
        }

        // Updatable view resolution
        var view_arena_storage: ?AstArena = null;
        var view_infra_storage: ?std.heap.ArenaAllocator = null;
        defer if (view_arena_storage) |*va| va.deinit();
        defer if (view_infra_storage) |*vi| vi.deinit();

        var view_check_where: ?*const ast_mod.Expr = null;
        var actual_table: []const u8 = scan_table;

        if (self.catalog.getTable(scan_table)) |ti| {
            ti.deinit(self.allocator);
        } else |_| {
            view_arena_storage = AstArena.init(self.allocator);
            view_infra_storage = std.heap.ArenaAllocator.init(self.allocator);
            if (self.resolveUpdatableView(
                &view_arena_storage.?,
                &view_infra_storage.?,
                scan_table,
            )) |uvi| {
                actual_table = uvi.base_table;
                // Merge view's WHERE with the UPDATE's predicate
                if (uvi.where_clause) |vw| {
                    if (predicate) |existing_pred| {
                        // AND them together
                        const combined = arena.create(ast_mod.Expr, .{ .binary_op = .{
                            .op = .@"and",
                            .left = vw,
                            .right = existing_pred,
                        } }) catch return EngineError.OutOfMemory;
                        predicate = combined;
                    } else {
                        predicate = vw;
                    }
                }
                if (uvi.check_option != 0 and uvi.where_clause != null) {
                    view_check_where = uvi.where_clause;
                }
            } else {
                return EngineError.TableNotFound;
            }
        }

        // Apply RLS USING filter for UPDATE
        if (try self.buildRlsUsingExpr(arena, actual_table, .update)) |rls_using| {
            if (predicate) |existing| {
                predicate = try arena.create(ast_mod.Expr, .{ .binary_op = .{
                    .op = .@"and",
                    .left = existing,
                    .right = rls_using,
                } });
            } else {
                predicate = rls_using;
            }
        }

        // Look up table
        var table_info = self.catalog.getTable(actual_table) catch return EngineError.TableNotFound;
        defer table_info.deinit(self.allocator);

        // Register SSI read+write for SERIALIZABLE transactions (UPDATE reads then writes)
        try self.ssiRegisterRead(table_info.data_root_page_id);
        try self.ssiRegisterWrite(table_info.data_root_page_id);

        var tree = BTree.init(self.pool, table_info.data_root_page_id);

        // Build column names
        const col_names = self.allocator.alloc([]const u8, table_info.columns.len) catch return EngineError.OutOfMemory;
        defer self.allocator.free(col_names);
        for (table_info.columns, 0..) |col, i| {
            col_names[i] = col.name;
        }

        // Build the list of column names being SET in this UPDATE (for UPDATE OF enforcement).
        var updated_col_names = std.ArrayListUnmanaged([]const u8){};
        defer updated_col_names.deinit(self.allocator);
        for (assignments) |asgn| {
            if (asgn.alias) |col| {
                updated_col_names.append(self.allocator, col) catch {};
            }
        }
        const updated_cols_slice: ?[]const []const u8 = if (updated_col_names.items.len > 0)
            updated_col_names.items
        else
            null;

        // Fire BEFORE UPDATE triggers (STATEMENT fires once, ROW fires per row to be updated)
        self.fireTriggers(actual_table, .update, .before, 1, null, false, updated_cols_slice);

        // Scan all rows, collect those matching predicate, update them
        var cursor = btree_mod.Cursor.init(self.allocator, &tree);
        defer cursor.deinit();
        cursor.seekFirst() catch return EngineError.StorageError;

        const UpdateEntry = struct { key: []u8, value: []u8, old_values: []Value, original_xmin: u32 };

        // Collect key-value pairs to update (can't modify B+Tree while iterating)
        var updates = std.ArrayListUnmanaged(UpdateEntry){};
        defer {
            for (updates.items) |item| {
                self.allocator.free(item.key);
                self.allocator.free(item.value);
                for (item.old_values) |v| v.free(self.allocator);
                self.allocator.free(item.old_values);
            }
            updates.deinit(self.allocator);
        }

        // Get MVCC context for visibility filtering (owned snapshot for RC)
        var mvcc_ctx = try self.getMvccContext();
        defer if (mvcc_ctx) |*ctx| {
            if (self.current_txn != null and self.current_txn.?.isolation == .read_committed) {
                ctx.snapshot.deinit();
            }
        };

        while (cursor.next() catch null) |entry| {
            defer self.allocator.free(entry.key);

            // Deserialize row (handle MVCC header if present)
            var values: []Value = undefined;
            var original_xmin: u32 = mvcc_mod.INVALID_XID;
            if (isVersionedRowData(entry.value)) {
                // MVCC row: check visibility first
                if (mvcc_ctx) |ctx| {
                    const hdr = TupleHeader.deserialize(entry.value[1..][0..mvcc_mod.TUPLE_HEADER_SIZE]);
                    original_xmin = hdr.xmin; // Save for later comparison after lock
                    if (!mvcc_mod.isTupleVisibleWithTm(hdr, ctx.snapshot, ctx.current_xid, ctx.current_cid, ctx.tm)) {
                        self.allocator.free(entry.value);
                        continue;
                    }
                    // Conflict detection: if row has xmax set by another active txn,
                    // that means a concurrent writer is modifying this row.
                    if (hdr.xmax != mvcc_mod.INVALID_XID and hdr.xmax != ctx.current_xid) {
                        if (self.tm.getState(hdr.xmax)) |state| {
                            if (state == .active) {
                                self.allocator.free(entry.value);
                                return EngineError.LockConflict;
                            }
                        }
                    }
                    // SERIALIZABLE: First-Committer-Wins rule
                    // If this row was modified by a transaction that committed after our snapshot,
                    // abort to prevent lost updates.
                    if (self.current_txn) |txn| {
                        if (txn.isolation == .serializable) {
                            // Check if row was created after our snapshot started
                            if (hdr.xmin >= ctx.snapshot.xmax and hdr.xmin != ctx.current_xid) {
                                self.allocator.free(entry.value);
                                return EngineError.SerializationFailure;
                            }
                            // Check if row was updated (xmax committed) after our snapshot
                            if (hdr.xmax != mvcc_mod.INVALID_XID and hdr.xmax != ctx.current_xid) {
                                if (hdr.xmax >= ctx.snapshot.xmax) {
                                    self.allocator.free(entry.value);
                                    return EngineError.SerializationFailure;
                                }
                                // Also check if xmax committed after we took our snapshot
                                if (ctx.tm) |tm| {
                                    if (tm.isCommitted(hdr.xmax)) {
                                        if (!ctx.snapshot.isVisible(hdr.xmax)) {
                                            self.allocator.free(entry.value);
                                            return EngineError.SerializationFailure;
                                        }
                                    }
                                }
                            }
                        }
                    }
                }
                values = executor_mod.deserializeRow(self.allocator, entry.value[mvcc_mod.MVCC_ROW_OVERHEAD..]) catch {
                    self.allocator.free(entry.value);
                    continue;
                };
            } else {
                values = executor_mod.deserializeRow(self.allocator, entry.value) catch {
                    self.allocator.free(entry.value);
                    continue;
                };
            }
            self.allocator.free(entry.value);

            var row = Row{
                .columns = col_names,
                .values = values,
                .allocator = self.allocator,
            };

            // Check predicate
            if (predicate) |pred| {
                const val = evalExpr(self.allocator, pred, &row, null) catch {
                    for (row.values) |v| v.free(self.allocator);
                    self.allocator.free(row.values);
                    continue;
                };
                defer val.free(self.allocator);
                if (!val.isTruthy()) {
                    for (row.values) |v| v.free(self.allocator);
                    self.allocator.free(row.values);
                    continue;
                }
            }

            // Acquire exclusive row lock for the row we're about to update
            if (self.current_txn) |txn| {
                const row_key = if (entry.key.len == 8)
                    std.mem.readInt(u64, entry.key[0..8], .big)
                else
                    0;
                const lock_target = LockTarget{
                    .table_page_id = table_info.data_root_page_id,
                    .row_key = row_key,
                };
                self.lock_manager.acquireRowLock(txn.xid, lock_target, .exclusive) catch {
                    for (row.values) |v| v.free(self.allocator);
                    self.allocator.free(row.values);
                    return EngineError.LockConflict;
                };
            }

            // Re-read the row after acquiring the lock to get fresh values
            // This prevents lost updates in READ COMMITTED where a concurrent transaction
            // could have committed changes between our initial read and lock acquisition.
            const fresh_value_bytes = tree.get(self.allocator, entry.key) catch |err| {
                for (row.values) |v| v.free(self.allocator);
                self.allocator.free(row.values);
                if (err == btree_mod.BTreeError.KeyNotFound) {
                    // Row was deleted by another transaction after we read it
                    continue;
                }
                return EngineError.StorageError;
            } orelse {
                // Row no longer exists (deleted concurrently)
                for (row.values) |v| v.free(self.allocator);
                self.allocator.free(row.values);
                continue;
            };
            defer self.allocator.free(fresh_value_bytes);

            // Deserialize the fresh row values
            var fresh_values: []Value = undefined;
            if (isVersionedRowData(fresh_value_bytes)) {
                // MVCC row: check visibility of the fresh version
                if (mvcc_ctx) |ctx| {
                    const fresh_hdr = TupleHeader.deserialize(fresh_value_bytes[1..][0..mvcc_mod.TUPLE_HEADER_SIZE]);
                    if (!mvcc_mod.isTupleVisibleWithTm(fresh_hdr, ctx.snapshot, ctx.current_xid, ctx.current_cid, ctx.tm)) {
                        // Row became invisible (e.g., updated by another transaction)
                        for (row.values) |v| v.free(self.allocator);
                        self.allocator.free(row.values);
                        continue;
                    }
                    // SERIALIZABLE: First-Committer-Wins check after lock acquisition
                    // If the row's xmin changed since our initial read, it means another
                    // transaction modified it. For SERIALIZABLE, this is a lost update.
                    if (self.current_txn) |txn| {
                        if (txn.isolation == .serializable) {
                            // Case 1: Original row was versioned, check if xmin changed
                            if (original_xmin != mvcc_mod.INVALID_XID and fresh_hdr.xmin != original_xmin) {
                                for (row.values) |v| v.free(self.allocator);
                                self.allocator.free(row.values);
                                return EngineError.SerializationFailure;
                            }
                            // Case 2: Original row was non-versioned, now it's versioned
                            // This means another transaction modified it first
                            if (original_xmin == mvcc_mod.INVALID_XID and fresh_hdr.xmin != ctx.current_xid) {
                                for (row.values) |v| v.free(self.allocator);
                                self.allocator.free(row.values);
                                return EngineError.SerializationFailure;
                            }
                        }
                    }
                }
                fresh_values = executor_mod.deserializeRow(self.allocator, fresh_value_bytes[mvcc_mod.MVCC_ROW_OVERHEAD..]) catch {
                    for (row.values) |v| v.free(self.allocator);
                    self.allocator.free(row.values);
                    continue;
                };
            } else {
                fresh_values = executor_mod.deserializeRow(self.allocator, fresh_value_bytes) catch {
                    for (row.values) |v| v.free(self.allocator);
                    self.allocator.free(row.values);
                    continue;
                };
            }

            // Free the old stale values and replace with fresh ones
            for (row.values) |v| v.free(self.allocator);
            self.allocator.free(row.values);
            row.values = fresh_values;

            // Save old values for index maintenance
            const old_values = self.allocator.alloc(Value, row.values.len) catch {
                for (row.values) |v| v.free(self.allocator);
                self.allocator.free(row.values);
                return EngineError.OutOfMemory;
            };
            for (row.values, 0..) |v, vi| {
                old_values[vi] = v.dupe(self.allocator) catch {
                    for (old_values[0..vi]) |ov| ov.free(self.allocator);
                    self.allocator.free(old_values);
                    for (row.values) |rv| rv.free(self.allocator);
                    self.allocator.free(row.values);
                    return EngineError.OutOfMemory;
                };
            }

            // Apply assignments
            for (assignments) |assign| {
                const new_val = evalExpr(self.allocator, assign.expr, &row, null) catch continue;
                // Find column index by alias (= column name)
                const col_name = assign.alias orelse {
                    new_val.free(self.allocator);
                    continue;
                };
                var found = false;
                for (col_names, 0..) |cn, ci| {
                    if (std.ascii.eqlIgnoreCase(cn, col_name)) {
                        row.values[ci].free(self.allocator);
                        row.values[ci] = new_val;
                        found = true;
                        break;
                    }
                }
                if (!found) new_val.free(self.allocator);
            }

            // Re-evaluate generated columns after applying SET assignments
            for (table_info.columns, 0..) |tc, ti| {
                if (!tc.flags.is_generated) continue;
                if (tc.generated_expr.len == 0) continue;
                const gen_val = self.evalGeneratedExpr(tc.generated_expr, &row) catch continue;
                row.values[ti].free(self.allocator);
                row.values[ti] = gen_val;
            }

            // Enforce column-level CHECK constraints on updated row
            {
                const has_any_check: bool = for (table_info.columns) |col| {
                    if (col.flags.has_check) break true;
                } else false;
                if (has_any_check) {
                    self.evalCheckConstraints(&table_info, col_names, row.values) catch |err| {
                        for (old_values) |ov| ov.free(self.allocator);
                        self.allocator.free(old_values);
                        for (row.values) |v| v.free(self.allocator);
                        self.allocator.free(row.values);
                        return err;
                    };
                }
            }

            // WITH CHECK OPTION: validate updated row still satisfies view's WHERE
            if (view_check_where) |where_expr| {
                if (!self.checkViewCondition(where_expr, col_names, row.values)) {
                    for (old_values) |ov| ov.free(self.allocator);
                    self.allocator.free(old_values);
                    for (row.values) |v| v.free(self.allocator);
                    self.allocator.free(row.values);
                    return EngineError.CheckOptionViolation;
                }
            }

            // Re-serialize (with MVCC header if in a transaction)
            const new_data = if (self.current_txn) |txn| blk: {
                const cid = self.tm.getCurrentCid(txn.xid) catch {
                    for (old_values) |ov| ov.free(self.allocator);
                    self.allocator.free(old_values);
                    for (row.values) |v| v.free(self.allocator);
                    self.allocator.free(row.values);
                    return EngineError.TransactionError;
                };
                const header = TupleHeader.forInsert(txn.xid, cid);
                break :blk mvcc_mod.serializeVersionedRow(self.allocator, header, row.values) catch {
                    for (old_values) |ov| ov.free(self.allocator);
                    self.allocator.free(old_values);
                    for (row.values) |v| v.free(self.allocator);
                    self.allocator.free(row.values);
                    return EngineError.OutOfMemory;
                };
            } else serializeRow(self.allocator, row.values) catch {
                for (old_values) |ov| ov.free(self.allocator);
                self.allocator.free(old_values);
                for (row.values) |v| v.free(self.allocator);
                self.allocator.free(row.values);
                return EngineError.OutOfMemory;
            };

            const key_copy = self.allocator.dupe(u8, entry.key) catch {
                self.allocator.free(new_data);
                for (old_values) |ov| ov.free(self.allocator);
                self.allocator.free(old_values);
                for (row.values) |v| v.free(self.allocator);
                self.allocator.free(row.values);
                return EngineError.OutOfMemory;
            };

            updates.append(self.allocator, .{ .key = key_copy, .value = new_data, .old_values = old_values, .original_xmin = original_xmin }) catch {
                self.allocator.free(key_copy);
                self.allocator.free(new_data);
                for (old_values) |ov| ov.free(self.allocator);
                self.allocator.free(old_values);
                for (row.values) |v| v.free(self.allocator);
                self.allocator.free(row.values);
                return EngineError.OutOfMemory;
            };

            for (row.values) |v| v.free(self.allocator);
            self.allocator.free(row.values);
        }

        // Apply updates (delete + re-insert) and maintain indexes
        const rows_updated = updates.items.len;
        for (updates.items) |item| {
            // Remove old index entries
            self.deleteIndexEntries(&table_info, item.old_values);

            tree.delete(item.key) catch {};
            tree.insert(item.key, item.value) catch {};

            // Add new index entries: deserialize new row values for index
            const idx_data = if (isVersionedRowData(item.value))
                item.value[mvcc_mod.MVCC_ROW_OVERHEAD..]
            else
                item.value;
            const new_values = executor_mod.deserializeRow(self.allocator, idx_data) catch continue;
            defer {
                for (new_values) |v| v.free(self.allocator);
                self.allocator.free(new_values);
            }
            self.insertIndexEntries(actual_table, &table_info, new_values, item.key) catch {};
        }

        // Update root page if needed
        if (tree.root_page_id != table_info.data_root_page_id) {
            self.updateTableRootPage(actual_table, tree.root_page_id) catch {};
        }

        // Track updates for auto-vacuum (each update creates a dead tuple)
        if (rows_updated > 0) {
            self.auto_vacuum.recordModification(actual_table, 0, @intCast(rows_updated), 0) catch {};
        }

        // Fire AFTER UPDATE triggers (STATEMENT fires once, ROW fires per successfully updated row)
        if (rows_updated > 0) {
            const triggers_after_upd = self.catalog.listTriggersForTable(
                self.allocator,
                actual_table,
                .update,
                .after,
            ) catch null;
            defer if (triggers_after_upd) |trigs| {
                for (trigs) |tri| tri.deinit();
                self.allocator.free(trigs);
            };

            var upd_when_evaluated = false;
            if (triggers_after_upd) |trigs| {
                for (trigs) |trigger| {
                    if (!trigger.enabled or trigger.level != .row) continue;
                    if (trigger.when_condition) |cond| {
                        const has_old = containsIgnoreCaseSubstring(cond, "old.");
                        const has_new = containsIgnoreCaseSubstring(cond, "new.");
                        if (has_old or has_new) {
                            // Per-row WHEN evaluation: evaluate condition for each updated row
                            var rows_that_pass: u64 = 0;
                            var first_passing_idx: ?usize = null;
                            var first_new_vals: ?[]Value = null;
                            defer if (first_new_vals) |vals| {
                                for (vals) |v| v.free(self.allocator);
                                self.allocator.free(vals);
                            };

                            for (updates.items, 0..) |upd, ri| {
                                const data = if (isVersionedRowData(upd.value))
                                    upd.value[mvcc_mod.MVCC_ROW_OVERHEAD..]
                                else
                                    upd.value;
                                const new_vals = executor_mod.deserializeRow(self.allocator, data) catch continue;
                                defer {
                                    if (first_passing_idx == null or first_passing_idx.? != ri) {
                                        for (new_vals) |v| v.free(self.allocator);
                                        self.allocator.free(new_vals);
                                    }
                                }
                                const row_ctx: TriggerRowContext = .{
                                    .col_names = col_names,
                                    .new_values = new_vals,
                                    .old_values = upd.old_values,
                                };
                                if (self.evaluateTriggerWhenCondition(cond, row_ctx)) {
                                    rows_that_pass += 1;
                                    if (first_passing_idx == null) {
                                        first_passing_idx = ri;
                                        first_new_vals = new_vals;
                                    }
                                }
                            }

                            if (first_passing_idx) |fpi| {
                                if (rows_that_pass > 0) {
                                    const upd_ctx: TriggerRowContext = .{
                                        .col_names = col_names,
                                        .new_values = first_new_vals,
                                        .old_values = updates.items[fpi].old_values,
                                    };
                                    self.fireTriggers(actual_table, .update, .after, rows_that_pass, upd_ctx, true, updated_cols_slice);
                                }
                            }
                            upd_when_evaluated = true;
                            break;
                        }
                    }
                }
            }

            if (!upd_when_evaluated) {
                var update_new_vals: ?[]Value = null;
                defer if (update_new_vals) |vals| {
                    for (vals) |v| v.free(self.allocator);
                    self.allocator.free(vals);
                };
                const update_ctx: ?TriggerRowContext = blk: {
                    if (updates.items.len > 0) {
                        const first_update = updates.items[0];
                        const idx_data_u = if (isVersionedRowData(first_update.value))
                            first_update.value[mvcc_mod.MVCC_ROW_OVERHEAD..]
                        else
                            first_update.value;
                        update_new_vals = executor_mod.deserializeRow(self.allocator, idx_data_u) catch break :blk null;
                        break :blk .{
                            .col_names = col_names,
                            .new_values = update_new_vals,
                            .old_values = first_update.old_values,
                        };
                    }
                    break :blk null;
                };
                self.fireTriggers(actual_table, .update, .after, @intCast(rows_updated), update_ctx, false, updated_cols_slice);
            }
        }

        // Handle RETURNING clause
        if (plan.returning) |returning_cols| {
            // Collect updated rows for RETURNING (from the updates collection)
            var result_col_names = std.ArrayListUnmanaged([]const u8){};
            var result_rows = std.ArrayListUnmanaged([]Value){};

            for (returning_cols) |ret_col| {
                switch (ret_col) {
                    .all_columns => {
                        // Add all table column names (dupe to avoid dangling pointers)
                        for (table_info.columns) |col| {
                            const name_copy = try self.allocator.dupe(u8, col.name);
                            try result_col_names.append(self.allocator, name_copy);
                        }
                        break;
                    },
                    .expr => |e| {
                        // Use alias if provided, otherwise stringify the expression
                        const col_name = e.alias orelse "?column?";
                        const name_copy = try self.allocator.dupe(u8, col_name);
                        try result_col_names.append(self.allocator, name_copy);
                    },
                    .table_all_columns => {
                        // For now, treat as all_columns (dupe to avoid dangling pointers)
                        for (table_info.columns) |col| {
                            const name_copy = try self.allocator.dupe(u8, col.name);
                            try result_col_names.append(self.allocator, name_copy);
                        }
                        break;
                    },
                }
            }

            // Build result rows by evaluating RETURNING expressions for each updated row
            // Note: We need to deserialize the updated rows from the updates collection
            for (updates.items) |item| {
                const idx_data = if (isVersionedRowData(item.value))
                    item.value[mvcc_mod.MVCC_ROW_OVERHEAD..]
                else
                    item.value;
                const new_values = executor_mod.deserializeRow(self.allocator, idx_data) catch continue;
                defer {
                    for (new_values) |v| v.free(self.allocator);
                    self.allocator.free(new_values);
                }

                var result_row = std.ArrayListUnmanaged(Value){};

                // Create a Row object for expression evaluation
                const ret_col_names = try self.allocator.alloc([]const u8, table_info.columns.len);
                for (table_info.columns, 0..) |col, i| {
                    ret_col_names[i] = col.name;
                }
                var input_row = Row{
                    .columns = ret_col_names,
                    .values = new_values,
                    .allocator = self.allocator,
                };
                defer self.allocator.free(input_row.columns);

                for (returning_cols) |ret_col| {
                    switch (ret_col) {
                        .all_columns => {
                            // Return all columns
                            for (new_values) |val| {
                                try result_row.append(self.allocator, try val.dupe(self.allocator));
                            }
                            break;
                        },
                        .expr => |e| {
                            // Evaluate the expression
                            const val = evalExpr(self.allocator, e.value, &input_row, null) catch
                                return EngineError.ExecutionError;
                            try result_row.append(self.allocator, val);
                        },
                        .table_all_columns => {
                            // Return all columns
                            for (new_values) |val| {
                                try result_row.append(self.allocator, try val.dupe(self.allocator));
                            }
                            break;
                        },
                    }
                }

                try result_rows.append(self.allocator, try result_row.toOwnedSlice(self.allocator));
            }

            // Create MaterializedOp for RETURNING results
            const ops = try self.allocator.create(OperatorChain);
            ops.* = .{};
            const mat_op = try self.allocator.create(MaterializedOp);
            mat_op.* = MaterializedOp.init(
                self.allocator,
                try result_col_names.toOwnedSlice(self.allocator),
                try result_rows.toOwnedSlice(self.allocator),
            );
            ops.materialized = mat_op;

            return .{
                .rows = mat_op.iterator(),
                .rows_affected = @intCast(rows_updated),
                .message = "UPDATE",
                ._ops = ops,
            };
        }

        return .{
            .rows_affected = @intCast(rows_updated),
            .message = "UPDATE",
        };
    }

    // ── DELETE execution ──────────────────────────────────────────────

    fn executeDelete(self: *Database, arena: *AstArena, plan: LogicalPlan) EngineError!QueryResult {
        defer {
            arena.deinit();
            self.allocator.destroy(arena);
        }

        // Check if write operations are allowed (standby mode check)
        self.standby_coordinator.checkWriteAllowed() catch |err| {
            return switch (err) {
                StandbyCoordinator.Error.WriteOperationNotAllowed => EngineError.TransactionError,
                else => EngineError.ExecutionError,
            };
        };

        // Plan structure for DELETE: Filter(Scan) or Scan
        var scan_table: []const u8 = "";
        var predicate: ?*const ast_mod.Expr = null;

        var current = plan.root;
        while (true) {
            switch (current.*) {
                .filter => |f| {
                    predicate = f.predicate;
                    current = f.input;
                },
                .scan => |s| {
                    scan_table = s.table;
                    break;
                },
                else => return EngineError.ExecutionError,
            }
        }

        // Updatable view resolution for DELETE
        var view_arena_storage: ?AstArena = null;
        var view_infra_storage: ?std.heap.ArenaAllocator = null;
        defer if (view_arena_storage) |*va| va.deinit();
        defer if (view_infra_storage) |*vi| vi.deinit();

        var actual_table: []const u8 = scan_table;

        if (self.catalog.getTable(scan_table)) |ti| {
            ti.deinit(self.allocator);
        } else |_| {
            view_arena_storage = AstArena.init(self.allocator);
            view_infra_storage = std.heap.ArenaAllocator.init(self.allocator);
            if (self.resolveUpdatableView(
                &view_arena_storage.?,
                &view_infra_storage.?,
                scan_table,
            )) |uvi| {
                actual_table = uvi.base_table;
                // Merge view's WHERE with the DELETE's predicate
                if (uvi.where_clause) |vw| {
                    if (predicate) |existing_pred| {
                        const combined = arena.create(ast_mod.Expr, .{ .binary_op = .{
                            .op = .@"and",
                            .left = vw,
                            .right = existing_pred,
                        } }) catch return EngineError.OutOfMemory;
                        predicate = combined;
                    } else {
                        predicate = vw;
                    }
                }
            } else {
                return EngineError.TableNotFound;
            }
        }

        // Apply RLS USING filter for DELETE
        if (try self.buildRlsUsingExpr(arena, actual_table, .delete)) |rls_using| {
            if (predicate) |existing| {
                predicate = try arena.create(ast_mod.Expr, .{ .binary_op = .{
                    .op = .@"and",
                    .left = existing,
                    .right = rls_using,
                } });
            } else {
                predicate = rls_using;
            }
        }

        var table_info = self.catalog.getTable(actual_table) catch return EngineError.TableNotFound;
        defer table_info.deinit(self.allocator);

        // Register SSI read+write for SERIALIZABLE transactions (DELETE reads then writes)
        try self.ssiRegisterRead(table_info.data_root_page_id);
        try self.ssiRegisterWrite(table_info.data_root_page_id);

        var tree = BTree.init(self.pool, table_info.data_root_page_id);

        const col_names = self.allocator.alloc([]const u8, table_info.columns.len) catch return EngineError.OutOfMemory;
        defer self.allocator.free(col_names);
        for (table_info.columns, 0..) |col, i| {
            col_names[i] = col.name;
        }

        // Fire BEFORE DELETE triggers (STATEMENT fires once, ROW fires per row to be deleted)
        self.fireTriggers(actual_table, .delete, .before, 1, null, false, null);

        var cursor = btree_mod.Cursor.init(self.allocator, &tree);
        defer cursor.deinit();
        cursor.seekFirst() catch return EngineError.StorageError;

        const DeleteEntry = struct { key: []u8, values: []Value };

        // Collect keys to delete (with row values for index maintenance)
        var deletes = std.ArrayListUnmanaged(DeleteEntry){};
        defer {
            for (deletes.items) |d| {
                self.allocator.free(d.key);
                for (d.values) |v| v.free(self.allocator);
                self.allocator.free(d.values);
            }
            deletes.deinit(self.allocator);
        }

        // Get MVCC context for visibility filtering (owned snapshot for RC)
        var mvcc_ctx_del = try self.getMvccContext();
        defer if (mvcc_ctx_del) |*ctx| {
            if (self.current_txn != null and self.current_txn.?.isolation == .read_committed) {
                ctx.snapshot.deinit();
            }
        };

        while (cursor.next() catch null) |entry| {
            // Deserialize row for predicate check and index maintenance
            var values: []Value = undefined;
            if (isVersionedRowData(entry.value)) {
                // MVCC row: check visibility first
                if (mvcc_ctx_del) |ctx| {
                    const hdr = TupleHeader.deserialize(entry.value[1..][0..mvcc_mod.TUPLE_HEADER_SIZE]);
                    if (!mvcc_mod.isTupleVisibleWithTm(hdr, ctx.snapshot, ctx.current_xid, ctx.current_cid, ctx.tm)) {
                        self.allocator.free(entry.value);
                        self.allocator.free(entry.key);
                        continue;
                    }
                    // Conflict detection: if row has xmax set by another active txn,
                    // that means a concurrent writer is modifying this row.
                    if (hdr.xmax != mvcc_mod.INVALID_XID and hdr.xmax != ctx.current_xid) {
                        if (self.tm.getState(hdr.xmax)) |state| {
                            if (state == .active) {
                                self.allocator.free(entry.value);
                                self.allocator.free(entry.key);
                                return EngineError.LockConflict;
                            }
                        }
                    }
                }
                values = executor_mod.deserializeRow(self.allocator, entry.value[mvcc_mod.MVCC_ROW_OVERHEAD..]) catch {
                    self.allocator.free(entry.value);
                    self.allocator.free(entry.key);
                    continue;
                };
            } else {
                values = executor_mod.deserializeRow(self.allocator, entry.value) catch {
                    self.allocator.free(entry.value);
                    self.allocator.free(entry.key);
                    continue;
                };
            }
            self.allocator.free(entry.value);

            if (predicate) |pred| {
                var row = Row{
                    .columns = col_names,
                    .values = values,
                    .allocator = self.allocator,
                };

                const val = evalExpr(self.allocator, pred, &row, null) catch {
                    for (values) |v| v.free(self.allocator);
                    self.allocator.free(values);
                    self.allocator.free(entry.key);
                    continue;
                };
                defer val.free(self.allocator);

                if (!val.isTruthy()) {
                    for (values) |v| v.free(self.allocator);
                    self.allocator.free(values);
                    self.allocator.free(entry.key);
                    continue;
                }
            }

            // Acquire exclusive row lock for the row we're about to delete
            if (self.current_txn) |txn| {
                const row_key = if (entry.key.len == 8)
                    std.mem.readInt(u64, entry.key[0..8], .big)
                else
                    0;
                const lock_target = LockTarget{
                    .table_page_id = table_info.data_root_page_id,
                    .row_key = row_key,
                };
                self.lock_manager.acquireRowLock(txn.xid, lock_target, .exclusive) catch {
                    for (values) |v| v.free(self.allocator);
                    self.allocator.free(values);
                    self.allocator.free(entry.key);
                    return EngineError.LockConflict;
                };
            }

            // Mark for deletion (keep values for index maintenance)
            deletes.append(self.allocator, .{ .key = entry.key, .values = values }) catch {
                for (values) |v| v.free(self.allocator);
                self.allocator.free(values);
                self.allocator.free(entry.key);
                continue;
            };
        }

        const rows_deleted = deletes.items.len;
        for (deletes.items) |d| {
            // Remove index entries before deleting the row
            self.deleteIndexEntries(&table_info, d.values);
            tree.delete(d.key) catch {};
        }

        if (tree.root_page_id != table_info.data_root_page_id) {
            self.updateTableRootPage(actual_table, tree.root_page_id) catch {};
        }

        // Track deletes for auto-vacuum (each delete creates a dead tuple)
        if (rows_deleted > 0) {
            self.auto_vacuum.recordModification(actual_table, 0, 0, @intCast(rows_deleted)) catch {};
        }

        // Fire AFTER DELETE triggers (STATEMENT fires once, ROW fires per successfully deleted row)
        if (rows_deleted > 0) {
            const triggers_after_del = self.catalog.listTriggersForTable(
                self.allocator,
                actual_table,
                .delete,
                .after,
            ) catch null;
            defer if (triggers_after_del) |trigs| {
                for (trigs) |tri| tri.deinit();
                self.allocator.free(trigs);
            };

            var del_when_evaluated = false;
            if (triggers_after_del) |trigs| {
                for (trigs) |trigger| {
                    if (!trigger.enabled or trigger.level != .row) continue;
                    if (trigger.when_condition) |cond| {
                        if (containsIgnoreCaseSubstring(cond, "old.")) {
                            // Evaluate WHEN condition per deleted row
                            var rows_that_pass: u64 = 0;
                            var first_passing_idx: ?usize = null;
                            for (deletes.items, 0..) |d, ri| {
                                const row_ctx: TriggerRowContext = .{
                                    .col_names = col_names,
                                    .new_values = null,
                                    .old_values = d.values,
                                };
                                if (self.evaluateTriggerWhenCondition(cond, row_ctx)) {
                                    rows_that_pass += 1;
                                    if (first_passing_idx == null) first_passing_idx = ri;
                                }
                            }
                            if (first_passing_idx) |fpi| {
                                if (rows_that_pass > 0) {
                                    const del_ctx: TriggerRowContext = .{
                                        .col_names = col_names,
                                        .new_values = null,
                                        .old_values = deletes.items[fpi].values,
                                    };
                                    self.fireTriggers(actual_table, .delete, .after, rows_that_pass, del_ctx, true, null);
                                }
                            }
                            del_when_evaluated = true;
                            break;
                        }
                    }
                }
            }

            if (!del_when_evaluated) {
                const del_ctx: ?TriggerRowContext = if (deletes.items.len > 0) .{
                    .col_names = col_names,
                    .new_values = null,
                    .old_values = deletes.items[0].values,
                } else null;
                self.fireTriggers(actual_table, .delete, .after, @intCast(rows_deleted), del_ctx, false, null);
            }
        }

        // Handle RETURNING clause
        if (plan.returning) |returning_cols| {
            // Collect deleted rows for RETURNING (from the deletes collection)
            var result_col_names = std.ArrayListUnmanaged([]const u8){};
            var result_rows = std.ArrayListUnmanaged([]Value){};

            for (returning_cols) |ret_col| {
                switch (ret_col) {
                    .all_columns => {
                        // Add all table column names (dupe to avoid dangling pointers)
                        for (table_info.columns) |col| {
                            const name_copy = try self.allocator.dupe(u8, col.name);
                            try result_col_names.append(self.allocator, name_copy);
                        }
                        break;
                    },
                    .expr => |e| {
                        // Use alias if provided, otherwise stringify the expression
                        const col_name = e.alias orelse "?column?";
                        const name_copy = try self.allocator.dupe(u8, col_name);
                        try result_col_names.append(self.allocator, name_copy);
                    },
                    .table_all_columns => {
                        // For now, treat as all_columns (dupe to avoid dangling pointers)
                        for (table_info.columns) |col| {
                            const name_copy = try self.allocator.dupe(u8, col.name);
                            try result_col_names.append(self.allocator, name_copy);
                        }
                        break;
                    },
                }
            }

            // Build result rows by evaluating RETURNING expressions for each deleted row
            for (deletes.items) |d| {
                var result_row = std.ArrayListUnmanaged(Value){};

                // Create a Row object for expression evaluation
                const ret_col_names = try self.allocator.alloc([]const u8, table_info.columns.len);
                for (table_info.columns, 0..) |col, i| {
                    ret_col_names[i] = col.name;
                }
                var input_row = Row{
                    .columns = ret_col_names,
                    .values = d.values,
                    .allocator = self.allocator,
                };
                defer self.allocator.free(input_row.columns);

                for (returning_cols) |ret_col| {
                    switch (ret_col) {
                        .all_columns => {
                            // Return all columns
                            for (d.values) |val| {
                                try result_row.append(self.allocator, try val.dupe(self.allocator));
                            }
                            break;
                        },
                        .expr => |e| {
                            // Evaluate the expression
                            const val = evalExpr(self.allocator, e.value, &input_row, null) catch
                                return EngineError.ExecutionError;
                            try result_row.append(self.allocator, val);
                        },
                        .table_all_columns => {
                            // Return all columns
                            for (d.values) |val| {
                                try result_row.append(self.allocator, try val.dupe(self.allocator));
                            }
                            break;
                        },
                    }
                }

                try result_rows.append(self.allocator, try result_row.toOwnedSlice(self.allocator));
            }

            // Create MaterializedOp for RETURNING results
            const ops = try self.allocator.create(OperatorChain);
            ops.* = .{};
            const mat_op = try self.allocator.create(MaterializedOp);
            mat_op.* = MaterializedOp.init(
                self.allocator,
                try result_col_names.toOwnedSlice(self.allocator),
                try result_rows.toOwnedSlice(self.allocator),
            );
            ops.materialized = mat_op;

            return .{
                .rows = mat_op.iterator(),
                .rows_affected = @intCast(rows_deleted),
                .message = "DELETE",
                ._ops = ops,
            };
        }

        return .{
            .rows_affected = @intCast(rows_deleted),
            .message = "DELETE",
        };
    }

    // ── MERGE execution ──────────────────────────────────────────────

    /// Execute a MERGE statement.
    /// MERGE INTO target USING source ON condition
    ///   WHEN MATCHED THEN UPDATE/DELETE
    ///   WHEN NOT MATCHED THEN INSERT
    ///   WHEN NOT MATCHED BY SOURCE THEN UPDATE/DELETE
    /// NOTE: Ownership of arena is NOT transferred — calling code (execSQL) frees it.
    fn executeMerge(self: *Database, arena: *AstArena, merge: *const ast_mod.MergeStmt) EngineError!QueryResult {
        _ = arena; // Arena is owned by caller (execSQL)

        self.standby_coordinator.checkWriteAllowed() catch |err| {
            return switch (err) {
                StandbyCoordinator.Error.WriteOperationNotAllowed => EngineError.TransactionError,
                else => EngineError.ExecutionError,
            };
        };

        const implicit_txn = self.current_txn == null;
        if (implicit_txn) {
            try self.beginTransaction(.read_committed);
        }
        errdefer {
            if (implicit_txn) {
                self.rollbackTransaction() catch {};
            }
        }

        var target_info = self.catalog.getTable(merge.target) catch return EngineError.TableNotFound;
        defer target_info.deinit(self.allocator);

        const tgt_alias = merge.target_alias orelse merge.target;
        const tgt_cnt = target_info.columns.len;

        // Build target column names ("tgt_alias.colname")
        const tgt_col_names = self.allocator.alloc([]const u8, tgt_cnt) catch return EngineError.OutOfMemory;
        defer {
            for (tgt_col_names) |n| self.allocator.free(n);
            self.allocator.free(tgt_col_names);
        }
        for (target_info.columns, 0..) |col, i| {
            tgt_col_names[i] = std.fmt.allocPrint(self.allocator, "{s}.{s}", .{ tgt_alias, col.name }) catch
                return EngineError.OutOfMemory;
        }

        // Collect source row values and column names. Each element is an owned []Value slice.
        var source_row_vals_list = std.ArrayListUnmanaged([]Value){};
        defer {
            for (source_row_vals_list.items) |vals| {
                for (vals) |v| v.free(self.allocator);
                self.allocator.free(vals);
            }
            source_row_vals_list.deinit(self.allocator);
        }
        var src_col_names: [][]const u8 = &.{};
        var src_cnt: usize = 0;

        // Two paths: table source vs subquery source
        switch (merge.source) {
            .table => |t| {
                var source_info = self.catalog.getTable(t.name) catch return EngineError.TableNotFound;
                defer source_info.deinit(self.allocator);

                const src_alias = t.alias orelse t.name;
                src_cnt = source_info.columns.len;

                // Pre-build qualified column name arrays ("alias.colname")
                const sc_names = self.allocator.alloc([]const u8, src_cnt) catch return EngineError.OutOfMemory;
                for (source_info.columns, 0..) |col, i| {
                    sc_names[i] = std.fmt.allocPrint(self.allocator, "{s}.{s}", .{ src_alias, col.name }) catch {
                        for (sc_names[0..i]) |n| self.allocator.free(n);
                        self.allocator.free(sc_names);
                        return EngineError.OutOfMemory;
                    };
                }
                src_col_names = sc_names;

                // Collect source rows from B+tree
                var src_tree = BTree.init(self.pool, source_info.data_root_page_id);
                var src_cursor = btree_mod.Cursor.init(self.allocator, &src_tree);
                defer src_cursor.deinit();
                src_cursor.seekFirst() catch return EngineError.StorageError;

                while (src_cursor.next() catch null) |entry| {
                    defer self.allocator.free(entry.key);
                    defer self.allocator.free(entry.value);

                    const src_raw_bytes = if (mvcc_mod.isVersionedRow(entry.value))
                        entry.value[mvcc_mod.MVCC_ROW_OVERHEAD..]
                    else
                        entry.value;
                    const raw_vals = deserializeRow(self.allocator, src_raw_bytes) catch return EngineError.ExecutionError;
                    defer {
                        for (raw_vals) |v| v.free(self.allocator);
                        self.allocator.free(raw_vals);
                    }

                    const cloned_vals = self.allocator.alloc(Value, src_cnt) catch return EngineError.OutOfMemory;
                    var cloned_inited: usize = 0;
                    errdefer {
                        for (cloned_vals[0..cloned_inited]) |v| v.free(self.allocator);
                        self.allocator.free(cloned_vals);
                    }
                    for (raw_vals, 0..) |v, i| {
                        cloned_vals[i] = v.dupe(self.allocator) catch return EngineError.OutOfMemory;
                        cloned_inited += 1;
                    }
                    source_row_vals_list.append(self.allocator, cloned_vals) catch return EngineError.OutOfMemory;
                }
            },
            .subquery => |sub| {
                // Execute the subquery and collect rows
                const sub_arena = self.allocator.create(AstArena) catch return EngineError.OutOfMemory;
                sub_arena.* = AstArena.init(self.allocator);
                defer {
                    sub_arena.deinit();
                    self.allocator.destroy(sub_arena);
                }

                const sub_stmt = ast_mod.Stmt{ .select = sub.select.* };
                const provider = self.schemaProvider();
                var sub_plnr = Planner.init(sub_arena, provider);
                const sub_plan = sub_plnr.plan(sub_stmt) catch return EngineError.PlanError;

                var sub_opt = Optimizer.init(sub_arena);
                const sub_optimized = sub_opt.optimize(sub_plan) catch return EngineError.PlanError;

                const sub_ops = self.allocator.create(OperatorChain) catch return EngineError.OutOfMemory;
                sub_ops.* = .{};
                defer sub_ops.deinit(self.allocator);

                var sub_iter = self.buildIterator(sub_optimized.root, sub_ops) catch return EngineError.ExecutionError;
                defer sub_iter.close();

                var first_row = true;
                var sub_col_names_buf: [][]const u8 = undefined;

                while (sub_iter.next() catch return EngineError.ExecutionError) |row_data| {
                    var row = row_data;
                    defer row.deinit();

                    if (first_row) {
                        // Extract column names from first row and qualify with alias
                        src_cnt = row.columns.len;
                        sub_col_names_buf = self.allocator.alloc([]const u8, src_cnt) catch return EngineError.OutOfMemory;
                        for (row.columns, 0..) |col_name, i| {
                            sub_col_names_buf[i] = std.fmt.allocPrint(self.allocator, "{s}.{s}", .{ sub.alias, col_name }) catch {
                                for (sub_col_names_buf[0..i]) |n| self.allocator.free(n);
                                self.allocator.free(sub_col_names_buf);
                                return EngineError.OutOfMemory;
                            };
                        }
                        src_col_names = sub_col_names_buf;
                        first_row = false;
                    }

                    // Clone row values
                    const cloned_vals = self.allocator.alloc(Value, row.values.len) catch return EngineError.OutOfMemory;
                    var cloned_inited: usize = 0;
                    errdefer {
                        for (cloned_vals[0..cloned_inited]) |v| v.free(self.allocator);
                        self.allocator.free(cloned_vals);
                    }
                    for (row.values, 0..) |v, i| {
                        cloned_vals[i] = v.dupe(self.allocator) catch return EngineError.OutOfMemory;
                        cloned_inited += 1;
                    }
                    source_row_vals_list.append(self.allocator, cloned_vals) catch return EngineError.OutOfMemory;
                }
            },
        }

        // Clean up source column names after switch (works for both paths)
        defer {
            if (src_col_names.len > 0) {
                for (src_col_names) |n| self.allocator.free(n);
                self.allocator.free(src_col_names);
            }
        }

        // Combined column names for ON condition evaluation (tgt columns first, then src).
        // Borrows strings from tgt_col_names and src_col_names — only free the outer slice.
        const combined_col_names = self.allocator.alloc([]const u8, tgt_cnt + src_cnt) catch return EngineError.OutOfMemory;
        defer self.allocator.free(combined_col_names);
        for (tgt_col_names, 0..) |n, i| combined_col_names[i] = n;
        for (src_col_names, 0..) |n, i| combined_col_names[tgt_cnt + i] = n;

        try self.ssiRegisterRead(target_info.data_root_page_id);
        try self.ssiRegisterWrite(target_info.data_root_page_id);

        // Track matched target row keys for WHEN NOT MATCHED BY SOURCE processing.
        var target_matched = std.StringHashMapUnmanaged(void){};
        defer {
            var it = target_matched.keyIterator();
            while (it.next()) |k| self.allocator.free(k.*);
            target_matched.deinit(self.allocator);
        }

        var rows_affected: u64 = 0;
        var target_tree = BTree.init(self.pool, target_info.data_root_page_id);

        // Process each source row against all target rows.
        for (source_row_vals_list.items) |src_vals| {
            const src_row = Row{
                .columns = src_col_names, // borrowed — do NOT call deinit on src_row
                .values = src_vals, // borrowed — owned by source_row_vals_list
                .allocator = self.allocator,
            };

            var target_cursor = btree_mod.Cursor.init(self.allocator, &target_tree);
            defer target_cursor.deinit();
            target_cursor.seekFirst() catch return EngineError.StorageError;

            var found_match = false;
            var matched_key: ?[]u8 = null;
            // Saved target values for the matched row (used in WHEN MATCHED extra_cond).
            var matched_tgt_vals: ?[]Value = null;
            defer if (matched_tgt_vals) |mtv| {
                for (mtv) |v| v.free(self.allocator);
                self.allocator.free(mtv);
            };

            // Find matching target row using ON condition.
            while (target_cursor.next() catch null) |tgt_entry| {
                defer self.allocator.free(tgt_entry.key);
                defer self.allocator.free(tgt_entry.value);

                const tgt_raw_bytes = if (mvcc_mod.isVersionedRow(tgt_entry.value))
                    tgt_entry.value[mvcc_mod.MVCC_ROW_OVERHEAD..]
                else
                    tgt_entry.value;
                const tgt_vals = deserializeRow(self.allocator, tgt_raw_bytes) catch return EngineError.ExecutionError;
                defer {
                    for (tgt_vals) |v| v.free(self.allocator);
                    self.allocator.free(tgt_vals);
                }

                // Build combined values array for ON evaluation.
                const combined_vals = self.allocator.alloc(Value, tgt_cnt + src_cnt) catch return EngineError.OutOfMemory;
                defer {
                    for (combined_vals) |v| v.free(self.allocator);
                    self.allocator.free(combined_vals);
                }
                for (tgt_vals, 0..) |v, i| {
                    combined_vals[i] = v.dupe(self.allocator) catch return EngineError.OutOfMemory;
                }
                for (src_vals, 0..) |v, i| {
                    combined_vals[tgt_cnt + i] = v.dupe(self.allocator) catch return EngineError.OutOfMemory;
                }

                const combined_row = Row{
                    .columns = combined_col_names,
                    .values = combined_vals,
                    .allocator = self.allocator,
                };
                // Do NOT call combined_row.deinit() — memory managed by defers above.

                const on_result = evalExpr(self.allocator, merge.on, &combined_row, null) catch
                    return EngineError.ExecutionError;
                defer on_result.free(self.allocator);

                if (on_result.isTruthy()) {
                    matched_key = self.allocator.dupe(u8, tgt_entry.key) catch return EngineError.OutOfMemory;
                    // Save target values for WHEN MATCHED extra_cond evaluation.
                    const saved_tgt = self.allocator.alloc(Value, tgt_cnt) catch return EngineError.OutOfMemory;
                    for (tgt_vals, 0..) |v, vi| {
                        saved_tgt[vi] = v.dupe(self.allocator) catch return EngineError.OutOfMemory;
                    }
                    matched_tgt_vals = saved_tgt;
                    found_match = true;
                    break;
                }
            }

            if (found_match) {
                const key = matched_key.?;
                defer self.allocator.free(key);

                const key_copy = self.allocator.dupe(u8, key) catch return EngineError.OutOfMemory;
                target_matched.put(self.allocator, key_copy, {}) catch {
                    self.allocator.free(key_copy);
                    return EngineError.OutOfMemory;
                };

                // Apply first matching WHEN MATCHED clause.
                for (merge.when_clauses) |clause| {
                    if (clause.condition != .matched) continue;

                    if (clause.extra_cond) |cond| {
                        // Build combined row for extra_cond (needs both target and source).
                        const combined_ec_vals = self.allocator.alloc(Value, tgt_cnt + src_cnt) catch return EngineError.OutOfMemory;
                        defer {
                            for (combined_ec_vals) |v| v.free(self.allocator);
                            self.allocator.free(combined_ec_vals);
                        }
                        const mtv = matched_tgt_vals.?;
                        for (mtv, 0..) |v, i| {
                            combined_ec_vals[i] = v.dupe(self.allocator) catch return EngineError.OutOfMemory;
                        }
                        for (src_vals, 0..) |v, i| {
                            combined_ec_vals[tgt_cnt + i] = v.dupe(self.allocator) catch return EngineError.OutOfMemory;
                        }
                        const combined_ec_row = Row{
                            .columns = combined_col_names,
                            .values = combined_ec_vals,
                            .allocator = self.allocator,
                        };
                        const cond_result = evalExpr(self.allocator, cond, &combined_ec_row, null) catch
                            return EngineError.ExecutionError;
                        defer cond_result.free(self.allocator);
                        if (!cond_result.isTruthy()) continue;
                    }

                    switch (clause.action) {
                        .delete => {
                            target_tree.delete(key) catch return EngineError.StorageError;
                            rows_affected += 1;
                        },
                        .update => |upd| {
                            // Read current target row.
                            var cur_cursor = btree_mod.Cursor.init(self.allocator, &target_tree);
                            defer cur_cursor.deinit();
                            cur_cursor.seek(key) catch return EngineError.StorageError;
                            const cur_entry = (cur_cursor.current() catch return EngineError.StorageError) orelse
                                return EngineError.ExecutionError;
                            defer self.allocator.free(cur_entry.key);
                            defer self.allocator.free(cur_entry.value);

                            const upd_raw_bytes = if (mvcc_mod.isVersionedRow(cur_entry.value))
                                cur_entry.value[mvcc_mod.MVCC_ROW_OVERHEAD..]
                            else
                                cur_entry.value;
                            const tgt_vals = deserializeRow(self.allocator, upd_raw_bytes) catch
                                return EngineError.ExecutionError;
                            defer {
                                for (tgt_vals) |v| v.free(self.allocator);
                                self.allocator.free(tgt_vals);
                            }

                            var updated = self.allocator.alloc(Value, tgt_vals.len) catch return EngineError.OutOfMemory;
                            var updated_inited: usize = 0;
                            errdefer {
                                for (updated[0..updated_inited]) |v| v.free(self.allocator);
                                self.allocator.free(updated);
                            }
                            for (tgt_vals, 0..) |v, vi| {
                                updated[vi] = v.dupe(self.allocator) catch return EngineError.OutOfMemory;
                                updated_inited += 1;
                            }
                            defer {
                                for (updated) |v| v.free(self.allocator);
                                self.allocator.free(updated);
                            }

                            for (upd.assignments) |assign| {
                                var col_idx: ?usize = null;
                                for (target_info.columns, 0..) |col, i| {
                                    if (std.ascii.eqlIgnoreCase(col.name, assign.column)) {
                                        col_idx = i;
                                        break;
                                    }
                                }
                                if (col_idx) |ci| {
                                    const new_val = evalExpr(self.allocator, assign.value, &src_row, null) catch
                                        return EngineError.ExecutionError;
                                    updated[ci].free(self.allocator);
                                    updated[ci] = new_val;
                                }
                            }

                            const new_data = if (self.current_txn) |txn| blk: {
                                const cid = self.tm.getCurrentCid(txn.xid) catch return EngineError.TransactionError;
                                const hdr = TupleHeader.forInsert(txn.xid, cid);
                                break :blk mvcc_mod.serializeVersionedRow(self.allocator, hdr, updated) catch return EngineError.OutOfMemory;
                            } else serializeRow(self.allocator, updated) catch return EngineError.OutOfMemory;
                            defer self.allocator.free(new_data);
                            target_tree.delete(key) catch return EngineError.StorageError;
                            target_tree.insert(key, new_data) catch return EngineError.StorageError;
                            rows_affected += 1;
                        },
                        .insert => {}, // INSERT is not valid for WHEN MATCHED
                    }
                    break;
                }
            } else {
                // Apply first matching WHEN NOT MATCHED clause.
                for (merge.when_clauses) |clause| {
                    if (clause.condition != .not_matched) continue;

                    if (clause.extra_cond) |cond| {
                        const cond_result = evalExpr(self.allocator, cond, &src_row, null) catch
                            return EngineError.ExecutionError;
                        defer cond_result.free(self.allocator);
                        if (!cond_result.isTruthy()) continue;
                    }

                    switch (clause.action) {
                        .insert => |ins| {
                            const next_key_num = self.findNextRowKey(&target_tree) catch return EngineError.StorageError;

                            var row_vals = std.ArrayListUnmanaged(Value){};
                            defer {
                                for (row_vals.items) |v| v.free(self.allocator);
                                row_vals.deinit(self.allocator);
                            }

                            if (ins.columns) |cols| {
                                // Create full row with NULLs, then fill in specified columns
                                try row_vals.ensureTotalCapacity(self.allocator, tgt_cnt);
                                for (0..tgt_cnt) |_| {
                                    row_vals.appendAssumeCapacity(.null_value);
                                }
                                for (cols, 0..) |col_name, i| {
                                    var col_idx: ?usize = null;
                                    for (target_info.columns, 0..) |col, j| {
                                        if (std.ascii.eqlIgnoreCase(col.name, col_name)) {
                                            col_idx = j;
                                            break;
                                        }
                                    }
                                    if (col_idx) |ci| {
                                        const val = evalExpr(self.allocator, ins.values[i], &src_row, null) catch
                                            return EngineError.ExecutionError;
                                        row_vals.items[ci].free(self.allocator);
                                        row_vals.items[ci] = val;
                                    }
                                }
                            } else {
                                // No columns specified - assume values are in column order
                                for (ins.values) |expr| {
                                    const val = evalExpr(self.allocator, expr, &src_row, null) catch
                                        return EngineError.ExecutionError;
                                    row_vals.append(self.allocator, val) catch return EngineError.OutOfMemory;
                                }
                            }

                            const row_data = if (self.current_txn) |txn| blk: {
                                const cid = self.tm.getCurrentCid(txn.xid) catch return EngineError.TransactionError;
                                const hdr = TupleHeader.forInsert(txn.xid, cid);
                                break :blk mvcc_mod.serializeVersionedRow(self.allocator, hdr, row_vals.items) catch return EngineError.OutOfMemory;
                            } else serializeRow(self.allocator, row_vals.items) catch return EngineError.OutOfMemory;
                            defer self.allocator.free(row_data);

                            var key_buf: [8]u8 = undefined;
                            std.mem.writeInt(u64, &key_buf, next_key_num, .big);
                            const ins_key = self.allocator.dupe(u8, &key_buf) catch return EngineError.OutOfMemory;
                            defer self.allocator.free(ins_key);

                            target_tree.insert(ins_key, row_data) catch return EngineError.StorageError;
                            rows_affected += 1;
                        },
                        else => {}, // UPDATE/DELETE not valid for WHEN NOT MATCHED
                    }
                    break;
                }
            }
        }

        // Process WHEN NOT MATCHED BY SOURCE — target rows not matched by any source row.
        {
            var cursor = btree_mod.Cursor.init(self.allocator, &target_tree);
            defer cursor.deinit();
            cursor.seekFirst() catch return EngineError.StorageError;

            var unmatched_keys = std.ArrayListUnmanaged([]u8){};
            defer {
                for (unmatched_keys.items) |k| self.allocator.free(k);
                unmatched_keys.deinit(self.allocator);
            }

            while (cursor.next() catch null) |entry| {
                defer self.allocator.free(entry.key);
                defer self.allocator.free(entry.value);
                if (!target_matched.contains(entry.key)) {
                    const k_copy = self.allocator.dupe(u8, entry.key) catch return EngineError.OutOfMemory;
                    unmatched_keys.append(self.allocator, k_copy) catch {
                        self.allocator.free(k_copy);
                        return EngineError.OutOfMemory;
                    };
                }
            }

            for (unmatched_keys.items) |key| {
                for (merge.when_clauses) |clause| {
                    if (clause.condition != .not_matched_source) continue;
                    if (clause.extra_cond) |cond| {
                        // Evaluate AND condition using only the target row — no source row for unmatched.
                        var ec_cursor = btree_mod.Cursor.init(self.allocator, &target_tree);
                        defer ec_cursor.deinit();
                        ec_cursor.seek(key) catch return EngineError.StorageError;
                        const ec_entry = (ec_cursor.current() catch return EngineError.StorageError) orelse
                            return EngineError.ExecutionError;
                        defer self.allocator.free(ec_entry.key);
                        defer self.allocator.free(ec_entry.value);
                        const ec_raw = if (mvcc_mod.isVersionedRow(ec_entry.value))
                            ec_entry.value[mvcc_mod.MVCC_ROW_OVERHEAD..]
                        else
                            ec_entry.value;
                        const ec_tgt_vals = deserializeRow(self.allocator, ec_raw) catch
                            return EngineError.ExecutionError;
                        defer {
                            for (ec_tgt_vals) |v| v.free(self.allocator);
                            self.allocator.free(ec_tgt_vals);
                        }
                        // Use unqualified column names so bare references (e.g. "score") resolve.
                        // getQualifiedColumn falls back to getColumn, so qualified refs also work.
                        const ec_col_names = self.allocator.alloc([]const u8, tgt_cnt) catch return EngineError.OutOfMemory;
                        defer self.allocator.free(ec_col_names);
                        for (target_info.columns, 0..) |col, ci| ec_col_names[ci] = col.name;
                        const ec_row = Row{
                            .columns = ec_col_names,
                            .values = ec_tgt_vals,
                            .allocator = self.allocator,
                        };
                        const cond_result = evalExpr(self.allocator, cond, &ec_row, null) catch
                            return EngineError.ExecutionError;
                        defer cond_result.free(self.allocator);
                        if (!cond_result.isTruthy()) continue;
                    }

                    switch (clause.action) {
                        .delete => {
                            target_tree.delete(key) catch return EngineError.StorageError;
                            rows_affected += 1;
                        },
                        .update => |upd| {
                            // Read current target row for this unmatched key.
                            var upd_cursor = btree_mod.Cursor.init(self.allocator, &target_tree);
                            defer upd_cursor.deinit();
                            upd_cursor.seek(key) catch return EngineError.StorageError;
                            const upd_entry = (upd_cursor.current() catch return EngineError.StorageError) orelse
                                return EngineError.ExecutionError;
                            defer self.allocator.free(upd_entry.key);
                            defer self.allocator.free(upd_entry.value);

                            const upd_raw = if (mvcc_mod.isVersionedRow(upd_entry.value))
                                upd_entry.value[mvcc_mod.MVCC_ROW_OVERHEAD..]
                            else
                                upd_entry.value;
                            const upd_tgt_vals = deserializeRow(self.allocator, upd_raw) catch
                                return EngineError.ExecutionError;
                            defer {
                                for (upd_tgt_vals) |v| v.free(self.allocator);
                                self.allocator.free(upd_tgt_vals);
                            }

                            var updated = self.allocator.alloc(Value, upd_tgt_vals.len) catch return EngineError.OutOfMemory;
                            var updated_inited: usize = 0;
                            errdefer {
                                for (updated[0..updated_inited]) |v| v.free(self.allocator);
                                self.allocator.free(updated);
                            }
                            for (upd_tgt_vals, 0..) |v, vi| {
                                updated[vi] = v.dupe(self.allocator) catch return EngineError.OutOfMemory;
                                updated_inited += 1;
                            }
                            defer {
                                for (updated) |v| v.free(self.allocator);
                                self.allocator.free(updated);
                            }

                            // Evaluate assignments using target row as context.
                            // Use unqualified names so bare refs (e.g. "priority") resolve;
                            // getQualifiedColumn falls back to getColumn so qualified refs also work.
                            const upd_col_names = self.allocator.alloc([]const u8, tgt_cnt) catch return EngineError.OutOfMemory;
                            defer self.allocator.free(upd_col_names);
                            for (target_info.columns, 0..) |col, ci| upd_col_names[ci] = col.name;
                            const upd_row_ctx = Row{
                                .columns = upd_col_names,
                                .values = updated,
                                .allocator = self.allocator,
                            };

                            for (upd.assignments) |assign| {
                                var col_idx: ?usize = null;
                                for (target_info.columns, 0..) |col, i| {
                                    if (std.ascii.eqlIgnoreCase(col.name, assign.column)) {
                                        col_idx = i;
                                        break;
                                    }
                                }
                                if (col_idx) |ci| {
                                    const new_val = evalExpr(self.allocator, assign.value, &upd_row_ctx, null) catch
                                        return EngineError.ExecutionError;
                                    updated[ci].free(self.allocator);
                                    updated[ci] = new_val;
                                }
                            }

                            const new_data = if (self.current_txn) |txn| blk: {
                                const cid = self.tm.getCurrentCid(txn.xid) catch return EngineError.TransactionError;
                                const hdr = TupleHeader.forInsert(txn.xid, cid);
                                break :blk mvcc_mod.serializeVersionedRow(self.allocator, hdr, updated) catch return EngineError.OutOfMemory;
                            } else serializeRow(self.allocator, updated) catch return EngineError.OutOfMemory;
                            defer self.allocator.free(new_data);
                            target_tree.delete(key) catch return EngineError.StorageError;
                            target_tree.insert(key, new_data) catch return EngineError.StorageError;
                            rows_affected += 1;
                        },
                        .insert => {}, // not valid
                    }
                    break;
                }
            }
        }

        if (implicit_txn) {
            try self.commitTransaction();
        }
        self.commitWal() catch {};

        return .{ .rows_affected = rows_affected, .message = "MERGE" };
    }

    // ── COPY statement execution ──────────────────────────────────

    fn executeCopy(self: *Database, stmt: *const ast_mod.CopyStmt, alloc: Allocator) EngineError!QueryResult {
        return switch (stmt.direction) {
            .from => try self.executeCopyFrom(stmt, alloc),
            .to => try self.executeCopyTo(stmt),
        };
    }

    fn executeCopyFrom(self: *Database, stmt: *const ast_mod.CopyStmt, _: Allocator) EngineError!QueryResult {
        const table_name = switch (stmt.source) {
            .table => |n| n,
            .query => return EngineError.ExecutionError, // FROM requires table
        };

        // Open the file with std.fs.cwd()
        const file = std.fs.cwd().openFile(stmt.path, .{}) catch return EngineError.ExecutionError;
        defer file.close();

        // Use a temporary arena for CSV reading
        var arena = std.heap.ArenaAllocator.init(self.allocator);
        defer arena.deinit();
        const arena_alloc = arena.allocator();

        const content = file.readToEndAlloc(arena_alloc, 100 * 1024 * 1024) catch return EngineError.ExecutionError;

        var lines = std.mem.splitScalar(u8, content, '\n');
        var row_count: u64 = 0;
        var first = true;

        while (lines.next()) |line| {
            const trimmed = std.mem.trim(u8, line, "\r");
            if (trimmed.len == 0) continue;
            if (first) {
                first = false;
                if (stmt.options.header) continue; // skip header
            }

            // Split line by delimiter
            var fields = std.ArrayListUnmanaged([]const u8){};
            var iter = std.mem.splitScalar(u8, trimmed, stmt.options.delimiter);
            while (iter.next()) |field| {
                try fields.append(arena_alloc, field);
            }

            // Build INSERT SQL
            var sql_buf = std.ArrayListUnmanaged(u8){};
            defer sql_buf.deinit(arena_alloc);
            try sql_buf.appendSlice(arena_alloc, "INSERT INTO ");
            try sql_buf.appendSlice(arena_alloc, table_name);
            try sql_buf.appendSlice(arena_alloc, " VALUES (");
            for (fields.items, 0..) |field, i| {
                if (i > 0) try sql_buf.append(arena_alloc, ',');
                // Check if it looks like a number
                if (self.isNumericString(field)) {
                    try sql_buf.appendSlice(arena_alloc, field);
                } else {
                    // Quote as string, escape single quotes
                    try sql_buf.append(arena_alloc, '\'');
                    for (field) |c| {
                        if (c == '\'') try sql_buf.append(arena_alloc, '\'');
                        try sql_buf.append(arena_alloc, c);
                    }
                    try sql_buf.append(arena_alloc, '\'');
                }
            }
            try sql_buf.appendSlice(arena_alloc, ")");

            _ = try self.execSQL(sql_buf.items);
            row_count += 1;
        }

        return .{ .message = "COPY" };
    }

    fn executeCopyTo(self: *Database, stmt: *const ast_mod.CopyStmt) EngineError!QueryResult {
        // Get result set to export
        var result = switch (stmt.source) {
            .table => |n| blk: {
                var sql_buf = std.ArrayListUnmanaged(u8){};
                defer sql_buf.deinit(self.allocator);
                try sql_buf.appendSlice(self.allocator, "SELECT * FROM ");
                try sql_buf.appendSlice(self.allocator, n);
                break :blk try self.execSQL(sql_buf.items);
            },
            .query => |sel| blk: {
                // Re-execute the select via execSQL with the statement
                // We'll create a temporary AST and execute it
                var arena: ?*AstArena = self.allocator.create(AstArena) catch return EngineError.OutOfMemory;
                arena.?.* = AstArena.init(self.allocator);

                const provider = self.schemaProvider();
                var an = Analyzer.init(self.allocator, provider);
                defer an.deinit();

                const select_stmt = sel.*;
                an.analyze(.{ .select = select_stmt });
                if (an.hasErrors()) {
                    arena.?.deinit();
                    self.allocator.destroy(arena.?);
                    return EngineError.AnalysisError;
                }

                var plnr = Planner.init(arena.?, provider);
                const plan = plnr.plan(.{ .select = select_stmt }) catch {
                    arena.?.deinit();
                    self.allocator.destroy(arena.?);
                    return EngineError.PlanError;
                };

                var opt = Optimizer.init(arena.?);
                const optimized = opt.optimize(plan) catch {
                    arena.?.deinit();
                    self.allocator.destroy(arena.?);
                    return EngineError.PlanError;
                };

                const owned_arena = arena.?;
                arena = null;
                break :blk try self.executePlan(owned_arena, optimized);
            },
        };
        defer result.close(self.allocator);

        // Open/create output file
        const file = std.fs.cwd().createFile(stmt.path, .{}) catch return EngineError.ExecutionError;
        defer file.close();

        // Use ArrayListUnmanaged to collect output
        var output = std.ArrayListUnmanaged(u8){};
        defer output.deinit(self.allocator);

        // Collect all rows from result
        var row_count: u64 = 0;
        if (result.rows != null) {
            var col_names: ?[][]const u8 = null;
            var first_row = true;

            while (true) {
                const maybe_row = result.rows.?.next() catch return EngineError.ExecutionError;
                const row_ptr = maybe_row orelse break;
                var row = row_ptr;
                defer row.deinit();

                // Collect column names from first row
                if (first_row) {
                    col_names = self.allocator.alloc([]const u8, row.values.len) catch
                        return EngineError.OutOfMemory;
                    for (row.columns, 0..) |col, i| {
                        col_names.?[i] = col;
                    }

                    // Write header if requested
                    if (stmt.options.header) {
                        for (col_names.?, 0..) |col, i| {
                            if (i > 0) try output.append(self.allocator, stmt.options.delimiter);
                            try output.appendSlice(self.allocator, col);
                        }
                        try output.append(self.allocator, '\n');
                    }
                    first_row = false;
                }

                // Write data row
                for (row.values, 0..) |val, i| {
                    if (i > 0) try output.append(self.allocator, stmt.options.delimiter);
                    switch (val) {
                        .integer => |n| {
                            var buf: [32]u8 = undefined;
                            const str = std.fmt.bufPrint(&buf, "{d}", .{n}) catch "";
                            try output.appendSlice(self.allocator, str);
                        },
                        .real => |r| {
                            var buf: [32]u8 = undefined;
                            const str = std.fmt.bufPrint(&buf, "{d}", .{r}) catch "";
                            try output.appendSlice(self.allocator, str);
                        },
                        .text => |t| try output.appendSlice(self.allocator, t),
                        .null_value => {}, // empty field
                        else => {},
                    }
                }
                try output.append(self.allocator, '\n');
                row_count += 1;
            }

            if (col_names) |cn| self.allocator.free(cn);
        }

        // Write output to file
        file.writeAll(output.items) catch return EngineError.ExecutionError;

        return .{ .message = "COPY" };
    }

    fn isNumericString(self: *Database, s: []const u8) bool {
        _ = self;
        if (s.len == 0) return false;
        var i: usize = 0;
        if (s[i] == '-' or s[i] == '+') i += 1;
        var has_digit = false;
        var has_dot = false;
        while (i < s.len) : (i += 1) {
            if (std.ascii.isDigit(s[i])) {
                has_digit = true;
            } else if (s[i] == '.' and !has_dot) {
                has_dot = true;
            } else return false;
        }
        return has_digit;
    }

    // ── DDL execution ────────────────────────────────────────────────

    fn executeCreateTable(self: *Database, arena: *AstArena, plan: LogicalPlan) EngineError!QueryResult {
        defer {
            arena.deinit();
            self.allocator.destroy(arena);
        }

        // The original AST is in the plan as an Empty node with description.
        // We need to re-parse to get the CreateTableStmt, or we can store it differently.
        // For now, we'll use the description to identify it and use the analyzer's validated info.
        _ = plan;

        // This path should not normally be reached — DDL is handled before planning.
        return .{ .message = "OK" };
    }

    fn executeDropTable(self: *Database, arena: *AstArena, plan: LogicalPlan) EngineError!QueryResult {
        defer {
            arena.deinit();
            self.allocator.destroy(arena);
        }
        _ = plan;
        return .{ .message = "OK" };
    }

    fn executeAlterTable(self: *Database, stmt: *const ast_mod.AlterTableStmt) !void {
        switch (stmt.action) {
            .add_column => |ac| {
                // Convert ColumnDef to ColumnInfo
                var flags = catalog_mod.constraintFlagsFromAst(ac.col_def.constraints);

                // Handle SERIAL/BIGSERIAL
                if (ac.col_def.data_type) |dt| {
                    if (dt == .type_serial or dt == .type_bigserial) {
                        flags.autoincrement = true;
                        flags.not_null = true;
                    }
                }

                // Dupe the column name to persist it beyond the arena lifetime
                const col_name = try self.allocator.dupe(u8, ac.col_def.name);
                defer self.allocator.free(col_name);

                const col_info = catalog_mod.ColumnInfo{
                    .name = col_name,
                    .column_type = catalog_mod.columnTypeFromAst(ac.col_def.data_type),
                    .flags = flags,
                };

                // Extract default expression if present
                var default_expr: ?[]const u8 = null;
                for (ac.col_def.constraints) |constraint| {
                    switch (constraint) {
                        .default => |default_val| {
                            // Store the expression source text (if available)
                            // For now, we'll extract it from the parsed expression
                            if (default_val.* == .integer_literal) {
                                default_expr = try std.fmt.allocPrint(self.allocator, "{d}", .{default_val.integer_literal});
                            } else if (default_val.* == .string_literal) {
                                default_expr = try std.fmt.allocPrint(self.allocator, "'{s}'", .{default_val.string_literal});
                            }
                        },
                        else => {},
                    }
                }
                defer if (default_expr) |de| self.allocator.free(de);

                try self.catalog.addColumn(stmt.table_name, col_info, default_expr);
            },
            .drop_column => |dc| {
                try self.catalog.dropColumn(stmt.table_name, dc.name, dc.if_exists);
            },
            .rename_column => |rc| {
                try self.catalog.renameColumn(stmt.table_name, rc.old_name, rc.new_name);
            },
            .rename_to => |new_name| {
                try self.catalog.renameTable(stmt.table_name, new_name);
            },
            .alter_column => |ac| {
                try self.catalog.alterColumn(stmt.table_name, ac.col_name, ac.action, ac.default_sql);
            },
        }
    }

    fn ensureSubqueryEvaluator(self: *Database) void {
        if (self.catalog.subquery_evaluator != null) return;
        self.subquery_evaluator_vtable = .{
            .ptr = self,
            .eval_scalar_fn = &Database.sqEvalScalar,
            .eval_exists_fn = &Database.sqEvalExists,
            .eval_contains_fn = &Database.sqEvalContains,
        };
        self.catalog.subquery_evaluator = &self.subquery_evaluator_vtable;
    }

    fn sqEvalScalar(ptr: *anyopaque, allocator: Allocator, stmt: *const ast_mod.SelectStmt, outer_row: *const executor_mod.Row) executor_mod.EvalError!executor_mod.Value {
        const self: *Database = @ptrCast(@alignCast(ptr));
        return self.runSubqueryScalar(allocator, stmt, outer_row) catch return executor_mod.EvalError.UnsupportedExpression;
    }

    fn sqEvalExists(ptr: *anyopaque, allocator: Allocator, stmt: *const ast_mod.SelectStmt, outer_row: *const executor_mod.Row) executor_mod.EvalError!bool {
        const self: *Database = @ptrCast(@alignCast(ptr));
        return self.runSubqueryExists(allocator, stmt, outer_row) catch return executor_mod.EvalError.UnsupportedExpression;
    }

    fn sqEvalContains(ptr: *anyopaque, allocator: Allocator, stmt: *const ast_mod.SelectStmt, outer_row: *const executor_mod.Row, needle: executor_mod.Value) executor_mod.EvalError!bool {
        const self: *Database = @ptrCast(@alignCast(ptr));
        return self.runSubqueryContains(allocator, stmt, outer_row, needle) catch return executor_mod.EvalError.UnsupportedExpression;
    }

    fn runSubqueryScalar(self: *Database, allocator: Allocator, stmt: *const ast_mod.SelectStmt, outer_row: *const executor_mod.Row) !executor_mod.Value {
        var sq_arena = try self.allocator.create(AstArena);
        sq_arena.* = AstArena.init(self.allocator);
        defer {
            sq_arena.deinit();
            self.allocator.destroy(sq_arena);
        }

        const provider = self.schemaProvider();
        var plnr = Planner.init(sq_arena, provider);
        const plan = try plnr.plan(.{ .select = stmt.* });
        var opt = Optimizer.init(sq_arena);
        const optimized = try opt.optimize(plan);

        var ops = try self.allocator.create(OperatorChain);
        ops.* = .{};
        ops.outer_row = outer_row;
        defer ops.deinit(self.allocator); // deinit() calls destroy(self) internally

        var iter = try self.buildIterator(optimized.root, ops);
        defer iter.close();

        if (try iter.next()) |*result_row| {
            var rr = result_row.*;
            defer rr.deinit();
            if (rr.values.len > 0) {
                return rr.values[0].dupe(allocator);
            }
        }
        return .null_value;
    }

    fn runSubqueryExists(self: *Database, allocator: Allocator, stmt: *const ast_mod.SelectStmt, outer_row: *const executor_mod.Row) !bool {
        _ = allocator;
        var sq_arena = try self.allocator.create(AstArena);
        sq_arena.* = AstArena.init(self.allocator);
        defer {
            sq_arena.deinit();
            self.allocator.destroy(sq_arena);
        }

        const provider = self.schemaProvider();
        var plnr = Planner.init(sq_arena, provider);
        const plan = try plnr.plan(.{ .select = stmt.* });
        var opt = Optimizer.init(sq_arena);
        const optimized = try opt.optimize(plan);

        var ops = try self.allocator.create(OperatorChain);
        ops.* = .{};
        ops.outer_row = outer_row;
        defer ops.deinit(self.allocator); // deinit() calls destroy(self) internally

        var iter = try self.buildIterator(optimized.root, ops);
        defer iter.close();

        if (try iter.next()) |*rr| {
            @constCast(rr).deinit();
            return true;
        }
        return false;
    }

    fn runSubqueryContains(self: *Database, allocator: Allocator, stmt: *const ast_mod.SelectStmt, outer_row: *const executor_mod.Row, needle: executor_mod.Value) !bool {
        var sq_arena = try self.allocator.create(AstArena);
        sq_arena.* = AstArena.init(self.allocator);
        defer {
            sq_arena.deinit();
            self.allocator.destroy(sq_arena);
        }

        const provider = self.schemaProvider();
        var plnr = Planner.init(sq_arena, provider);
        const plan = try plnr.plan(.{ .select = stmt.* });
        var opt = Optimizer.init(sq_arena);
        const optimized = try opt.optimize(plan);

        var ops = try self.allocator.create(OperatorChain);
        ops.* = .{};
        ops.outer_row = outer_row;
        defer ops.deinit(self.allocator); // deinit() calls destroy(self) internally

        var iter = try self.buildIterator(optimized.root, ops);
        defer iter.close();

        while (try iter.next()) |*rr_ptr| {
            var rr = rr_ptr.*;
            defer rr.deinit();
            if (rr.values.len > 0) {
                const col_val = rr.values[0].dupe(allocator) catch break;
                defer col_val.free(allocator);
                if (needle.eql(col_val)) return true;
            }
        }
        return false;
    }

    /// Execute a full SQL statement including DDL. This is the primary entry point.
    pub fn execSQL(self: *Database, sql: []const u8) EngineError!QueryResult {
        // Reset schema arena from previous exec call
        _ = self.schema_arena.reset(.retain_capacity);
        // Set up subquery evaluation (lazy self-referential init)
        self.ensureSubqueryEvaluator();
        // Reflect the active explicit transaction's xid so txid_current() can
        // return the real value; autocommit statements have no explicit xid.
        self.catalog.current_xid = if (self.current_txn) |txn| txn.xid else mvcc_mod.INVALID_XID;

        // Parse first to determine statement type
        var arena: ?*AstArena = self.allocator.create(AstArena) catch return EngineError.OutOfMemory;
        arena.?.* = AstArena.init(self.allocator);
        errdefer if (arena) |a| {
            a.deinit();
            self.allocator.destroy(a);
        };

        var infra_alloc = std.heap.ArenaAllocator.init(self.allocator);
        defer infra_alloc.deinit();

        var p = Parser.init(infra_alloc.allocator(), sql, arena.?) catch return EngineError.ParseError;
        defer p.deinit();

        const maybe_stmt = p.parseStatement() catch return EngineError.ParseError;
        const stmt = maybe_stmt orelse return EngineError.ParseError;

        // Handle DDL directly (before analysis/planning)
        switch (stmt) {
            .create_table => |ct| {
                // Check if write operations are allowed (standby mode check)
                self.standby_coordinator.checkWriteAllowed() catch |err| {
                    arena.?.deinit();
                    self.allocator.destroy(arena.?);
                    arena = null; // Prevent errdefer from double-freeing
                    return switch (err) {
                        StandbyCoordinator.Error.WriteOperationNotAllowed => EngineError.TransactionError,
                        else => EngineError.ExecutionError,
                    };
                };

                // Handle CREATE TABLE AS SELECT
                if (ct.as_select != null) {
                    const result = self.executeCTAS(arena.?, &ct) catch |err| {
                        arena = null; // executeCTAS already freed the arena; prevent errdefer double-free
                        return switch (err) {
                            EngineError.TableAlreadyExists => EngineError.TableAlreadyExists,
                            EngineError.OutOfMemory => EngineError.OutOfMemory,
                            EngineError.TableNotFound => EngineError.TableNotFound,
                            else => EngineError.ExecutionError,
                        };
                    };
                    arena = null; // executeCTAS already freed the arena
                    return result;
                }

                self.catalog.createTableFromAst(&ct) catch |err| {
                    return switch (err) {
                        error.TableAlreadyExists => EngineError.TableAlreadyExists,
                        error.OutOfMemory => EngineError.OutOfMemory,
                        else => EngineError.StorageError,
                    };
                };
                arena.?.deinit();
                self.allocator.destroy(arena.?);
                self.commitWal() catch {};
                return .{ .message = "CREATE TABLE" };
            },
            .drop_table => |dt| {
                // Check if write operations are allowed (standby mode check)
                self.standby_coordinator.checkWriteAllowed() catch |err| {
                    arena.?.deinit();
                    self.allocator.destroy(arena.?);
                    arena = null; // Prevent errdefer from double-freeing
                    return switch (err) {
                        StandbyCoordinator.Error.WriteOperationNotAllowed => EngineError.TransactionError,
                        else => EngineError.ExecutionError,
                    };
                };

                self.catalog.dropTable(dt.name, dt.if_exists) catch |err| {
                    return switch (err) {
                        error.TableNotFound => EngineError.TableNotFound,
                        error.OutOfMemory => EngineError.OutOfMemory,
                        else => EngineError.StorageError,
                    };
                };
                // Remove table from auto-vacuum tracking
                self.auto_vacuum.removeTable(dt.name);
                arena.?.deinit();
                self.allocator.destroy(arena.?);
                self.commitWal() catch {};
                return .{ .message = "DROP TABLE" };
            },
            .truncate => |tr| {
                self.standby_coordinator.checkWriteAllowed() catch |err| {
                    arena.?.deinit();
                    self.allocator.destroy(arena.?);
                    arena = null;
                    return switch (err) {
                        StandbyCoordinator.Error.WriteOperationNotAllowed => EngineError.TransactionError,
                        else => EngineError.ExecutionError,
                    };
                };

                for (tr.names) |tbl_name| {
                    var table_info = self.catalog.getTable(tbl_name) catch {
                        return EngineError.TableNotFound;
                    };
                    defer table_info.deinit(self.allocator);

                    var tree = BTree.init(self.pool, table_info.data_root_page_id);
                    var cursor = Cursor.init(self.allocator, &tree);
                    defer cursor.deinit();
                    cursor.seekFirst() catch {
                        continue;
                    };

                    var keys_to_delete = std.ArrayListUnmanaged([]u8){};
                    defer {
                        for (keys_to_delete.items) |k| self.allocator.free(k);
                        keys_to_delete.deinit(self.allocator);
                    }

                    while (cursor.next() catch null) |entry| {
                        defer self.allocator.free(entry.value);
                        const raw = if (isVersionedRowData(entry.value))
                            entry.value[mvcc_mod.MVCC_ROW_OVERHEAD..]
                        else
                            entry.value;
                        if (deserializeRow(self.allocator, raw)) |vals| {
                            self.deleteIndexEntries(&table_info, vals);
                            for (vals) |v| v.free(self.allocator);
                            self.allocator.free(vals);
                        } else |_| {}
                        keys_to_delete.append(self.allocator, entry.key) catch {
                            self.allocator.free(entry.key);
                            continue;
                        };
                    }

                    for (keys_to_delete.items) |k| {
                        tree.delete(k) catch {};
                    }

                    if (tree.root_page_id != table_info.data_root_page_id) {
                        self.updateTableRootPage(tbl_name, tree.root_page_id) catch {};
                    }
                }

                arena.?.deinit();
                self.allocator.destroy(arena.?);
                self.commitWal() catch {};
                return .{ .message = "TRUNCATE" };
            },
            .vacuum => |v| {
                const result = self.executeVacuum(v.table_name);
                if (result) |_| {
                    arena.?.deinit();
                    self.allocator.destroy(arena.?);
                } else |_| {}
                return result;
            },
            .analyze => |a| {
                const result = self.executeAnalyze(a.table_name);
                if (result) |_| {
                    arena.?.deinit();
                    self.allocator.destroy(arena.?);
                } else |_| {}
                return result;
            },
            .transaction => |txn| {
                arena.?.deinit();
                self.allocator.destroy(arena.?);
                switch (txn) {
                    .begin => |begin_stmt| {
                        const isolation: mvcc_mod.IsolationLevel = if (begin_stmt.isolation_level) |iso|
                            switch (iso) {
                                .read_committed => .read_committed,
                                .repeatable_read => .repeatable_read,
                                .serializable => .serializable,
                            }
                        else
                            .read_committed;
                        self.beginTransaction(isolation) catch {
                            return .{ .message = "ERROR: already in a transaction" };
                        };
                        return .{ .message = "BEGIN" };
                    },
                    .commit => {
                        self.commitTransaction() catch {
                            return .{ .message = "WARNING: there is no transaction in progress" };
                        };
                        return .{ .message = "COMMIT" };
                    },
                    .rollback => |rb| {
                        if (rb.savepoint) |sp_name| {
                            // ROLLBACK TO SAVEPOINT name
                            self.rollbackToSavepoint(sp_name) catch |err| {
                                return switch (err) {
                                    EngineError.SavepointNotFound => .{ .message = "ERROR: savepoint not found" },
                                    EngineError.NoActiveTransaction => .{ .message = "ERROR: no transaction in progress" },
                                    else => .{ .message = "ERROR: rollback to savepoint failed" },
                                };
                            };
                            return .{ .message = "ROLLBACK" };
                        } else {
                            self.rollbackTransaction() catch {
                                return .{ .message = "WARNING: there is no transaction in progress" };
                            };
                            return .{ .message = "ROLLBACK" };
                        }
                    },
                    .savepoint => |sp_name| {
                        self.createSavepoint(sp_name) catch |err| {
                            return switch (err) {
                                EngineError.NoActiveTransaction => .{ .message = "ERROR: SAVEPOINT can only be used in transaction blocks" },
                                else => .{ .message = "ERROR: savepoint creation failed" },
                            };
                        };
                        return .{ .message = "SAVEPOINT" };
                    },
                    .release => |sp_name| {
                        self.releaseSavepoint(sp_name) catch |err| {
                            return switch (err) {
                                EngineError.SavepointNotFound => .{ .message = "ERROR: savepoint not found" },
                                EngineError.NoActiveTransaction => .{ .message = "ERROR: no transaction in progress" },
                                else => .{ .message = "ERROR: release savepoint failed" },
                            };
                        };
                        return .{ .message = "RELEASE" };
                    },
                }
            },
            .create_view => |cv| {
                const check_opt: u8 = switch (cv.check_option) {
                    .none => 0,
                    .local => 1,
                    .cascaded => 2,
                };
                self.catalog.createView(
                    cv.name,
                    sql,
                    cv.or_replace,
                    cv.if_not_exists,
                    cv.column_names,
                    check_opt,
                ) catch |err| {
                    return switch (err) {
                        error.ViewAlreadyExists => EngineError.TableAlreadyExists,
                        error.OutOfMemory => EngineError.OutOfMemory,
                        else => EngineError.StorageError,
                    };
                };
                arena.?.deinit();
                self.allocator.destroy(arena.?);
                self.commitWal() catch {};
                return .{ .message = "CREATE VIEW" };
            },
            .drop_view => |dv| {
                self.catalog.dropView(dv.name, dv.if_exists) catch |err| {
                    return switch (err) {
                        error.ViewNotFound => EngineError.TableNotFound,
                        error.OutOfMemory => EngineError.OutOfMemory,
                        else => EngineError.StorageError,
                    };
                };
                arena.?.deinit();
                self.allocator.destroy(arena.?);
                self.commitWal() catch {};
                return .{ .message = "DROP VIEW" };
            },
            .create_type => |ct| {
                self.catalog.createEnumType(ct.name, ct.values) catch |err| {
                    return switch (err) {
                        error.TypeAlreadyExists => EngineError.TableAlreadyExists,
                        error.TableAlreadyExists => EngineError.TableAlreadyExists,
                        error.OutOfMemory => EngineError.OutOfMemory,
                        else => EngineError.StorageError,
                    };
                };
                arena.?.deinit();
                self.allocator.destroy(arena.?);
                self.commitWal() catch {};
                return .{ .message = "CREATE TYPE" };
            },
            .drop_type => |dt| {
                self.catalog.dropEnumType(dt.name, dt.if_exists) catch |err| {
                    return switch (err) {
                        error.TypeNotFound => EngineError.TableNotFound,
                        error.OutOfMemory => EngineError.OutOfMemory,
                        else => EngineError.StorageError,
                    };
                };
                arena.?.deinit();
                self.allocator.destroy(arena.?);
                self.commitWal() catch {};
                return .{ .message = "DROP TYPE" };
            },
            .create_domain => |cd| {
                // TODO: Serialize constraint expression to text for storage
                // For now, constraints are stored but not enforced
                _ = cd.constraint; // Constraint exists in AST but not yet serialized
                self.catalog.createDomain(cd.name, cd.base_type, null) catch |err| {
                    return switch (err) {
                        error.TypeAlreadyExists => EngineError.TableAlreadyExists,
                        error.TableAlreadyExists => EngineError.TableAlreadyExists,
                        error.OutOfMemory => EngineError.OutOfMemory,
                        else => EngineError.StorageError,
                    };
                };
                arena.?.deinit();
                self.allocator.destroy(arena.?);
                self.commitWal() catch {};
                return .{ .message = "CREATE DOMAIN" };
            },
            .drop_domain => |dd| {
                self.catalog.dropDomain(dd.name, dd.if_exists) catch |err| {
                    return switch (err) {
                        error.TypeNotFound => EngineError.TableNotFound,
                        error.OutOfMemory => EngineError.OutOfMemory,
                        else => EngineError.StorageError,
                    };
                };
                arena.?.deinit();
                self.allocator.destroy(arena.?);
                self.commitWal() catch {};
                return .{ .message = "DROP DOMAIN" };
            },
            .create_function => |cf| {
                // Unquote the function body: parseStringLiteral returns WITH outer quotes
                // but executor needs raw SQL. Strip ' delimiters and unescape '' -> '.
                var mutable_cf = cf;
                if (cf.body.len >= 2 and cf.body[0] == '\'' and cf.body[cf.body.len - 1] == '\'') {
                    const inner = cf.body[1 .. cf.body.len - 1];
                    const unquoted = std.mem.replaceOwned(u8, infra_alloc.allocator(), inner, "''", "'") catch {
                        return EngineError.OutOfMemory;
                    };
                    mutable_cf.body = unquoted;
                }
                self.catalog.createFunction(mutable_cf) catch |err| {
                    return switch (err) {
                        error.TableAlreadyExists => EngineError.TableAlreadyExists,
                        error.OutOfMemory => EngineError.OutOfMemory,
                        else => EngineError.StorageError,
                    };
                };
                arena.?.deinit();
                self.allocator.destroy(arena.?);
                self.commitWal() catch {};
                return .{ .message = "CREATE FUNCTION" };
            },
            .drop_function => |df| {
                // TODO: For now, ignore param_types (no overload resolution yet)
                _ = df.param_types;
                self.catalog.dropFunction(df.name, df.if_exists) catch |err| {
                    return switch (err) {
                        error.FunctionNotFound => EngineError.TableNotFound,
                        error.OutOfMemory => EngineError.OutOfMemory,
                        else => EngineError.StorageError,
                    };
                };
                arena.?.deinit();
                self.allocator.destroy(arena.?);
                self.commitWal() catch {};
                return .{ .message = "DROP FUNCTION" };
            },
            .create_trigger => |ct| {
                // Unquote the trigger body: parseStringLiteral returns WITH outer quotes
                // but exec() needs raw SQL. Strip ' delimiters and unescape '' -> '.
                var mutable_ct = ct;
                if (ct.body.len >= 2 and ct.body[0] == '\'' and ct.body[ct.body.len - 1] == '\'') {
                    const inner = ct.body[1 .. ct.body.len - 1];
                    const unquoted = std.mem.replaceOwned(u8, infra_alloc.allocator(), inner, "''", "'") catch {
                        return EngineError.OutOfMemory;
                    };
                    mutable_ct.body = unquoted;
                }
                self.catalog.createTrigger(mutable_ct) catch |err| {
                    return switch (err) {
                        error.TableAlreadyExists => EngineError.TableAlreadyExists,
                        error.OutOfMemory => EngineError.OutOfMemory,
                        else => EngineError.StorageError,
                    };
                };
                arena.?.deinit();
                self.allocator.destroy(arena.?);
                self.commitWal() catch {};
                return .{ .message = "CREATE TRIGGER" };
            },
            .drop_trigger => |dt| {
                self.catalog.dropTrigger(dt.name, dt.if_exists) catch |err| {
                    return switch (err) {
                        error.TypeNotFound => EngineError.TableNotFound,
                        error.OutOfMemory => EngineError.OutOfMemory,
                        else => EngineError.StorageError,
                    };
                };
                arena.?.deinit();
                self.allocator.destroy(arena.?);
                self.commitWal() catch {};
                return .{ .message = "DROP TRIGGER" };
            },
            .alter_trigger => |at| {
                self.catalog.alterTrigger(at.name, at.enable) catch |err| {
                    return switch (err) {
                        error.TypeNotFound => EngineError.TableNotFound,
                        error.OutOfMemory => EngineError.OutOfMemory,
                        else => EngineError.StorageError,
                    };
                };
                arena.?.deinit();
                self.allocator.destroy(arena.?);
                self.commitWal() catch {};
                return .{ .message = "ALTER TRIGGER" };
            },
            .create_role => |cr| {
                self.catalog.createRole(cr) catch |err| {
                    return switch (err) {
                        error.TypeAlreadyExists => EngineError.TableAlreadyExists,
                        error.OutOfMemory => EngineError.OutOfMemory,
                        else => EngineError.StorageError,
                    };
                };
                arena.?.deinit();
                self.allocator.destroy(arena.?);
                self.commitWal() catch {};
                return .{ .message = "CREATE ROLE" };
            },
            .drop_role => |dr| {
                self.catalog.dropRole(dr.name, dr.if_exists) catch |err| {
                    return switch (err) {
                        error.TypeNotFound => EngineError.TableNotFound,
                        error.OutOfMemory => EngineError.OutOfMemory,
                        else => EngineError.StorageError,
                    };
                };
                arena.?.deinit();
                self.allocator.destroy(arena.?);
                self.commitWal() catch {};
                return .{ .message = "DROP ROLE" };
            },
            .alter_role => |ar| {
                self.catalog.alterRole(ar.name, ar.options) catch |err| {
                    return switch (err) {
                        error.TypeNotFound => EngineError.TableNotFound,
                        error.OutOfMemory => EngineError.OutOfMemory,
                        else => EngineError.StorageError,
                    };
                };
                arena.?.deinit();
                self.allocator.destroy(arena.?);
                self.commitWal() catch {};
                return .{ .message = "ALTER ROLE" };
            },
            .grant => |g| {
                self.catalog.grantPermission(g) catch |err| {
                    return switch (err) {
                        error.OutOfMemory => EngineError.OutOfMemory,
                        else => EngineError.StorageError,
                    };
                };
                arena.?.deinit();
                self.allocator.destroy(arena.?);
                self.commitWal() catch {};
                return .{ .message = "GRANT" };
            },
            .revoke => |r| {
                self.catalog.revokePermission(r) catch |err| {
                    return switch (err) {
                        error.OutOfMemory => EngineError.OutOfMemory,
                        else => EngineError.StorageError,
                    };
                };
                arena.?.deinit();
                self.allocator.destroy(arena.?);
                self.commitWal() catch {};
                return .{ .message = "REVOKE" };
            },
            .grant_role => |g| {
                for (g.members) |member| {
                    self.catalog.grantRole(g.role, member, g.with_admin_option) catch |err| {
                        return switch (err) {
                            error.OutOfMemory => EngineError.OutOfMemory,
                            else => EngineError.StorageError,
                        };
                    };
                }
                arena.?.deinit();
                self.allocator.destroy(arena.?);
                self.commitWal() catch {};
                return .{ .message = "GRANT" };
            },
            .revoke_role => |r| {
                for (r.members) |member| {
                    self.catalog.revokeRole(r.role, member) catch |err| {
                        return switch (err) {
                            error.OutOfMemory => EngineError.OutOfMemory,
                            else => EngineError.StorageError,
                        };
                    };
                }
                arena.?.deinit();
                self.allocator.destroy(arena.?);
                self.commitWal() catch {};
                return .{ .message = "REVOKE" };
            },
            .create_policy => |cp| {
                self.catalog.createPolicy(cp) catch |err| {
                    return switch (err) {
                        error.TypeAlreadyExists => EngineError.TableAlreadyExists,
                        error.OutOfMemory => EngineError.OutOfMemory,
                        else => EngineError.StorageError,
                    };
                };
                arena.?.deinit();
                self.allocator.destroy(arena.?);
                self.commitWal() catch {};
                return .{ .message = "CREATE POLICY" };
            },
            .drop_policy => |dp| {
                self.catalog.dropPolicy(dp.table_name, dp.policy_name, dp.if_exists) catch |err| {
                    return switch (err) {
                        error.TypeNotFound => EngineError.TableNotFound,
                        error.OutOfMemory => EngineError.OutOfMemory,
                        else => EngineError.StorageError,
                    };
                };
                arena.?.deinit();
                self.allocator.destroy(arena.?);
                self.commitWal() catch {};
                return .{ .message = "DROP POLICY" };
            },
            .alter_table_rls => |rls| {
                if (rls.enable) {
                    try self.catalog.enableRLS(rls.table_name);
                } else {
                    try self.catalog.disableRLS(rls.table_name);
                }
                arena.?.deinit();
                self.allocator.destroy(arena.?);
                self.commitWal() catch {};
                return .{ .message = "ALTER TABLE" };
            },
            .alter_table => |at| {
                // Check if write operations are allowed (standby mode check)
                self.standby_coordinator.checkWriteAllowed() catch |err| {
                    arena.?.deinit();
                    self.allocator.destroy(arena.?);
                    arena = null; // Prevent errdefer from double-freeing
                    return switch (err) {
                        StandbyCoordinator.Error.WriteOperationNotAllowed => EngineError.TransactionError,
                        else => EngineError.ExecutionError,
                    };
                };

                self.executeAlterTable(&at) catch |err| {
                    arena.?.deinit();
                    self.allocator.destroy(arena.?);
                    arena = null; // Prevent errdefer from double-freeing
                    return switch (err) {
                        error.TableNotFound => EngineError.TableNotFound,
                        error.ColumnNotFound => EngineError.ColumnNotFound,
                        error.OutOfMemory => EngineError.OutOfMemory,
                        else => EngineError.StorageError,
                    };
                };
                arena.?.deinit();
                self.allocator.destroy(arena.?);
                self.commitWal() catch {};
                return .{ .message = "ALTER TABLE" };
            },
            .create_index => |ci| {
                // Check if write operations are allowed (standby mode check)
                self.standby_coordinator.checkWriteAllowed() catch |err| {
                    arena.?.deinit();
                    self.allocator.destroy(arena.?);
                    arena = null; // Prevent errdefer from double-freeing
                    return switch (err) {
                        StandbyCoordinator.Error.WriteOperationNotAllowed => EngineError.TransactionError,
                        else => EngineError.ExecutionError,
                    };
                };

                // Get the table
                var table_info = self.catalog.getTable(ci.table) catch |err| {
                    return switch (err) {
                        error.TableNotFound => EngineError.TableNotFound,
                        error.OutOfMemory => EngineError.OutOfMemory,
                        else => EngineError.StorageError,
                    };
                };
                defer table_info.deinit(self.allocator);

                // Extract column name from the first OrderByItem
                if (ci.columns.len == 0) return EngineError.ExecutionError;
                const col_name = if (ci.columns[0].expr.* == .column_ref)
                    ci.columns[0].expr.column_ref.name
                else
                    return EngineError.ExecutionError;

                // Check if index already exists
                if (table_info.findIndex(col_name) != null) {
                    if (ci.if_not_exists) {
                        arena.?.deinit();
                        self.allocator.destroy(arena.?);
                        const message = if (ci.concurrently) "CREATE INDEX CONCURRENTLY" else "CREATE INDEX";
                        return .{ .message = message };
                    }
                    return EngineError.TableAlreadyExists;
                }

                // Find the column index in the table
                var col_idx: u16 = 0;
                var found = false;
                for (table_info.columns, 0..) |col, i| {
                    if (std.ascii.eqlIgnoreCase(col.name, col_name)) {
                        col_idx = @intCast(i);
                        found = true;
                        break;
                    }
                }
                if (!found) return EngineError.ExecutionError;

                // Determine index type BEFORE allocating page
                var idx_type = catalog_mod.IndexType.btree;
                if (ci.index_type) |type_str| {
                    if (std.ascii.eqlIgnoreCase(type_str, "hash")) {
                        idx_type = catalog_mod.IndexType.hash;
                    } else if (std.ascii.eqlIgnoreCase(type_str, "gist")) {
                        idx_type = catalog_mod.IndexType.gist;
                    } else if (std.ascii.eqlIgnoreCase(type_str, "gin")) {
                        idx_type = catalog_mod.IndexType.gin;
                    } else if (std.ascii.eqlIgnoreCase(type_str, "btree")) {
                        idx_type = catalog_mod.IndexType.btree;
                    }
                }

                // Allocate a new index page (B+Tree or Hash based on index type)
                const idx_root_id = self.catalog.pool.pager.allocPage() catch {
                    return EngineError.StorageError;
                };
                {
                    const raw = self.catalog.pool.pager.allocPageBuf() catch {
                        return EngineError.StorageError;
                    };
                    defer self.catalog.pool.pager.freePageBuf(raw);

                    // Initialize page based on index type
                    if (idx_type == .hash) {
                        // Hash index initialization is handled by HashIndex.init
                        // Just write an empty FSM page as placeholder (HashIndex will initialize on first use)
                        @memset(raw, 0);
                        raw[0] = 0x05; // FSM page type marker
                    } else {
                        // B+Tree index
                        btree_mod.initLeafPage(raw, self.catalog.pool.pager.page_size, idx_root_id);
                    }

                    self.catalog.pool.pager.writePage(idx_root_id, raw) catch {
                        return EngineError.StorageError;
                    };
                }

                // Build a new indexes array with the new index added
                const new_indexes = self.allocator.alloc(catalog_mod.IndexInfo, table_info.indexes.len + 1) catch {
                    return EngineError.OutOfMemory;
                };
                defer self.allocator.free(new_indexes);

                @memcpy(new_indexes[0..table_info.indexes.len], table_info.indexes);

                // Allocate and duplicate included_columns
                const included_dup = self.allocator.alloc([]const u8, ci.included_columns.len) catch {
                    return EngineError.OutOfMemory;
                };
                for (ci.included_columns, 0..) |inc_col, i| {
                    included_dup[i] = self.allocator.dupe(u8, inc_col) catch {
                        return EngineError.OutOfMemory;
                    };
                }

                // idx_type already determined above before page allocation
                // Set initial state: BUILDING if concurrent, VALID otherwise
                const initial_state: catalog_mod.IndexState = if (ci.concurrently) .building else .valid;
                new_indexes[table_info.indexes.len] = .{
                    .index_name = self.allocator.dupe(u8, ci.name) catch {
                        return EngineError.OutOfMemory;
                    },
                    .column_name = self.allocator.dupe(u8, col_name) catch {
                        return EngineError.OutOfMemory;
                    },
                    .column_index = col_idx,
                    .root_page_id = idx_root_id,
                    .included_columns = included_dup,
                    .index_type = idx_type,
                    .is_unique = ci.unique,
                    .state = initial_state,
                };

                // Serialize the updated table and store in catalog
                const value = catalog_mod.serializeTableFull(
                    self.allocator,
                    table_info.columns,
                    table_info.table_constraints,
                    new_indexes,
                    table_info.data_root_page_id,
                ) catch {
                    // Free the allocated strings for the new index since we're bailing out
                    self.allocator.free(new_indexes[table_info.indexes.len].index_name);
                    self.allocator.free(new_indexes[table_info.indexes.len].column_name);
                    for (included_dup) |incl| self.allocator.free(incl);
                    self.allocator.free(included_dup);
                    return EngineError.OutOfMemory;
                };
                defer self.allocator.free(value);

                // Free the allocated strings for the new index since they're now in the serialized buffer
                self.allocator.free(new_indexes[table_info.indexes.len].index_name);
                self.allocator.free(new_indexes[table_info.indexes.len].column_name);
                for (included_dup) |incl| self.allocator.free(incl);
                self.allocator.free(included_dup);

                self.catalog.tree.delete(ci.table) catch {
                    return EngineError.StorageError;
                };
                self.catalog.tree.insert(ci.table, value) catch {
                    return EngineError.StorageError;
                };

                // If index was created CONCURRENTLY, transition from BUILDING to VALID
                // after the synchronous index build completes
                if (ci.concurrently) {
                    // Fetch the updated table info to get the newly added index
                    var updated_table_info = self.catalog.getTable(ci.table) catch |err| {
                        arena.?.deinit();
                        self.allocator.destroy(arena.?);
                        return switch (err) {
                            error.TableNotFound => EngineError.TableNotFound,
                            error.OutOfMemory => EngineError.OutOfMemory,
                            else => EngineError.StorageError,
                        };
                    };
                    defer updated_table_info.deinit(self.allocator);

                    // Find the newly created index and transition it from BUILDING to VALID
                    const new_indexes_updated = self.allocator.alloc(catalog_mod.IndexInfo, updated_table_info.indexes.len) catch {
                        arena.?.deinit();
                        self.allocator.destroy(arena.?);
                        return EngineError.OutOfMemory;
                    };
                    defer self.allocator.free(new_indexes_updated);

                    @memcpy(new_indexes_updated, updated_table_info.indexes);

                    // Find the index we just created and update its state to VALID
                    for (new_indexes_updated) |*idx| {
                        if (std.ascii.eqlIgnoreCase(idx.index_name, ci.name)) {
                            idx.state = .valid;
                            break;
                        }
                    }

                    // Serialize and update the catalog with the new state
                    const updated_value = catalog_mod.serializeTableFull(
                        self.allocator,
                        updated_table_info.columns,
                        updated_table_info.table_constraints,
                        new_indexes_updated,
                        updated_table_info.data_root_page_id,
                    ) catch {
                        arena.?.deinit();
                        self.allocator.destroy(arena.?);
                        return EngineError.OutOfMemory;
                    };
                    defer self.allocator.free(updated_value);

                    self.catalog.tree.delete(ci.table) catch {
                        arena.?.deinit();
                        self.allocator.destroy(arena.?);
                        return EngineError.StorageError;
                    };
                    self.catalog.tree.insert(ci.table, updated_value) catch {
                        arena.?.deinit();
                        self.allocator.destroy(arena.?);
                        return EngineError.StorageError;
                    };
                }

                arena.?.deinit();
                self.allocator.destroy(arena.?);
                self.commitWal() catch {};

                // Return appropriate message based on concurrently flag
                const message = if (ci.concurrently) "CREATE INDEX CONCURRENTLY" else "CREATE INDEX";
                return .{ .message = message };
            },
            .drop_index => |di| {
                // Check if write operations are allowed (standby mode check)
                self.standby_coordinator.checkWriteAllowed() catch |err| {
                    arena.?.deinit();
                    self.allocator.destroy(arena.?);
                    arena = null; // Prevent errdefer from double-freeing
                    return switch (err) {
                        StandbyCoordinator.Error.WriteOperationNotAllowed => EngineError.TransactionError,
                        else => EngineError.ExecutionError,
                    };
                };

                // Find the table that contains the index by checking the column name
                // For now, we search through all tables to find which one has an index on this column
                // This is a limitation of DROP INDEX not specifying the table name
                var found_table: ?[]const u8 = null;
                var owned_table_name: ?[]const u8 = null;

                // Get all tables (iterate through catalog tree)
                var cursor = btree_mod.Cursor.init(self.allocator, &self.catalog.tree);
                defer cursor.deinit();

                cursor.seekFirst() catch {
                    if (di.if_exists) {
                        arena.?.deinit();
                        self.allocator.destroy(arena.?);
                        return .{ .message = "DROP INDEX" };
                    }
                    return EngineError.StorageError;
                };

                var search_done = false;
                while (!search_done) {
                    const maybe_entry = cursor.next() catch null;
                    if (maybe_entry == null) break;
                    const entry = maybe_entry.?;
                    defer {
                        self.allocator.free(entry.key);
                        self.allocator.free(entry.value);
                    }

                    const table_name = entry.key;
                    const table_info = self.catalog.getTable(table_name) catch {
                        continue;
                    };
                    defer table_info.deinit(self.allocator);

                    for (table_info.indexes) |idx| {
                        // Check if this index matches by index name (new format)
                        // or by column name as fallback (old format / backward compat)
                        const index_match = if (idx.index_name.len > 0)
                            std.ascii.eqlIgnoreCase(idx.index_name, di.name)
                        else
                            std.ascii.eqlIgnoreCase(idx.column_name, di.name);

                        if (index_match) {
                            owned_table_name = try self.allocator.dupe(u8, table_name);
                            found_table = owned_table_name;
                            search_done = true;
                            break;
                        }
                    }
                }

                if (found_table == null) {
                    if (owned_table_name) |otn| self.allocator.free(otn);
                    if (di.if_exists) {
                        arena.?.deinit();
                        self.allocator.destroy(arena.?);
                        return .{ .message = "DROP INDEX" };
                    }
                    return EngineError.TableNotFound;
                }

                // Get the table and remove the index
                const table_name = found_table.?;
                defer if (owned_table_name) |otn| self.allocator.free(otn);

                var table_info = self.catalog.getTable(table_name) catch {
                    return EngineError.TableNotFound;
                };
                defer table_info.deinit(self.allocator);

                // Count how many indexes we'll keep (all except the one matching the drop)
                var keep_count: usize = 0;
                for (table_info.indexes) |idx| {
                    const index_match = if (idx.index_name.len > 0)
                        std.ascii.eqlIgnoreCase(idx.index_name, di.name)
                    else
                        std.ascii.eqlIgnoreCase(idx.column_name, di.name);
                    if (!index_match) keep_count += 1;
                }

                // Find and remove the index from the table's indexes slice
                const new_indexes = self.allocator.alloc(catalog_mod.IndexInfo, keep_count) catch {
                    return EngineError.OutOfMemory;
                };
                defer self.allocator.free(new_indexes);

                var new_idx: usize = 0;
                for (table_info.indexes) |idx| {
                    const index_match = if (idx.index_name.len > 0)
                        std.ascii.eqlIgnoreCase(idx.index_name, di.name)
                    else
                        std.ascii.eqlIgnoreCase(idx.column_name, di.name);
                    if (!index_match) {
                        new_indexes[new_idx] = idx;
                        new_idx += 1;
                    }
                }

                // Serialize the updated table and store in catalog
                const value = catalog_mod.serializeTableFull(
                    self.allocator,
                    table_info.columns,
                    table_info.table_constraints,
                    new_indexes,
                    table_info.data_root_page_id,
                ) catch {
                    return EngineError.OutOfMemory;
                };
                defer self.allocator.free(value);

                self.catalog.tree.delete(table_name) catch {
                    return EngineError.StorageError;
                };
                self.catalog.tree.insert(table_name, value) catch {
                    return EngineError.StorageError;
                };

                arena.?.deinit();
                self.allocator.destroy(arena.?);
                self.commitWal() catch {};
                return .{ .message = "DROP INDEX" };
            },
            .reindex => |r| {
                const result = self.executeReindex(r);
                if (result) |_| {
                    arena.?.deinit();
                    self.allocator.destroy(arena.?);
                } else |_| {}
                return result;
            },
            .set => |s| {
                arena.?.deinit();
                self.allocator.destroy(arena.?);
                var set_op = SetOp.init(s.parameter, s.value, &self.config);
                while (set_op.next() catch return EngineError.ExecutionError) |_| {}
                return .{ .message = "SET" };
            },
            .show => |s| {
                arena.?.deinit();
                self.allocator.destroy(arena.?);

                // Materialize all rows from ShowOp
                var show_op = ShowOp.init(self.allocator, s.parameter, &self.config);
                defer show_op.close();

                var rows = std.ArrayListUnmanaged([]Value){};
                errdefer {
                    for (rows.items) |row_vals| {
                        for (row_vals) |v| v.free(self.allocator);
                        self.allocator.free(row_vals);
                    }
                    rows.deinit(self.allocator);
                }

                while (show_op.next() catch return EngineError.ExecutionError) |row_data| {
                    var row = row_data;
                    const vals = self.allocator.alloc(Value, row.values.len) catch return EngineError.OutOfMemory;
                    errdefer self.allocator.free(vals);
                    for (row.values, 0..) |v, i| {
                        vals[i] = v.dupe(self.allocator) catch return EngineError.OutOfMemory;
                    }
                    row.deinit();
                    rows.append(self.allocator, vals) catch return EngineError.OutOfMemory;
                }

                // Create column names: [name, value]
                const col_names = self.allocator.alloc([]const u8, 2) catch return EngineError.OutOfMemory;
                errdefer self.allocator.free(col_names);
                col_names[0] = self.allocator.dupe(u8, "name") catch return EngineError.OutOfMemory;
                errdefer self.allocator.free(col_names[0]);
                col_names[1] = self.allocator.dupe(u8, "value") catch return EngineError.OutOfMemory;

                // Create MaterializedOp to hold the rows
                const mat_op = self.allocator.create(MaterializedOp) catch return EngineError.OutOfMemory;
                mat_op.* = MaterializedOp.init(
                    self.allocator,
                    col_names,
                    rows.toOwnedSlice(self.allocator) catch return EngineError.OutOfMemory,
                );

                const ops = self.allocator.create(OperatorChain) catch return EngineError.OutOfMemory;
                ops.* = .{ .materialized = mat_op };

                return .{
                    .rows = mat_op.iterator(),
                    ._ops = ops,
                    .message = "SHOW",
                };
            },
            .reset => |r| {
                arena.?.deinit();
                self.allocator.destroy(arena.?);
                var reset_op = ResetOp.init(r.parameter, &self.config);
                while (reset_op.next() catch return EngineError.ExecutionError) |_| {}
                return .{ .message = "RESET" };
            },
            .explain => |ex| {
                // EXPLAIN: analyze → plan → (optionally optimize) → format
                const provider = self.schemaProvider();

                var an = Analyzer.init(self.allocator, provider);
                defer an.deinit();
                an.analyze(ex.stmt.*);
                if (an.hasErrors()) return EngineError.AnalysisError;

                var plnr = Planner.init(arena.?, provider);
                const plan = plnr.plan(ex.stmt.*) catch return EngineError.PlanError;

                var opt = Optimizer.init(arena.?);
                const optimized = opt.optimize(plan) catch return EngineError.PlanError;

                // Format the plan as text using arena allocator
                var plan_text = std.ArrayList(u8){};
                defer plan_text.deinit(arena.?.allocator());

                const writer = plan_text.writer(arena.?.allocator());
                planner_mod.formatPlan(optimized.root, writer, 0) catch return EngineError.ExecutionError;

                // If ANALYZE flag is set, execute the query and show runtime stats
                if (ex.analyze) {
                    writer.writeAll("\n--- ANALYZE Runtime Statistics ---\n") catch return EngineError.ExecutionError;

                    // Execute the query to collect actual runtime statistics
                    const ops = self.allocator.create(OperatorChain) catch return EngineError.OutOfMemory;
                    ops.* = .{};
                    defer ops.deinit(self.allocator);

                    const iter = self.buildIterator(optimized.root, ops) catch |err| {
                        writer.print("(Execution failed: {})\n", .{err}) catch return EngineError.ExecutionError;
                        const plan_str = plan_text.toOwnedSlice(arena.?.allocator()) catch return EngineError.OutOfMemory;
                        return .{ .message = plan_str, ._arena = arena };
                    };

                    // Create a stats object for the root operator
                    var root_stats = executor_mod.OperatorStats{
                        .name = @tagName(optimized.root.*),
                    };

                    // Wrap the iterator with instrumentation
                    var instrumented = executor_mod.InstrumentedIterator.init(iter, &root_stats) catch {
                        writer.writeAll("(Failed to initialize instrumentation)\n") catch return EngineError.ExecutionError;
                        const plan_str = plan_text.toOwnedSlice(arena.?.allocator()) catch return EngineError.OutOfMemory;
                        return .{ .message = plan_str, ._arena = arena };
                    };
                    const inst_iter = instrumented.iterator();

                    // Execute the query by consuming all rows
                    var total_rows: u64 = 0;
                    var exec_error = false;
                    while (true) {
                        const maybe_row = inst_iter.next() catch |err| {
                            writer.print("(Execution error: {})\n", .{err}) catch return EngineError.ExecutionError;
                            exec_error = true;
                            break;
                        };
                        if (maybe_row) |row| {
                            var mutable_row = row;
                            mutable_row.deinit();
                            total_rows += 1;
                        } else {
                            break;
                        }
                    }

                    // Display statistics
                    writer.print("Total rows returned: {d}\n", .{total_rows}) catch return EngineError.ExecutionError;
                    writer.print("{any}\n", .{root_stats}) catch return EngineError.ExecutionError;

                    inst_iter.close();
                }

                // Return plan text as a single-row result; owned by arena
                const plan_str = plan_text.toOwnedSlice(arena.?.allocator()) catch return EngineError.OutOfMemory;

                // Keep arena alive - will be freed in QueryResult.close()
                return .{ .message = plan_str, ._arena = arena };
            },
            .merge => |m| {
                // MERGE is executed directly as a special DML operation
                const result = try self.executeMerge(arena.?, &m);
                arena.?.deinit();
                self.allocator.destroy(arena.?);
                arena = null; // prevent errdefer from double-freeing
                return result;
            },
            .copy => |c| {
                const result = try self.executeCopy(&c, infra_alloc.allocator());
                arena.?.deinit();
                self.allocator.destroy(arena.?);
                arena = null; // prevent errdefer from double-freeing
                return result;
            },
            else => {},
        }

        // DML: analyze → plan → optimize → execute
        const provider = self.schemaProvider();

        var an = Analyzer.init(self.allocator, provider);
        defer an.deinit();
        an.analyze(stmt);
        if (an.hasErrors()) return EngineError.AnalysisError;

        var plnr = Planner.init(arena.?, provider);
        const plan = plnr.plan(stmt) catch return EngineError.PlanError;

        var opt = Optimizer.init(arena.?);
        const optimized = opt.optimize(plan) catch return EngineError.PlanError;

        // Transfer arena ownership to executePlan — prevent errdefer double-free
        const owned_arena = arena.?;
        arena = null;
        return self.executePlan(owned_arena, optimized);
    }

    // ── VACUUM ──────────────────────────────────────────────────────

    fn executeVacuum(self: *Database, table_name: ?[]const u8) EngineError!QueryResult {
        // Cannot vacuum inside a transaction
        if (self.current_txn != null) return EngineError.TransactionError;

        if (table_name) |name| {
            // Vacuum a specific table
            var table_info = self.catalog.getTable(name) catch return EngineError.TableNotFound;
            defer table_info.deinit(self.allocator);

            _ = vacuum_mod.vacuumTable(
                self.allocator,
                self.pool,
                table_info.data_root_page_id,
                self.tm,
                &table_info,
                &self.fsm,
            ) catch return EngineError.StorageError;

            // Update catalog if root page changed
            const fresh = self.catalog.getTable(name) catch return EngineError.TableNotFound;
            defer fresh.deinit(self.allocator);
            if (table_info.data_root_page_id != fresh.data_root_page_id) {
                self.updateTableRootPage(name, table_info.data_root_page_id) catch {};
            }
        } else {
            // Vacuum all tables
            const tables = self.catalog.listTables(self.allocator) catch return EngineError.StorageError;
            defer {
                for (tables) |t| self.allocator.free(t);
                self.allocator.free(tables);
            }

            for (tables) |tbl_name| {
                var table_info = self.catalog.getTable(tbl_name) catch continue;
                defer table_info.deinit(self.allocator);

                const orig_root = table_info.data_root_page_id;

                _ = vacuum_mod.vacuumTable(
                    self.allocator,
                    self.pool,
                    table_info.data_root_page_id,
                    self.tm,
                    &table_info,
                    &self.fsm,
                ) catch continue;

                if (table_info.data_root_page_id != orig_root) {
                    self.updateTableRootPage(tbl_name, table_info.data_root_page_id) catch {};
                }
            }
        }

        // Prune completed transactions after vacuuming
        // (must be after vacuum so isAborted() can detect aborted XIDs)
        self.tm.pruneCompleted();

        self.commitWal() catch {};

        return .{ .message = "VACUUM" };
    }

    // ── ANALYZE ──────────────────────────────────────────────────────

    fn executeAnalyze(self: *Database, table_name: ?[]const u8) EngineError!QueryResult {
        // ANALYZE can run inside a transaction (read-only operation)

        if (table_name) |name| {
            // Analyze a specific table
            try self.analyzeTable(name);
        } else {
            // Analyze all tables
            const tables = self.catalog.listTables(self.allocator) catch return EngineError.StorageError;
            defer {
                for (tables) |t| self.allocator.free(t);
                self.allocator.free(tables);
            }

            for (tables) |tbl_name| {
                self.analyzeTable(tbl_name) catch continue; // Skip errors, continue with other tables
            }
        }

        return .{ .message = "ANALYZE" };
    }

    /// Collect and store statistics for a single table.
    fn analyzeTable(self: *Database, table_name: []const u8) EngineError!void {
        const table_info = self.catalog.getTable(table_name) catch return EngineError.TableNotFound;
        defer table_info.deinit(self.allocator);

        // Scan the table to collect statistics
        var row_count: u64 = 0;
        var column_values = std.StringHashMapUnmanaged(std.ArrayListUnmanaged([]const u8)){}; // col_name -> value list
        defer {
            var it = column_values.iterator();
            while (it.next()) |entry| {
                for (entry.value_ptr.items) |val| self.allocator.free(val);
                entry.value_ptr.deinit(self.allocator);
            }
            column_values.deinit(self.allocator);
        }

        // Initialize value lists for each column
        for (table_info.columns) |col| {
            const list = std.ArrayListUnmanaged([]const u8){};
            column_values.put(self.allocator, col.name, list) catch return EngineError.OutOfMemory;
        }

        // Scan all tuples in the table
        var tree = BTree.init(self.pool, table_info.data_root_page_id);
        var cursor = Cursor.init(self.allocator, &tree);
        defer cursor.deinit();

        cursor.seekFirst() catch {}; // Empty table is ok

        while (cursor.next() catch null) |entry| {
            defer self.allocator.free(entry.key);
            defer self.allocator.free(entry.value);

            row_count += 1;

            // Deserialize row to collect column values (handle MVCC-versioned rows)
            const values = if (mvcc_mod.isVersionedRow(entry.value)) blk: {
                const result = mvcc_mod.deserializeVersionedRow(self.allocator, entry.value) catch continue;
                // Note: We only need the values, header is discarded
                break :blk result.values;
            } else executor_mod.deserializeRow(self.allocator, entry.value) catch continue;
            defer {
                for (values) |v| v.free(self.allocator);
                self.allocator.free(values);
            }

            // Store values for each column (for distinct count, null fraction, etc.)
            for (table_info.columns, 0..) |col, i| {
                if (i < values.len) {
                    const val = values[i];
                    // Serialize the value to bytes for comparison
                    const serialized = self.serializeValueForStats(val) catch return EngineError.OutOfMemory;
                    var list = column_values.getPtr(col.name).?;
                    list.append(self.allocator, serialized) catch return EngineError.OutOfMemory;
                } else {
                    // Column not present in this row (schema evolution)
                    const null_bytes = self.allocator.dupe(u8, &[_]u8{0x00}) catch return EngineError.OutOfMemory;
                    var list = column_values.getPtr(col.name).?;
                    list.append(self.allocator, null_bytes) catch return EngineError.OutOfMemory;
                }
            }
        }

        // Create and store table stats
        const table_stats = stats_mod.TableStats.init(row_count);
        self.catalog.createTableStats(table_name, table_stats) catch return EngineError.StorageError;

        // Create and store column stats
        for (table_info.columns) |col| {
            const values = column_values.getPtr(col.name).?.items;

            // Calculate column statistics
            const distinct_count = try self.countDistinct(values);
            const null_fraction = calculateNullFraction(values);
            const avg_width = calculateAvgWidth(values);
            const correlation = try self.calculateCorrelation(values);

            // Build histogram from non-NULL values
            const histogram_buckets = try self.buildHistogram(values);
            defer {
                for (histogram_buckets) |bucket| {
                    self.allocator.free(bucket.lower);
                    self.allocator.free(bucket.upper);
                }
                self.allocator.free(histogram_buckets);
            }

            // Create column stats with histogram
            const col_stats = stats_mod.ColumnStats{
                .distinct_count = distinct_count,
                .null_fraction = null_fraction,
                .avg_width = avg_width,
                .correlation = correlation,
                .most_common_values = &.{},
                .histogram_buckets = histogram_buckets,
            };

            self.catalog.createColumnStats(table_name, col.name, col_stats) catch return EngineError.StorageError;
        }
    }

    // ── REINDEX ──────────────────────────────────────────────────────

    fn executeReindex(self: *Database, stmt: ast_mod.ReindexStmt) EngineError!QueryResult {
        switch (stmt) {
            .index => |index_name| {
                // Find which table contains this index
                const tables = self.catalog.listTables(self.allocator) catch return EngineError.StorageError;
                defer {
                    for (tables) |t| self.allocator.free(t);
                    self.allocator.free(tables);
                }

                var found_table: ?[]const u8 = null;
                var found_index: ?catalog_mod.IndexInfo = null;

                for (tables) |tbl_name| {
                    var table_info = self.catalog.getTable(tbl_name) catch continue;
                    defer table_info.deinit(self.allocator);

                    for (table_info.indexes) |idx| {
                        if (std.mem.eql(u8, idx.index_name, index_name)) {
                            found_table = tbl_name;
                            found_index = idx;
                            break;
                        }
                    }

                    if (found_table != null) break;
                }

                if (found_table == null) {
                    return EngineError.IndexNotFound;
                }

                // Rebuild the index
                try self.rebuildIndex(found_table.?, found_index.?);
                self.commitWal() catch {};

                return .{ .message = "REINDEX" };
            },
            .table => |table_name| {
                // Get table info
                var table_info = self.catalog.getTable(table_name) catch return EngineError.TableNotFound;
                defer table_info.deinit(self.allocator);

                // Rebuild all indexes on the table
                for (table_info.indexes) |idx| {
                    try self.rebuildIndex(table_name, idx);
                }
                self.commitWal() catch {};

                return .{ .message = "REINDEX" };
            },
            .database => {
                // Rebuild all indexes in the database
                const tables = self.catalog.listTables(self.allocator) catch return EngineError.StorageError;
                defer {
                    for (tables) |t| self.allocator.free(t);
                    self.allocator.free(tables);
                }

                for (tables) |tbl_name| {
                    var table_info = self.catalog.getTable(tbl_name) catch continue;
                    defer table_info.deinit(self.allocator);

                    for (table_info.indexes) |idx| {
                        self.rebuildIndex(tbl_name, idx) catch continue;
                    }
                }
                self.commitWal() catch {};

                return .{ .message = "REINDEX" };
            },
        }
    }

    /// Rebuild a single index from scratch.
    fn rebuildIndex(self: *Database, table_name: []const u8, index_info: catalog_mod.IndexInfo) EngineError!void {
        // Get table info
        var table_info = self.catalog.getTable(table_name) catch return EngineError.TableNotFound;
        defer table_info.deinit(self.allocator);

        // Clear the old index structure (allocate a new root page)
        const new_root_page_id = self.catalog.pool.pager.allocPage() catch return EngineError.StorageError;

        // Initialize the new root page based on index type
        {
            const raw = self.catalog.pool.pager.allocPageBuf() catch return EngineError.StorageError;
            defer self.catalog.pool.pager.freePageBuf(raw);

            if (index_info.index_type == .hash) {
                // Hash index initialization
                @memset(raw, 0);
                raw[0] = 0x05; // FSM page type marker
            } else {
                // B+Tree index
                btree_mod.initLeafPage(raw, self.catalog.pool.pager.page_size, new_root_page_id);
            }

            self.catalog.pool.pager.writePage(new_root_page_id, raw) catch return EngineError.StorageError;
        }

        // Scan the table and rebuild the index
        var tree = BTree.init(self.pool, table_info.data_root_page_id);
        var cursor = Cursor.init(self.allocator, &tree);
        defer cursor.deinit();

        cursor.seekFirst() catch {}; // Empty table is ok

        // Create new index tree
        var index_tree = BTree.init(self.pool, new_root_page_id);

        while (true) {
            const maybe_entry = cursor.next() catch break;
            if (maybe_entry == null) break;
            const entry = maybe_entry.?;
            defer {
                self.allocator.free(entry.key);
                self.allocator.free(entry.value);
            }

            // Deserialize the row
            const values = executor_mod.deserializeRow(self.allocator, entry.value) catch continue;
            defer {
                for (values) |v| v.free(self.allocator);
                self.allocator.free(values);
            }

            // Get the indexed column value
            if (index_info.column_index >= values.len) continue;
            const col_value = values[index_info.column_index];

            // Serialize the index key (column value)
            const index_key = self.serializeIndexKey(col_value) catch continue;
            defer self.allocator.free(index_key);

            // Index value is the row key (primary key)
            const index_value = self.allocator.dupe(u8, entry.key) catch continue;
            defer self.allocator.free(index_value);

            // Insert into the new index tree (BTree does NOT take ownership, it copies)
            index_tree.insert(index_key, index_value) catch continue;
        }

        // Update the catalog with the new root page ID and state in a single operation
        try self.updateIndexProperties(table_name, index_info.index_name, new_root_page_id, .valid);
    }

    /// Serialize an index key from a column value.
    fn serializeIndexKey(self: *Database, val: Value) EngineError![]const u8 {
        return self.serializeValueForStats(val);
    }

    /// Update index properties (root page and state) in a single catalog update.
    fn updateIndexProperties(self: *Database, table_name: []const u8, index_name: []const u8, new_root_page_id: u32, new_state: catalog_mod.IndexState) EngineError!void {
        // Get current table info
        var table_info = self.catalog.getTable(table_name) catch return EngineError.TableNotFound;
        defer table_info.deinit(self.allocator);

        // Create a new indexes array with the updated index
        var new_indexes = std.ArrayList(catalog_mod.IndexInfo){};
        defer new_indexes.deinit(self.allocator);

        for (table_info.indexes) |idx| {
            if (std.mem.eql(u8, idx.index_name, index_name)) {
                // Update this index's root page and state (preserve all other properties)
                var updated_idx = idx;
                updated_idx.root_page_id = new_root_page_id;
                updated_idx.state = new_state;
                try new_indexes.append(self.allocator, updated_idx);
            } else {
                try new_indexes.append(self.allocator, idx);
            }
        }

        // Update the catalog (drop and recreate)
        self.catalog.dropTable(table_name, false) catch {};
        self.catalog.createTableWithIndexes(
            table_name,
            table_info.columns,
            table_info.table_constraints,
            new_indexes.items,
            table_info.data_root_page_id,
        ) catch return EngineError.StorageError;
    }

    /// Serialize a value to bytes for statistics collection.
    fn serializeValueForStats(self: *Database, val: Value) EngineError![]const u8 {
        var buf = std.ArrayListUnmanaged(u8){};
        const writer = buf.writer(self.allocator);

        switch (val) {
            .null_value => try writer.writeByte(0x00),
            .integer => |i| {
                try writer.writeByte(0x01);
                try writer.writeInt(i64, i, .little);
            },
            .real => |r| {
                try writer.writeByte(0x02);
                try writer.writeAll(std.mem.asBytes(&r));
            },
            .text => |t| {
                try writer.writeByte(0x03);
                try writer.writeAll(t);
            },
            .blob => |b| {
                try writer.writeByte(0x04);
                try writer.writeAll(b);
            },
            .boolean => |b| {
                try writer.writeByte(0x05);
                try writer.writeByte(if (b) 1 else 0);
            },
            else => try writer.writeByte(0xFF), // Unsupported type marker
        }

        return try buf.toOwnedSlice(self.allocator);
    }

    /// Count distinct values in a list.
    fn countDistinct(self: *Database, values: []const []const u8) EngineError!u64 {
        var seen = std.StringHashMapUnmanaged(void){};
        defer seen.deinit(self.allocator);

        for (values) |val| {
            // Skip NULL values (0x00 tag) — only count non-NULL distinct values
            if (val.len > 0 and val[0] != 0x00) {
                seen.put(self.allocator, val, {}) catch return EngineError.OutOfMemory;
            }
        }

        return seen.count();
    }

    /// Calculate fraction of NULL values.
    fn calculateNullFraction(values: []const []const u8) f64 {
        if (values.len == 0) return 0.0;

        var null_count: u64 = 0;
        for (values) |val| {
            if (val.len > 0 and val[0] == 0x00) { // NULL tag
                null_count += 1;
            }
        }

        return @as(f64, @floatFromInt(null_count)) / @as(f64, @floatFromInt(values.len));
    }

    /// Calculate average storage width in bytes.
    fn calculateAvgWidth(values: []const []const u8) f64 {
        if (values.len == 0) return 0.0;

        var total_width: u64 = 0;
        for (values) |val| {
            total_width += val.len;
        }

        return @as(f64, @floatFromInt(total_width)) / @as(f64, @floatFromInt(values.len));
    }

    /// Build an equi-depth histogram from column values.
    /// Filters out NULL values, sorts remaining values, and creates ~10 buckets with equal row counts.
    fn buildHistogram(self: *Database, values: []const []const u8) EngineError![]stats_mod.HistogramBucket {
        // Filter out NULL values (marked with 0x00 tag)
        var non_null = std.ArrayListUnmanaged([]const u8){};
        defer non_null.deinit(self.allocator);

        for (values) |val| {
            if (val.len > 0 and val[0] != 0x00) { // Skip NULL marker
                non_null.append(self.allocator, val) catch return EngineError.OutOfMemory;
            }
        }

        // Empty column yields empty histogram
        if (non_null.items.len == 0) {
            return self.allocator.alloc(stats_mod.HistogramBucket, 0) catch return EngineError.OutOfMemory;
        }

        // Sort non-NULL values lexicographically
        std.mem.sort([]const u8, non_null.items, {}, struct {
            fn compare(_: void, a: []const u8, b: []const u8) bool {
                return std.mem.order(u8, a, b) == .lt;
            }
        }.compare);

        // Count distinct values by iterating through sorted list
        var distinct_count: usize = 1; // At least 1 since list is non-empty
        for (1..non_null.items.len) |i| {
            if (std.mem.order(u8, non_null.items[i - 1], non_null.items[i]) != .eq) {
                distinct_count += 1;
            }
        }

        // Determine bucket count: target ~10 buckets, but cap at number of distinct values
        const target_bucket_count = @min(10, distinct_count);

        // If only 1 distinct value, create single bucket
        if (distinct_count == 1) {
            var buckets = std.ArrayListUnmanaged(stats_mod.HistogramBucket){};
            errdefer {
                for (buckets.items) |bucket| {
                    self.allocator.free(bucket.lower);
                    self.allocator.free(bucket.upper);
                }
                buckets.deinit(self.allocator);
            }

            const lower = self.allocator.dupe(u8, non_null.items[0]) catch return EngineError.OutOfMemory;
            errdefer self.allocator.free(lower);
            const upper = self.allocator.dupe(u8, non_null.items[0]) catch return EngineError.OutOfMemory;
            errdefer self.allocator.free(upper);

            try buckets.append(self.allocator, .{
                .lower = lower,
                .upper = upper,
                .count = @intCast(non_null.items.len),
            });

            return try buckets.toOwnedSlice(self.allocator);
        }

        // Build equi-depth histogram: divide sorted values into target_bucket_count buckets
        var buckets = std.ArrayListUnmanaged(stats_mod.HistogramBucket){};
        errdefer {
            for (buckets.items) |bucket| {
                self.allocator.free(bucket.lower);
                self.allocator.free(bucket.upper);
            }
            buckets.deinit(self.allocator);
        }

        const rows_per_bucket = (non_null.items.len + target_bucket_count - 1) / target_bucket_count;
        var bucket_idx: usize = 0;

        while (bucket_idx < target_bucket_count and bucket_idx * rows_per_bucket < non_null.items.len) {
            const start_idx = bucket_idx * rows_per_bucket;
            const end_idx = @min((bucket_idx + 1) * rows_per_bucket - 1, non_null.items.len - 1);

            if (start_idx > non_null.items.len - 1) break;

            const lower = self.allocator.dupe(u8, non_null.items[start_idx]) catch return EngineError.OutOfMemory;
            errdefer self.allocator.free(lower);
            const upper = self.allocator.dupe(u8, non_null.items[end_idx]) catch return EngineError.OutOfMemory;
            errdefer self.allocator.free(upper);

            const bucket_count = end_idx - start_idx + 1;

            try buckets.append(self.allocator, .{
                .lower = lower,
                .upper = upper,
                .count = @intCast(bucket_count),
            });

            bucket_idx += 1;
        }

        return try buckets.toOwnedSlice(self.allocator);
    }

    /// Calculate Spearman's rank correlation coefficient between logical (sorted) order and physical (storage) order.
    /// Returns a value from -1.0 to 1.0:
    ///   - Values close to +1.0: Column values are ordered in storage (index scans efficient)
    ///   - Values close to -1.0: Column values are reverse-ordered in storage
    ///   - Values close to 0.0: Column values are randomly ordered (no correlation)
    ///
    /// This statistic helps the optimizer decide whether an index scan or sequential scan is more efficient.
    fn calculateCorrelation(self: *Database, values: []const []const u8) EngineError!f64 {
        // Filter out NULL values
        var non_null = std.ArrayListUnmanaged([]const u8){};
        defer non_null.deinit(self.allocator);

        for (values) |val| {
            if (val.len > 0 and val[0] != 0x00) { // Skip NULL marker
                non_null.append(self.allocator, val) catch return EngineError.OutOfMemory;
            }
        }

        // Need at least 2 values to compute correlation
        if (non_null.items.len < 2) return 0.0;

        // Create array of (value, physical_position) pairs
        const ValuePos = struct {
            value: []const u8,
            physical_pos: usize,
        };

        var pairs = std.ArrayListUnmanaged(ValuePos){};
        defer pairs.deinit(self.allocator);

        for (non_null.items, 0..) |val, pos| {
            pairs.append(self.allocator, .{ .value = val, .physical_pos = pos }) catch return EngineError.OutOfMemory;
        }

        // Sort by value (logical order)
        std.mem.sort(ValuePos, pairs.items, {}, struct {
            fn compare(_: void, a: ValuePos, b: ValuePos) bool {
                return std.mem.order(u8, a.value, b.value) == .lt;
            }
        }.compare);

        // Assign ranks to logical order (handling ties by averaging ranks)
        var logical_ranks = std.ArrayListUnmanaged(f64){};
        defer logical_ranks.deinit(self.allocator);
        try logical_ranks.resize(self.allocator, pairs.items.len);

        var i: usize = 0;
        while (i < pairs.items.len) {
            // Find extent of tie group
            var j: usize = i + 1;
            while (j < pairs.items.len and std.mem.eql(u8, pairs.items[i].value, pairs.items[j].value)) {
                j += 1;
            }

            // Assign average rank to all ties (rank is 1-indexed)
            const avg_rank = @as(f64, @floatFromInt(i + j + 1)) / 2.0;
            for (i..j) |k| {
                logical_ranks.items[k] = avg_rank;
            }

            i = j;
        }

        // Compute physical ranks (based on physical_pos, same tie-handling logic)
        var physical_ranks = std.ArrayListUnmanaged(f64){};
        defer physical_ranks.deinit(self.allocator);
        try physical_ranks.resize(self.allocator, pairs.items.len);

        // Create temporary array sorted by physical position to assign ranks
        var phys_sorted = std.ArrayListUnmanaged(struct { physical_pos: usize, idx: usize }){};
        defer phys_sorted.deinit(self.allocator);
        for (pairs.items, 0..) |pair, idx| {
            phys_sorted.append(self.allocator, .{ .physical_pos = pair.physical_pos, .idx = idx }) catch return EngineError.OutOfMemory;
        }

        std.mem.sort(@TypeOf(phys_sorted.items[0]), phys_sorted.items, {}, struct {
            fn compare(_: void, a: @TypeOf(phys_sorted.items[0]), b: @TypeOf(phys_sorted.items[0])) bool {
                return a.physical_pos < b.physical_pos;
            }
        }.compare);

        i = 0;
        while (i < phys_sorted.items.len) {
            var j: usize = i + 1;
            while (j < phys_sorted.items.len and phys_sorted.items[i].physical_pos == phys_sorted.items[j].physical_pos) {
                j += 1;
            }

            const avg_rank = @as(f64, @floatFromInt(i + j + 1)) / 2.0;
            for (i..j) |k| {
                physical_ranks.items[phys_sorted.items[k].idx] = avg_rank;
            }

            i = j;
        }

        // Compute Spearman's rank correlation coefficient: r = 1 - (6 * Σd²) / (n * (n² - 1))
        // where d = difference in ranks
        const n = @as(f64, @floatFromInt(pairs.items.len));
        var sum_d_squared: f64 = 0.0;

        for (0..pairs.items.len) |k| {
            const d = logical_ranks.items[k] - physical_ranks.items[k];
            sum_d_squared += d * d;
        }

        const correlation = 1.0 - (6.0 * sum_d_squared) / (n * (n * n - 1.0));
        return correlation;
    }

    // ── Auto-Vacuum ──────────────────────────────────────────────────

    /// Check if any tables need vacuuming and run vacuum on those that do.
    /// Called automatically after transaction commits and auto-commit DML.
    fn runAutoVacuumIfNeeded(self: *Database) void {
        if (!self.auto_vacuum.config.enabled) return;
        // Cannot auto-vacuum while inside a transaction
        if (self.current_txn != null) return;

        const tables = self.auto_vacuum.getTablesNeedingVacuum(self.allocator) catch return;
        defer self.allocator.free(tables);

        if (tables.len == 0) return;

        for (tables) |tbl_name| {
            var table_info = self.catalog.getTable(tbl_name) catch continue;
            defer table_info.deinit(self.allocator);

            const orig_root = table_info.data_root_page_id;

            const vac_result = vacuum_mod.vacuumTable(
                self.allocator,
                self.pool,
                table_info.data_root_page_id,
                self.tm,
                &table_info,
                &self.fsm,
            ) catch continue;

            if (table_info.data_root_page_id != orig_root) {
                self.updateTableRootPage(tbl_name, table_info.data_root_page_id) catch {};
            }

            // Report completion to reset counters
            self.auto_vacuum.reportVacuumComplete(tbl_name, vac_result);
        }

        // Prune completed transactions after vacuuming
        self.tm.pruneCompleted();
        self.commitWal() catch {};
    }

    // ── SchemaProvider adapter ────────────────────────────────────────

    pub fn schemaProvider(self: *Database) SchemaProvider {
        return .{
            .ptr = @ptrCast(self),
            .vtable = &.{
                .getTable = @ptrCast(&catalogGetTable),
                .tableExists = @ptrCast(&catalogTableExists),
            },
        };
    }

    fn catalogGetTable(self: *Database, _: Allocator, name: []const u8) ?TableInfo {
        // Deserialize using the schema arena so memory is managed by the
        // Database and freed between exec calls. The analyzer doesn't need
        // to manage TableInfo lifetimes.
        const value = self.catalog.tree.get(self.allocator, name) catch return null;
        if (value) |v| {
            defer self.allocator.free(v);
            return catalog_mod.deserializeTable(self.schema_arena.allocator(), name, v) catch null;
        }

        // Not a real table — check if it's a view
        return self.resolveViewAsTable(name);
    }

    /// Resolve a view as a synthetic TableInfo for the analyzer/planner.
    /// Parses the view's SQL, plans it, and extracts column info from the plan.
    fn resolveViewAsTable(self: *Database, name: []const u8) ?TableInfo {
        const view_info = self.catalog.getView(name) catch return null;
        defer view_info.deinit();

        var view_arena = AstArena.init(self.allocator);
        defer view_arena.deinit();

        var infra_alloc = std.heap.ArenaAllocator.init(self.allocator);
        defer infra_alloc.deinit();

        var p = Parser.init(infra_alloc.allocator(), view_info.sql, &view_arena) catch return null;
        defer p.deinit();

        const stmt = (p.parseStatement() catch return null) orelse return null;

        const view_select = switch (stmt) {
            .create_view => |cv| cv.select,
            .select => |s| s,
            else => return null,
        };

        // Plan the view's SELECT to extract column types
        const provider = self.schemaProvider();
        var plnr = Planner.init(&view_arena, provider);
        const view_plan = plnr.plan(.{ .select = view_select }) catch return null;

        var opt = Optimizer.init(&view_arena);
        const optimized = opt.optimize(view_plan) catch return null;

        // Extract output columns from the plan — Project resolves to named/typed columns
        const arena_alloc = self.schema_arena.allocator();
        const plan_cols = resolveViewPlanColumns(arena_alloc, optimized.root) orelse
            return null;

        if (plan_cols.len > 0) {
            const columns = arena_alloc.alloc(ColumnInfo, plan_cols.len) catch return null;
            for (plan_cols, 0..) |col, i| {
                // Use view column aliases if available
                const col_name = if (i < view_info.column_names.len)
                    view_info.column_names[i]
                else
                    col.column;
                columns[i] = .{
                    .name = arena_alloc.dupe(u8, col_name) catch return null,
                    .column_type = col.col_type.toColumnType(),
                    .flags = .{},
                };
            }
            return .{
                .name = arena_alloc.dupe(u8, name) catch return null,
                .columns = columns,
                .table_constraints = &.{},
                .data_root_page_id = 0, // Views don't have a data root page
            };
        }

        return null;
    }

    fn catalogTableExists(self: *Database, name: []const u8) bool {
        if (self.catalog.tableExists(name) catch false) return true;
        return self.catalog.viewExists(name) catch false;
    }

    // ── Updatable View Support ──────────────────────────────────────

    /// Info extracted from an updatable view definition.
    const UpdatableViewInfo = struct {
        /// The single base table name.
        base_table: []const u8,
        /// The view's WHERE clause (null if no filter).
        where_clause: ?*const ast_mod.Expr,
        /// View column names → base table column names mapping.
        /// For simple views (SELECT * or SELECT col1, col2), these are
        /// the column expressions from the SELECT.
        view_columns: []const ast_mod.ResultColumn,
        /// WITH CHECK OPTION type (0=none, 1=local, 2=cascaded).
        check_option: u8,
    };

    /// Check if a view name refers to an updatable view and return info about it.
    /// An updatable view must:
    /// - Reference exactly one base table (no JOINs)
    /// - Have no aggregates (GROUP BY, HAVING, aggregate functions)
    /// - Have no DISTINCT
    /// - Have no set operations (UNION/INTERSECT/EXCEPT)
    /// - Have no subqueries in FROM
    /// Returns null if the name is not a view or the view is not updatable.
    fn resolveUpdatableView(
        self: *Database,
        view_arena: *AstArena,
        infra_arena: *std.heap.ArenaAllocator,
        view_name: []const u8,
    ) ?UpdatableViewInfo {
        const view_info = self.catalog.getView(view_name) catch return null;
        // Dupe SQL into infra_arena so AST string references survive view_info.deinit()
        const duped_sql = infra_arena.allocator().dupe(u8, view_info.sql) catch {
            view_info.deinit();
            return null;
        };
        const check_opt = view_info.check_option;
        view_info.deinit();

        var p = Parser.init(infra_arena.allocator(), duped_sql, view_arena) catch return null;
        defer p.deinit();

        const stmt = (p.parseStatement() catch return null) orelse return null;

        const view_select = switch (stmt) {
            .create_view => |cv| cv.select,
            .select => |s| s,
            else => return null,
        };

        // Must not have DISTINCT
        if (view_select.distinct) return null;
        if (view_select.distinct_on.len > 0) return null;

        // Must not have GROUP BY / HAVING
        if (view_select.group_by.len > 0) return null;
        if (view_select.having != null) return null;

        // Must not have set operations
        if (view_select.set_operation != null) return null;

        // Must not have CTEs
        if (view_select.ctes.len > 0) return null;

        // Must not have JOINs
        if (view_select.joins.len > 0) return null;

        // Must have a FROM clause with a simple table name (not a subquery or table function)
        const from = view_select.from orelse return null;
        const base_table = switch (from.*) {
            .table_name => |tn| tn.name,
            .subquery => return null,
            .table_function => return null, // Table functions not supported in updatable views
            .values_table => return null, // VALUES tables not supported in updatable views
        };

        // Verify the base table actually exists (not another view — for simplicity)
        if (!(self.catalog.tableExists(base_table) catch false)) return null;

        // Check for aggregate functions in column expressions
        for (view_select.columns) |col| {
            switch (col) {
                .expr => |e| {
                    if (containsAggregateFunction(e.value)) return null;
                },
                .all_columns, .table_all_columns => {},
            }
        }

        return .{
            .base_table = base_table,
            .where_clause = view_select.where,
            .view_columns = view_select.columns,
            .check_option = check_opt,
        };
    }

    /// Check if an expression tree contains aggregate function calls.
    fn containsAggregateFunction(expr: *const ast_mod.Expr) bool {
        return switch (expr.*) {
            .function_call => |fc| {
                const agg_names = [_][]const u8{ "count", "sum", "avg", "min", "max", "count_star", "group_concat" };
                for (agg_names) |name| {
                    if (std.ascii.eqlIgnoreCase(fc.name, name)) return true;
                }
                for (fc.args) |arg| {
                    if (containsAggregateFunction(arg)) return true;
                }
                return false;
            },
            .binary_op => |bo| containsAggregateFunction(bo.left) or containsAggregateFunction(bo.right),
            .unary_op => |uo| containsAggregateFunction(uo.operand),
            .paren => |p| containsAggregateFunction(p),
            .between => |b| containsAggregateFunction(b.expr) or containsAggregateFunction(b.low) or containsAggregateFunction(b.high),
            .in_list => |il| blk: {
                if (containsAggregateFunction(il.expr)) break :blk true;
                for (il.list) |item| {
                    if (containsAggregateFunction(item)) break :blk true;
                }
                break :blk false;
            },
            .is_null => |isn| containsAggregateFunction(isn.expr),
            .like => |l| containsAggregateFunction(l.expr) or containsAggregateFunction(l.pattern),
            .case_expr => |ce| blk: {
                if (ce.operand) |op| {
                    if (containsAggregateFunction(op)) break :blk true;
                }
                for (ce.when_clauses) |wc| {
                    if (containsAggregateFunction(wc.condition) or containsAggregateFunction(wc.result)) break :blk true;
                }
                if (ce.else_expr) |ee| {
                    if (containsAggregateFunction(ee)) break :blk true;
                }
                break :blk false;
            },
            .cast => |c| containsAggregateFunction(c.expr),
            else => false,
        };
    }

    /// Evaluate the view's WHERE clause against a set of values to check WITH CHECK OPTION.
    /// Returns true if the row satisfies the view's WHERE, false otherwise.
    fn evalGeneratedExpr(self: *Database, expr_sql: []const u8, row: *const Row) EngineError!Value {
        var gen_arena = ast_mod.AstArena.init(self.allocator);
        defer gen_arena.deinit();
        var infra = std.heap.ArenaAllocator.init(self.allocator);
        defer infra.deinit();
        var p = parser_mod.Parser.init(infra.allocator(), expr_sql, &gen_arena) catch return .null_value;
        defer p.deinit();
        const expr_ptr = p.parseExpr(0) catch return .null_value;
        return evalExpr(self.allocator, expr_ptr, row, null) catch .null_value;
    }

    /// Evaluate all column-level CHECK constraints for a row.
    /// Returns CheckConstraintViolation if any constraint fails.
    /// NULL values pass CHECK (SQL standard behavior).
    fn evalCheckConstraints(self: *Database, table_info: *const TableInfo, col_names: []const []const u8, values: []const Value) EngineError!void {
        const row = Row{ .columns = col_names, .values = @constCast(values), .allocator = self.allocator };
        for (table_info.columns) |col| {
            if (!col.flags.has_check or col.check_expr.len == 0) continue;
            // Find column value — NULL passes CHECK unconditionally
            const col_val: Value = for (col_names, values) |name, val| {
                if (std.ascii.eqlIgnoreCase(name, col.name)) break val;
            } else .null_value;
            if (col_val == .null_value) continue;
            // Parse and evaluate the expression
            var check_arena = ast_mod.AstArena.init(self.allocator);
            defer check_arena.deinit();
            var infra = std.heap.ArenaAllocator.init(self.allocator);
            defer infra.deinit();
            var p = parser_mod.Parser.init(infra.allocator(), col.check_expr, &check_arena) catch continue;
            defer p.deinit();
            const expr_ptr = p.parseExpr(0) catch continue;
            const result = evalExpr(self.allocator, expr_ptr, &row, null) catch continue;
            defer result.free(self.allocator);
            const passed = switch (result) {
                .boolean => |b| b,
                .null_value => true,
                .integer => |i| i != 0,
                else => false,
            };
            if (!passed) return EngineError.CheckConstraintViolation;
        }
    }

    fn checkViewCondition(self: *Database, where_expr: *const ast_mod.Expr, col_names: []const []const u8, values: []Value) bool {
        const row = Row{
            .columns = col_names,
            .values = values,
            .allocator = self.allocator,
        };
        const result = evalExpr(self.allocator, where_expr, &row, null) catch return false;
        defer result.free(self.allocator);
        return switch (result) {
            .boolean => |b| b,
            .integer => |i| i != 0,
            else => false,
        };
    }
};

