        r.close(testing.allocator);
    }
    {
        var r = try db.exec("INSERT INTO t2 (id) VALUES (1)");
        r.close(testing.allocator);
    }

    // T1: reads t1, will delete from t2
    try db.beginTransaction(.serializable);
    {
        var r = try db.exec("SELECT * FROM t1");
        while (try r.rows.?.next()) |*row_ptr| {
            var row = row_ptr.*;
