    try db.beginTransaction(.serializable);
    {
        var r = try db.exec("SELECT * FROM t2");
        while (try r.rows.?.next()) |*row_ptr| {
            var row = row_ptr.*;
            defer row.deinit();
        }
        r.close(testing.allocator);
    }
    {
        var r = try db.exec("DELETE FROM t1 WHERE id = 1");
        r.close(testing.allocator);
    }
    const saved_txn2 = db.current_txn;
    db.current_txn = null;

