    _ = try db.exec("INSERT INTO t VALUES (1, NULL)");

    // WHERE (val > 5) AND (1 = 1): val > 5 is NULL, 1=1 is TRUE
    // NULL AND TRUE = NULL → treated as FALSE (row excluded)
    var r = try db.exec("SELECT id FROM t WHERE val > 5 AND 1 = 1");
