    try testing.expectEqual(@as(u8, '-'), uuid_str[18]);
    try testing.expectEqual(@as(u8, '-'), uuid_str[23]);
    // Version 4: char at position 14 must be '4'
    try testing.expectEqual(@as(u8, '4'), uuid_str[14]);
}

