test "prepared stmt: bind date in WHERE clause" {

    if (!ENABLE_TESTS) return error.SkipZigTest;
    if (!ENABLE_PREPARED_STMT_TESTS) return error.SkipZigTest;
    const path = "test_prepared_date_where.db";
    defer std.fs.cwd().deleteFile(path) catch {};
    var db = try createTestDb(testing.allocator, path);
    defer cleanupTestDb(&db, path);

    // Setup test table
    var r1 = try db.execSQL("CREATE TABLE appointments (id INTEGER PRIMARY KEY, appt_date DATE)");
    defer r1.close(testing.allocator);

    // Insert 2 rows directly
    var r2 = try db.execSQL("INSERT INTO appointments VALUES (1, CAST('2024-01-15' AS DATE))");
    defer r2.close(testing.allocator);
    var r3 = try db.execSQL("INSERT INTO appointments VALUES (2, CAST('2024-06-30' AS DATE))");
    defer r3.close(testing.allocator);

    // Prepare SELECT statement with date parameter in WHERE
    var stmt = try db.prepare(testing.allocator, "SELECT id FROM appointments WHERE appt_date = ?");
    defer stmt.close();

    // Bind parameter: date=19737 (Jan 15 2024, which is day 19723 + 14 = 19737)
    // Actually, let's calculate: 2024-01-15 should be very close to 19723
    // Using dateToDays algorithm: 2024-01-15 = 19737
    try stmt.bind(0, Value{ .date = 19737 });

    // Execute
    var result = try stmt.execute();
    defer result.close(testing.allocator);

    // Verify exactly 1 row returned with id = 1
    const row_opt = try result.rows.?.next();
    try testing.expect(row_opt != null);
    var row = row_opt.?;
    defer row.deinit();
    try testing.expectEqual(@as(i64, 1), row.values[0].integer);

    // Verify no more rows
    const row_opt2 = try result.rows.?.next();
    try testing.expect(row_opt2 == null);
}

// NOTE: We previously had a "zzz_cleanup_global_registry" test here that called
// cleanupGlobalTmRegistry() to prevent memory leak warnings. This test caused
// deadlocks because:
// 1. Zig test runner doesn't guarantee execution order (despite "zzz_" prefix)
// 2. Cleanup could run while other tests are still using the registry
// 3. Race conditions between deinit() and concurrent acquire()/release() calls
//
// The "memory leaks" this tried to fix are expected test artifacts (see debugging.md)
// and don't represent production bugs. The global registry is designed to persist
// for the lifetime of the process to maintain transaction ID monotonicity.

// ── $N-Style Parameter Tests ──────────────────────────────────────────────

test "numbered param: $1 in SELECT WHERE" {

    if (!ENABLE_TESTS) return error.SkipZigTest;
    if (!ENABLE_PREPARED_STMT_TESTS) return error.SkipZigTest;
    const path = "test_numbered_param_select.db";
    defer std.fs.cwd().deleteFile(path) catch {};
    var db = try createTestDb(testing.allocator, path);
    defer cleanupTestDb(&db, path);

    // Setup test table
    var r1 = try db.execSQL("CREATE TABLE t (id INTEGER PRIMARY KEY, name TEXT)");
    defer r1.close(testing.allocator);
    var r2 = try db.execSQL("INSERT INTO t (id, name) VALUES (1, 'Alice'), (2, 'Bob'), (3, 'Charlie')");
    defer r2.close(testing.allocator);

    // Prepare statement with $1 parameter
    var stmt = try db.prepare(testing.allocator, "SELECT * FROM t WHERE id = $1");
    defer stmt.close();

    // Bind parameter at index 0 (corresponding to $1)
    try stmt.bind(0, Value{ .integer = 2 });
    var result = try stmt.execute();
    defer result.close(testing.allocator);

    // Verify result: should return row with id=2, name='Bob'
    try testing.expect(result.rows != null);
    var count: usize = 0;
    while (try result.rows.?.next()) |*row_ptr| {
        var row = row_ptr.*;
        defer row.deinit();
        count += 1;
        try testing.expectEqual(@as(i64, 2), row.values[0].integer);
        try testing.expectEqualStrings("Bob", row.values[1].text);
    }
    try testing.expectEqual(@as(usize, 1), count);
}

