    // Insert value that satisfies (12 * 2 = 24 > 20)
    _ = try db.exec("INSERT INTO t VALUES (1, 12)");

    // Insert boundary value (11 * 2 = 22 > 20)
    _ = try db.exec("INSERT INTO t VALUES (2, 11)");

