        try testing.expectEqual(@as(u64, 0), r.rows_affected);
    }

    // Verify target unchanged
    {
        var r = try db.execSQL("SELECT id, val FROM t");
        defer r.close(testing.allocator);

        var row_count: usize = 0;
        while (try r.rows.?.next()) |*row_ptr| {
