            defer row.deinit();

            try testing.expectEqual(@as(i64, 1), row.values[0].integer);
            try testing.expectEqualStrings("existing", row.values[1].text);
            row_count += 1;
        }

        try testing.expectEqual(@as(usize, 1), row_count);
    }
}

