    // Select and verify qty is 10
    var r = try db.exec("SELECT qty FROM items WHERE id = 1");
    defer r.close(testing.allocator);
    var row = (try r.rows.?.next()).?;
    defer row.deinit();
    try testing.expectEqual(@as(i64, 10), row.values[0].integer);
}

