test "IS JSON: filters rows in WHERE clause" {
    if (!ENABLE_TESTS) return error.SkipZigTest;
    const path = "test_is_json_where.db";
    defer std.fs.cwd().deleteFile(path) catch {};
    var db = try createTestDb(testing.allocator, path);
    defer cleanupTestDb(&db, path);

    var r1 = try db.execSQL("CREATE TABLE docs (id INTEGER, payload TEXT)");
    defer r1.close(testing.allocator);
    var r2 = try db.execSQL("INSERT INTO docs VALUES (1, '{\"valid\":true}')");
    defer r2.close(testing.allocator);
    var r3 = try db.execSQL("INSERT INTO docs VALUES (2, 'not json at all')");
    defer r3.close(testing.allocator);
    var r4 = try db.execSQL("INSERT INTO docs VALUES (3, '[1,2,3]')");
    defer r4.close(testing.allocator);

    var result = try db.execSQL("SELECT id FROM docs WHERE payload IS JSON ORDER BY id");
    defer result.close(testing.allocator);
    var ids = std.ArrayListUnmanaged(i64){};
    defer ids.deinit(testing.allocator);
    while (try result.rows.?.next()) |*row_ptr| {
        var row = row_ptr.*;
        defer row.deinit();
        try ids.append(testing.allocator, row.values[0].integer);
    }
    try testing.expectEqual(@as(usize, 2), ids.items.len);
    try testing.expectEqual(@as(i64, 1), ids.items[0]);
    try testing.expectEqual(@as(i64, 3), ids.items[1]);
}


test "PreparedStatement: numbered params can be prepared and executed twice in a row" {
    const path = "test_prepared_numbered_params_twice.db";
    defer std.fs.cwd().deleteFile(path) catch {};
    var db = try Database.open(testing.allocator, path, .{});
    defer db.close();

    _ = try db.execSQL("CREATE TABLE test_params (id INTEGER, name TEXT, value INTEGER)");
    _ = try db.execSQL("INSERT INTO test_params VALUES (1, 'alice', 100)");
    _ = try db.execSQL("INSERT INTO test_params VALUES (2, 'bob', 200)");
    _ = try db.execSQL("INSERT INTO test_params VALUES (3, 'charlie', 300)");

    const query = "SELECT * FROM test_params WHERE name = $1 AND value > $2";
    for (0..2) |_| {
        var stmt = try db.prepare(testing.allocator, query);
        defer stmt.close();
        try stmt.bind(0, Value{ .text = "bob" });
        try stmt.bind(1, Value{ .integer = 100 });
        var result = try stmt.execute();
        defer result.close(testing.allocator);
        var count: usize = 0;
        if (result.rows) |rows_iter| {
            while (try rows_iter.next()) |*row_ptr| {
                var row = row_ptr.*;
                defer row.deinit();
                count += 1;
            }
        }
        try testing.expectEqual(@as(usize, 1), count);
    }
}
